const THIRUKKURAL_DATA = [{"number": 1, "line1": "அகர முதல எழுத்தெல்லாம் ஆதி", "line2": "பகவன் முதற்றே உலகு.", "translation": "'A' leads letters; the Ancient Lord Leads and lords the entire world"}, {"number": 2, "line1": "கற்றதனால் ஆய பயனென்கொல் வாலறிவன்", "line2": "நற்றாள் தொழாஅர் எனின்.", "translation": "That lore is vain which does not fall  At His good feet who knoweth all"}, {"number": 3, "line1": "மலர்மிசை ஏகினான் மாணடி சேர்ந்தார்", "line2": "நிலமிசை நீடுவாழ் வார்.", "translation": "Long they live on earth who gain The feet of God in florid brain"}, {"number": 4, "line1": "வேண்டுதல் வேண்டாமை இலானடி சேர்ந்தார்க்கு", "line2": "யாண்டும் இடும்பை இல.", "translation": "Who hold His feet who likes nor loathes Are free from woes of human births"}, {"number": 5, "line1": "இருள்சேர் இருவினையும் சேரா இறைவன்", "line2": "பொருள்சேர் புகழ்புரிந்தார் மாட்டு.", "translation": "God's praise who tell, are free from right  And wrong, the twins of dreaming night"}, {"number": 6, "line1": "பொறிவாயில் ஐந்தவித்தான் பொய்தீர் ஒழுக்க", "line2": "நெறிநின்றார் நீடுவாழ் வார்.", "translation": "They prosper long who walk His way Who has the senses signed away"}, {"number": 7, "line1": "தனக்குவமை இல்லாதான் தாள்சேர்ந்தார்க் கல்லால்", "line2": "மனக்கவலை மாற்றல் அரிது.", "translation": "His feet, whose likeness none can find, Alone can ease the anxious mind"}, {"number": 8, "line1": "அறவாழி அந்தணன் தாள்சேர்ந்தார்க் கல்லால்", "line2": "பிறவாழி நீந்தல் அரிது.", "translation": "Who swims the sea of vice is he Who clasps the feet of Virtue's sea"}, {"number": 9, "line1": "கோளில் பொறியின் குணமிலவே எண்குணத்தான்", "line2": "தாளை வணங்காத் தலை.", "translation": "Like senses stale that head is vain Which bows not to Eight-Virtued Divine"}, {"number": 10, "line1": "பிறவிப் பெருங்கடல் நீந்துவர் நீந்தார்", "line2": "இறைவன் அடிசேரா தார்.", "translation": "The sea of births they alone swim Who clench His feet and cleave to Him"}, {"number": 11, "line1": "வான்நின்று உலகம் வழங்கி வருதலால்", "line2": "தான்அமிழ்தம் என்றுணரற் பாற்று.", "translation": "The genial rain ambrosia call: The world but lasts while rain shall fall"}, {"number": 12, "line1": "துப்பார்க்குத் துப்பாய துப்பாக்கித் துப்பார்க்குத்", "line2": "துப்பாய தூஉம் மழை.", "translation": "The rain begets the food we eat"}, {"number": 13, "line1": "விண்இன்று பொய்ப்பின் விரிநீர் வியனுலகத்து", "line2": "உள்நின்று உடற்றும் பசி.", "translation": "Let clouds their visits stay, and dearth Distresses all the sea-girt earth"}, {"number": 14, "line1": "ஏரின் உழாஅர் உழவர் புயல்என்னும்", "line2": "வாரி வளங்குன்றிக் கால்.", "translation": "Unless the fruitful shower descend, The ploughman's sacred toil must end"}, {"number": 15, "line1": "கெடுப்பதூஉம் கெட்டார்க்குச் சார்வாய்மற் றாங்கே", "line2": "எடுப்பதூஉம் எல்லாம் மழை.", "translation": "Destruction it may sometimes pour But only rain can life restore"}, {"number": 16, "line1": "விசும்பின் துளிவீழின் அல்லால்மற் றாங்கே", "line2": "பசும்புல் தலைகாண்பு அரிது.", "translation": "No grassy blade its head will rear, If from the cloud no drop appear"}, {"number": 17, "line1": "நெடுங்கடலும் தன்நீர்மை குன்றும் தடிந்தெழிலி", "line2": "தான்நல்கா தாகி விடின்.", "translation": "The ocean's wealth will waste away, Except the cloud its stores repay"}, {"number": 18, "line1": "சிறப்பொடு பூசனை செல்லாது வானம்", "line2": "வறக்குமேல் வானோர்க்கும் ஈண்டு.", "translation": "The earth, beneath a barren sky, Would offerings for the gods deny"}, {"number": 19, "line1": "தானம் தவம்இரண்டும் தங்கா வியன்உலகம்", "line2": "வானம் வழங்கா தெனின்.", "translation": "Were heaven above to fail below Nor alms nor penance earth would show"}, {"number": 20, "line1": "நீர்இன்று அமையாது உலகெனின் யார்யார்க்கும்", "line2": "வான்இன்று அமையாது ஒழுக்கு.", "translation": "Water is life that comes from rain Sans rain our duties go in vain"}, {"number": 21, "line1": "ஒழுக்கத்து நீத்தார் பெருமை விழுப்பத்து", "line2": "வேண்டும் பனுவல் துணிவு.", "translation": "No merit can be held so high As theirs who sense and self deny"}, {"number": 22, "line1": "துறந்தார் பெருமை துணைக்கூறின் வையத்து", "line2": "இறந்தாரை எண்ணிக்கொண் டற்று.", "translation": "To con ascetic glory here Is to count the dead upon the sphere"}, {"number": 23, "line1": "இருமை வகைதெரிந்து ஈண்டுஅறம் பூண்டார்", "line2": "பெருமை பிறங்கிற்று உலகு.", "translation": "No lustre can with theirs compare Who know the right and virtue wear"}, {"number": 24, "line1": "உரனென்னும் தோட்டியான் ஓரைந்தும் காப்பான்", "line2": "வரனென்னும் வைப்பிற்கோர் வித்து.", "translation": "With hook of firmness to restrain The senses five, is heaven to gain"}, {"number": 25, "line1": "ஐந்தவித்தான் ஆற்றல் அகல்விசும்பு ளார்கோமான்", "line2": "இந்திரனே சாலுங் கரி.", "translation": "Indra himself has cause to say How great the power ascetics' sway"}, {"number": 26, "line1": "செயற்கரிய செய்வார் பெரியர் சிறியர்", "line2": "செயற்கரிய செய்கலா தார்.", "translation": "The small the paths of ease pursue The great achieve things rare to do"}, {"number": 27, "line1": "சுவைஒளி ஊறுஓசை நாற்றமென ஐந்தின்", "line2": "வகைதெரிவான் கட்டே உலகு.", "translation": "They gain the world, who grasp and tell Of taste, sight, hearing, touch and smell"}, {"number": 28, "line1": "நிறைமொழி மாந்தர் பெருமை நிலத்து", "line2": "மறைமொழி காட்டி விடும்.", "translation": "Full-worded men by what they say, Their greatness to the world display"}, {"number": 29, "line1": "குணமென்னும் குன்றேறி நின்றார் வெகுளி", "line2": "கணமேயும் காத்தல் அரிது.", "translation": "Their wrath, who've climb'd the mount of good, Though transient, cannot be withstood"}, {"number": 30, "line1": "அந்தணர் என்போர் அறவோர்மற் றெவ்வுயிர்க்கும்", "line2": "செந்தண்மை பூண்டொழுக லான்.", "translation": "With gentle mercy towards all, The sage fulfils the vitue's call"}, {"number": 31, "line1": "சிறப்புஈனும் செல்வமும் ஈனும் அறத்தினூஉங்கு", "line2": "ஆக்கம் எவனோ உயிர்க்கு.", "translation": "From virtue weal and wealth outflow; What greater good can mankind know?"}, {"number": 32, "line1": "அறத்தினூஉங்கு ஆக்கமும் இல்லை அதனை", "line2": "மறத்தலின் ஊங்கில்லை கேடு.", "translation": "Virtue enhances joy and gain; Forsaking it is fall and pain"}, {"number": 33, "line1": "ஒல்லும் வகையான் அறவினை ஓவாதே", "line2": "செல்லும்வாய் எல்லாஞ் செயல்.", "translation": "Perform good deeds as much you can Always and everywhere, o man!"}, {"number": 34, "line1": "மனத்துக்கண் மாசிலன் ஆதல் அனைத்தறன்", "line2": "ஆகுல நீர பிற.", "translation": "In spotless mind virtue is found And not in show and swelling sound"}, {"number": 35, "line1": "அழுக்காறு அவாவெகுளி இன்னாச்சொல் நான்கும்", "line2": "இழுக்கா இயன்றது அறம்.", "translation": "Four ills eschew and virtue reach, Lust, anger, envy, evil-speech"}, {"number": 36, "line1": "அன்றறிவாம் என்னாது அறஞ்செய்க மற்றது", "line2": "பொன்றுங்கால் பொன்றாத் துணை.", "translation": "Do good enow; defer it not A deathless aid in death if sought"}, {"number": 37, "line1": "அறத்தாறு இதுவென வேண்டா சிவிகை", "line2": "பொறுத்தானோடு ஊர்ந்தான் இடை.", "translation": "Litter-bearer and rider say  Without a word, the fortune's way"}, {"number": 38, "line1": "வீழ்நாள் படாஅமை நன்றாற்றின் அஃதொருவன்", "line2": "வாழ்நாள் வழியடைக்கும் கல்.", "translation": "Like stones that block rebirth and pain Are doing good and good again"}, {"number": 39, "line1": "அறத்தான் வருவதே இன்பம் மற்றெல்லாம்", "line2": "புறத்த புகழும் இல.", "translation": "Weal flows only from virtue done The rest is rue and renown gone"}, {"number": 40, "line1": "செயற்பால தோரும் அறனே ஒருவற்கு", "line2": "உயற்பால தோரும் பழி.", "translation": "Worthy act is virtue done Vice is what we ought to shun"}, {"number": 41, "line1": "இல்வாழ்வான் என்பான் இயல்புடைய மூவர்க்கும்", "line2": "நல்லாற்றின் நின்ற துணை.", "translation": "The ideal householder is he Who aids the natural orders there"}, {"number": 42, "line1": "துறந்தார்க்கும் துவ்வாதவர்க்கும் இறந்தார்க்கும்", "line2": "இல்வாழ்வான் என்பான் துணை.", "translation": "His help the monk and retired share, And celibate students are his care"}, {"number": 43, "line1": "தென்புலத்தார் தெய்வம் விருந்தொக்கல் தானென்றாங்கு", "line2": "ஐம்புலத்தாறு ஓம்பல் தலை.", "translation": "By dutiful householder's aid God, manes, kin, self and guests are served"}, {"number": 44, "line1": "பழியஞ்சிப் பாத்தூண் உடைத்தாயின் வாழ்க்கை", "line2": "வழியெஞ்சல் எஞ்ஞான்றும் இல்.", "translation": "Sin he shuns and food he shares His home is bright and brighter fares"}, {"number": 45, "line1": "அன்பும் அறனும் உடைத்தாயின் இல்வாழ்க்கை", "line2": "பண்பும் பயனும் அது.", "translation": "In grace and gain the home excels, Where love with virtue sweetly dwells"}, {"number": 46, "line1": "அறத்தாற்றின் இல்வாழ்க்கை ஆற்றின் புறத்தாற்றில்", "line2": "போஒய்ப் பெறுவ தெவன்?", "translation": "Who turns from righteous family To be a monk, what profits he?"}, {"number": 47, "line1": "இயல்பினான் இல்வாழ்க்கை வாழ்பவன் என்பான்", "line2": "முயல்வாருள் எல்லாம் தலை.", "translation": "Of all who strive for bliss, the great Is he who leads the married state"}, {"number": 48, "line1": "ஆற்றின் ஒழுக்கி அறனிழுக்கா இல்வாழ்க்கை", "line2": "நோற்பாரின் நோன்மை உடைத்து.", "translation": "Straight in virtue, right in living Make men brighter than monks praying"}, {"number": 49, "line1": "அறனெனப் பட்டதே இல்வாழ்க்கை அஃதும்", "line2": "பிறன்பழிப்ப தில்லாயின் நன்று.", "translation": "Home-life and virtue, are the same; Which spotless monkhood too can claim"}, {"number": 50, "line1": "வையத்துள் வாழ்வாங்கு வாழ்பவன் வான்உறையும்", "line2": "தெய்வத்துள் வைக்கப் படும்.", "translation": "He is a man of divine worth Who lives in ideal home on earth"}, {"number": 51, "line1": "மனைக்தக்க மாண்புடையள் ஆகித்தற் கொண்டான்", "line2": "வளத்தக்காள் வாழ்க்கைத் துணை.", "translation": "A good housewife befits the house, Spending with thrift the mate's resource"}, {"number": 52, "line1": "மனைமாட்சி இல்லாள்கண் இல்லாயின் வாழ்க்கை", "line2": "எனைமாட்சித் தாயினும் இல்.", "translation": "Bright is home when wife is chaste If not all greatness is but waste"}, {"number": 53, "line1": "இல்லதென் இல்லவள் மாண்பானால் உள்ளதென்", "line2": "இல்லவள் மாணாக் கடை?", "translation": "What is rare when wife is good What can be there when she is bad?"}, {"number": 54, "line1": "பெண்ணின் பெருந்தக்க யாவுள கற்பென்னும்", "line2": "திண்மைஉண் டாகப் பெறின்.", "translation": "What greater fortune is for men Than a constant chaste woman?"}, {"number": 55, "line1": "தெய்வம் தொழாஅள் கொழுநன் தொழுதெழுவாள்", "line2": "பெய்யெனப் பெய்யும் மழை.", "translation": "Her spouse before God who adores, Is like rain that at request pours"}, {"number": 56, "line1": "தற்காத்துத் தற்கொண்டாற் பேணித் தகைசான்ற", "line2": "சொற்காத்துச் சோர்விலாள் பெண்.", "translation": "The good wife guards herself from blame, She tends her spouse and brings him fame"}, {"number": 57, "line1": "சிறைகாக்கும் காப்பெவன் செய்யும் மகளிர்", "line2": "நிறைகாக்கும் காப்பே தலை.", "translation": "Of what avail are watch and ward? Their purity is women's guard"}, {"number": 58, "line1": "பெற்றாற் பெறின்பெறுவர் பெண்டிர் பெருஞ்சிறப்புப்", "line2": "புத்தேளிர் வாழும் உலகு.", "translation": "Women who win their husbands' heart Shall flourish where the gods resort"}, {"number": 59, "line1": "புகழ்புரிந்த இல்லிலோர்க்கு இல்லை இகழ்வார்முன்", "line2": "ஏறுபோல் பீடு நடை.", "translation": "A cuckold has not the lion-like gait Before his detractors aright"}, {"number": 60, "line1": "மங்கலம் என்ப மனைமாட்சி மற்று அதன்", "line2": "நன்கலம் நன்மக்கட் பேறு.", "translation": "An honest wife is home's delight And children good are jewels abright"}, {"number": 61, "line1": "பெறுமவற்றுள் யாமறிவது இல்லை அறிவறிந்த", "line2": "மக்கட்பேறு அல்ல பிற.", "translation": "The world no higher bliss bestows Than children virtuous and wise"}, {"number": 62, "line1": "எழுபிறப்பும் தீயவை தீண்டா பழிபிறங்காப்", "line2": "பண்புடை மக்கட் பெறின்.", "translation": "No evil comes and no blemish; Noble sons bring all we wish"}, {"number": 63, "line1": "தம்பொருள் என்பதம் மக்கள் அவர்பொருள்", "line2": "தம்தம் வினையான் வரும்.", "translation": "Children are one's wealth indeed Their wealth is measured by their deed"}, {"number": 64, "line1": "அமிழ்தினும் ஆற்ற இனிதேதம் மக்கள்", "line2": "சிறுகை அளாவிய கூழ்.", "translation": "The food is more than nectar sweet In which one's children hands insert"}, {"number": 65, "line1": "மக்கள்மெய் தீண்டல் உடற்கின்பம் மற்றுஅவர்", "line2": "சொற்கேட்டல் இன்பம் செவிக்கு.", "translation": "Children's touch delights the body Sweet to ears are their words lovely"}, {"number": 66, "line1": "குழல்இனிது யாழ்இனிது என்பதம் மக்கள்", "line2": "மழலைச்சொல் கேளா தவர்.", "translation": "The flute and lute are sweet they say Deaf to baby's babble's lay!"}, {"number": 67, "line1": "தந்தை மகற்காற்றும் நன்றி அவையத்து", "line2": "முந்தி இருப்பச் செயல்.", "translation": "A father's duty to his son is  To seat him in front of the wise"}, {"number": 68, "line1": "தம்மின்தம் மக்கள் அறிவுடைமை மாநிலத்து", "line2": "மன்னுயிர்க் கெல்லாம் இனிது.", "translation": "With joy the hearts of parents swell  To see their children themselves excel"}, {"number": 69, "line1": "ஈன்ற பொழுதின் பெரிதுவக்கும் தன்மகனைச்", "line2": "சான்றோன் எனக்கேட்ட தாய்.", "translation": "The mother, hearing her son's merit  Delights more than when she begot"}, {"number": 70, "line1": "மகன்தந்தைக்கு ஆற்றும் உதவி இவன்தந்தை", "line2": "என்நோற்றான் கொல் எனும் சொல்.", "translation": "The son to sire this word is debt  \\\"What penance such a son begot!\\\""}, {"number": 71, "line1": "அன்பிற்கும் உண்டோ அடைக்குந்தாழ் ஆர்வலர்", "line2": "புன்கணீர் பூசல் தரும்.", "translation": "What bolt can bar true love in fact  The tricking tears reveal the heart"}, {"number": 72, "line1": "அன்பிலார் எல்லாம் தமக்குரியர் அன்புடையார்", "line2": "என்பும் உரியர் பிறர்க்கு.", "translation": "To selves belong the loveless ones;  To oth'rs the loving e'en to bones"}, {"number": 73, "line1": "அன்போடு இயைந்த வழக்கென்ப ஆருயிர்க்கு", "line2": "என்போடு இயைந்த தொடர்பு.", "translation": "Soul is encased in frame of bone  To taste the life of love alone"}, {"number": 74, "line1": "அன்புஈனும் ஆர்வம் உடைமை அதுஈனும்", "line2": "நண்பு என்னும் நாடாச் சிறப்பு.", "translation": "Love yields aspiration and thence  Friendship springs up in excellence"}, {"number": 75, "line1": "அன்புற்று அமர்ந்த வழக்கென்ப வையகத்து", "line2": "இன்புற்றார் எய்தும் சிறப்பு.", "translation": "The crowning joy of home life flows  From peaceful psychic love always"}, {"number": 76, "line1": "அறத்திற்கே அன்புசார் பென்ப அறியார்", "line2": "மறத்திற்கும் அஃதே துணை.", "translation": "\\\"Love is virtue's friend\\\" say know-nots  It helps us against evil plots"}, {"number": 77, "line1": "என்பி லதனை வெயில்போலக் காயுமே", "line2": "அன்பி லதனை அறம்.", "translation": "Justice burns the loveless form  Like solar blaze the boneless worm"}, {"number": 78, "line1": "அன்பகத் தில்லா உயிர்வாழ்க்கை வன்பாற்கண்", "line2": "வற்றல் மரந்தளிர்த் தற்று.", "translation": "Life bereft of love is gloom  Can sapless tree in desert bloom?"}, {"number": 79, "line1": "புறத்துறுப் பெல்லாம் எவன்செய்யும் யாக்கை", "line2": "அகத்துறுப்பு அன்பி லவர்க்கு.", "translation": "Love is the heart which limbs must move,  Or vain the outer parts will prove"}, {"number": 80, "line1": "அன்பின் வழியது உயிர்நிலை அஃதிலார்க்கு", "line2": "என்புதோல் போர்த்த உடம்பு.", "translation": "The seat of life is love alone;  Or beings are but skin and bone!"}, {"number": 81, "line1": "இருந்தோம்பி இல்வாழ்வ தெல்லாம் விருந்தோம்பி", "line2": "வேளாண்மை செய்தற் பொருட்டு.", "translation": "Men set up home, toil and earn  To tend the guests and do good turn"}, {"number": 82, "line1": "விருந்து புறத்ததாத் தானுண்டல் சாவா", "line2": "மருந்தெனினும் வேண் டற்பாற் றன்று.", "translation": "To keep out guests cannot be good  Albeit you eat nector-like food"}, {"number": 83, "line1": "வருவிருந்து வைகலும் ஓம்புவான் வாழ்க்கை", "line2": "பருவந்து பாழ்படுதல் இன்று.", "translation": "Who tends his guests day in and out  His life in want never wears out"}, {"number": 84, "line1": "அகனமர்ந்து செய்யாள் உறையும் முகனமர்ந்து", "line2": "நல்விருந்து ஓம்புவான் இல்.", "translation": "The goddess of wealth will gladly rest  Where smiles welcome the worthy guest"}, {"number": 85, "line1": "வித்தும் இடல்வேண்டும் கொல்லோ விருந்தோம்பி", "line2": "மிச்சில் மிசைவான் புலம்.", "translation": "Should his field be sown who first  Feeds the guests and eats the rest?"}, {"number": 86, "line1": "செல்விருந்து ஓம்பி வருவிருந்து பார்த்திருப்பான்", "line2": "நல்வருந்து வானத் தவர்க்கு.", "translation": "Who tends a guest and looks for next  Is a welcome guest in heaven's feast"}, {"number": 87, "line1": "இனைத்துணைத் தென்பதொன் றில்லை விருந்தின்", "line2": "துணைத்துணை வேள்விப் பயன்.", "translation": "Worth of the guest of quality  Is worth of hospitality"}, {"number": 88, "line1": "பரிந்தோம்பிப் பற்றற்றேம் என்பர் விருந்தோம்பி", "line2": "வேள்வி தலைப்படா தார்.", "translation": "Who loathe guest-service one day cry:  \\\"We toil and store; but life is dry\\\""}, {"number": 89, "line1": "உடைமையுள் இன்மை விருந்தோம்பல் ஓம்பா", "line2": "மடமை மடவார்கண் உண்டு.", "translation": "The man of wealth is poor indeed  Whose folly fails the guest to feed"}, {"number": 90, "line1": "மோப்பக் குழையும் அனிச்சம் முகந்திரிந்து", "line2": "நோக்கக் குநழ்யும் விருந்து.", "translation": "Anicham smelt withers: like that  A wry-faced look withers the guest"}, {"number": 91, "line1": "இன்சொலால் ஈரம் அளைஇப் படிறுஇலவாம்", "line2": "செம்பொருள் கண்டார்வாய்ச் சொல்.", "translation": "The words of Seers are lovely sweet  Merciful and free from deceit"}, {"number": 92, "line1": "அகன்அமர்ந்து ஈதலின் நன்றே முகனமர்ந்து", "line2": "இன்சொலன் ஆகப் பெறின்.", "translation": "Sweet words from smiling lips dispense  More joys than heart's beneficence"}, {"number": 93, "line1": "முகத்தான் அமர்ந்து இனிதுநோக்கி அகத்தானாம்", "line2": "இன்சொ லினதே அறம்.", "translation": "Calm face, sweet look, kind words from heart  Such is the gracious virtue's part"}, {"number": 94, "line1": "துன்புறூஉம் துவ்வாமை இல்லாகும் யார்மாட்டும்", "line2": "இன்புறூஉம் இன்சொ லவர்க்கு.", "translation": "Whose loving words delight each one  The woe of want from them is gone"}, {"number": 95, "line1": "பணிவுடையன் இன்சொலன் ஆதல் ஒருவற்கு", "line2": "அணியல்ல மற்றுப் பிற.", "translation": "To be humble and sweet words speak  No other jewel do wise men seek"}, {"number": 96, "line1": "அல்லவை தேய அறம்பெருகும் நல்லவை", "line2": "நாடி இனிய சொலின்", "translation": "His sins vanish, his virtues grow  Whose fruitful words with sweetness flow"}, {"number": 97, "line1": "நயன்ஈன்று நன்றி பயக்கும் பயன்ஈன்று", "line2": "பண்பின் தலைப்பிரியாச் சொல்.", "translation": "The fruitful courteous kindly words  Lead to goodness and graceful deeds"}, {"number": 98, "line1": "சிறுமையுவு நீங்கிய இன்சொல் மறுமையும்", "line2": "இம்மையும் இன்பம் தரும்.", "translation": "Kind words free from meanness delight  This life on earth and life the next"}, {"number": 99, "line1": "இன்சொல் இனிதீன்றல் காண்பான் எவன்கொலோ", "line2": "வன்சொல் வழங்கு வது?", "translation": "Who sees the sweets of sweetness here  To use harsh words how can he dare?"}, {"number": 100, "line1": "இனிய உளவாக இன்னாத கூறல்", "line2": "கனிஇருப்பக் காய்கவர்ந் தற்று.", "translation": "Leaving ripe fruits the raw he eats  Who speaks harsh words when sweet word suits"}, {"number": 101, "line1": "செய்யாமல் செய்த உதவிக்கு வையகமும்", "line2": "வானகமும் ஆற்றல் அரிது.", "translation": "Unhelped in turn good help given  Exceeds in worth earth and heaven"}, {"number": 102, "line1": "காலத்தி னாற்செய்த நன்றி சிறிதெனினும்", "line2": "ஞாலத்தின் மாணப் பெரிது.", "translation": "A help rendered in hour of need  Though small is greater than the world"}, {"number": 103, "line1": "பயன்தூக்கார் செய்த உதவி நயன்தூக்கின்", "line2": "நன்மை கடலின் பெரிது.", "translation": "Help rendered without weighing fruits  Outweighs the sea in grand effects"}, {"number": 104, "line1": "தினைத்துணை நன்றி செயினும் பனைத்துணையாக்", "line2": "கொள்வர் பயன்தெரி வார்.", "translation": "Help given though millet-small  Knowers count its good palm-tree tall"}, {"number": 105, "line1": "உதவி வரைத்தன்று உதவி உதவி", "line2": "செயப்பட்டார் சால்பின் வரைத்து.", "translation": "A help is not the help's measure  It is gainer's worth and pleasure"}, {"number": 106, "line1": "மறவற்க மாசற்றார் கேண்மை துறவற்க", "line2": "துன்பத்துள் துப்பாயார் நட்பு.", "translation": "Forget not friendship of the pure  Forsake not timely helpers sure"}, {"number": 107, "line1": "எழுமை எழுபிறப்பும் உள்ளுவர் தங்கண்", "line2": "விழுமந் துடைத்தவர் நட்பு.", "translation": "Through sevenfold births, in memory fares  The willing friend who wiped one's tears"}, {"number": 108, "line1": "நன்றி மறப்பது நன்றன்று நன்றல்லது", "line2": "அன்றே மறப்பது நன்று.", "translation": "To forget good turns is not good  Good it is over wrong not to brood"}, {"number": 109, "line1": "கொன்றன்ன இன்னா செயினும் அவர்செய்த", "line2": "ஒன்றுநன்று உள்ளக் கெடும்.", "translation": "Let deadly harms be forgotten  While remembering one good-turn"}, {"number": 110, "line1": "எந்நன்றி கொன்றார்க்கும் உய்வுண்டாம் உய்வில்லை", "line2": "செய்ந்நன்றி கொன்ற மகற்கு.", "translation": "The virtue-killer may be saved  Not benefit-killer who is damned"}, {"number": 111, "line1": "தகுதி எனவொன்று நன்றே பகுதியால்", "line2": "பாற்பட்டு ஒழுகப் பெறின்.", "translation": "Equity is supreme virtue  It is to give each man his due"}, {"number": 112, "line1": "செப்பம் உடையவன் ஆக்கஞ் சிதைவின்றி", "line2": "எச்சத்திற் கேமாப்பு உடைத்து.", "translation": "Wealth of the man of equity  Grows and lasts to posterity"}, {"number": 113, "line1": "நன்றே தரினும் நடுவிகந்தாம் ஆக்கத்தை", "line2": "அன்றே யொழிய விடல்.", "translation": "Though profitable, turn away  From unjust gains without delay"}, {"number": 114, "line1": "தக்கார் தகவிலர் என்பது அவரவர்", "line2": "எச்சத்தாற் காணப்ப படும்.", "translation": "The worthy and the unworthy  Are seen in their posterity"}, {"number": 115, "line1": "கேடும் பெருக்கமும் இல்லல்ல நெஞ்சத்துக்", "line2": "கோடாமை சான்றோர்க் கணி.", "translation": "Loss and gain by cause arise;  Equal mind adorns the wise"}, {"number": 116, "line1": "கெடுவல்யான் என்பது அறிகதன் நெஞ்சம்", "line2": "நடுவொரீஇ அல்ல செயின்.", "translation": "Of perdition let him be sure  Who leaves justice to sinful lure"}, {"number": 117, "line1": "கெடுவாக வையாது உலகம் நடுவாக", "line2": "நன்றிக்கண் தங்கியான் தாழ்வு.", "translation": "The just reduced to poverty  Is not held down by equity"}, {"number": 118, "line1": "சமன்செய்து சீர்தூக்குங் கோல்போல் அமைந்தொருபால்", "line2": "கோடாமை சான்றோர்க் கணி.", "translation": "Like balance holding equal scales  A well poised mind is jewel of the wise"}, {"number": 119, "line1": "சொற்கோட்டம் இல்லது செப்பம் ஒருதலையா", "line2": "உட்கோட்டம் இன்மை பெறின்.", "translation": "Justice is upright, unbending  And free from crooked word-twisting"}, {"number": 120, "line1": "வாணிகம் செய்வார்க்கு வாணிகம் பேணிப்", "line2": "பிறவும் தமபோல் செயின்.", "translation": "A trader's trade prospers fairly  When his dealings are neighbourly"}, {"number": 121, "line1": "அடக்கம் அமரருள் உய்க்கும் அடங்காமை", "line2": "ஆரிருள் உய்த்து விடும்.", "translation": "Self-rule leads to realms of gods  Indulgence leads to gloomy hades"}, {"number": 122, "line1": "காக்க பொருளா அடக்கத்தை ஆக்கம்", "line2": "அதனினூஉங் கில்லை உயிர்க்கு.", "translation": "No gains with self-control measure  Guard with care this great treasure"}, {"number": 123, "line1": "செறிவறிந்து சீர்மை பயக்கும் அறிவறிந்து", "line2": "ஆற்றின் அடங்கப் பெறின்.", "translation": "Knowing wisdom who lives controlled  Name and fame seek him untold"}, {"number": 124, "line1": "நிலையின் திரியாது அடங்கியான் தோற்றம்", "line2": "மலையினும் மாணப் பெரிது.", "translation": "Firmly fixed in self serene  The sage looks grander than mountain"}, {"number": 125, "line1": "எல்லார்க்கும் நன்றாம் பணிதல் அவருள்ளும்", "line2": "செல்வர்க்கே செல்வம் தகைத்து.", "translation": "Humility is good for all  To the rich it adds a wealth special"}, {"number": 126, "line1": "ஒருமையுள் ஆமைபோல் ஐந்தடக்கல் ஆற்றின்", "line2": "எழுமையும் ஏமாப் புடைத்து.", "translation": "Who senses five like tortoise hold  Their joy prolongs to births sevenfold"}, {"number": 127, "line1": "யாகாவா ராயினும் நாகாக்க காவாக்கால்", "line2": "சோகாப்பர் சொல்லிழுக்குப் பட்டு.", "translation": "Rein the tongue if nothing else  Or slips of tongue bring all the woes"}, {"number": 128, "line1": "ஒன்றானுந் தீச்சொல் பொருட்பயன் உண்டாயின்", "line2": "நன்றாகா தாகி விடும்.", "translation": "Even a single evil word  Will turn all good results to bad"}, {"number": 129, "line1": "தீயினாற் சுட்டபுண் உள்ளாறும் ஆறாதே", "line2": "நாவினாற் சுட்ட வடு.", "translation": "The fire-burnt wounds do find a cure  Tongue-burnt wound rests a running sore"}, {"number": 130, "line1": "கதங்காத்துக் கற்றடங்கல் ஆற்றுவான் செவ்வி", "line2": "அறம்பார்க்கும் ஆற்றின் நுழைந்து.", "translation": "Virtue seeks and peeps to see  Self-controlled savant anger free"}, {"number": 131, "line1": "ஒழுக்கம் விழுப்பந் தரலான் ஒழுக்கம்", "line2": "உயிரினும் ஓம்பப் படும்.", "translation": "Decorum does one dignity  More than life guard its purity"}, {"number": 132, "line1": "பரிந்தோம்பிக் காக்க ஒழுக்கம் தெரிந்தோம்பித்", "line2": "தேரினும் அஃதே துணை.", "translation": "Virtues of conduct all excel;  The soul aid should be guarded well"}, {"number": 133, "line1": "ஒழுக்கம் உடைமை குடிமை இழுக்கம்", "line2": "இழிந்த பிறப்பாய் விடும்.", "translation": "Good conduct shows good family  Low manners mark anomaly"}, {"number": 134, "line1": "மறப்பினும் ஓத்துக் கொளலாகும் பார்ப்பான்", "line2": "பிறப்பொழுக்கங் குன்றக் கெடும்.", "translation": "Readers recall forgotten lore,  But conduct lost returns no more"}, {"number": 135, "line1": "அழுக்கா றுடையான்கண் ஆக்கம்போன்று இல்லை", "line2": "ஒழுக்க மிலான்கண் உயர்வு.", "translation": "The envious prosper but ill  The ill-behaved sinks lower still"}, {"number": 136, "line1": "ஒழுக்கத்தின் ஒல்கார் உரவோர் இழுக்கத்தின்", "line2": "ஏதம் படுபாக் கறிந்து.", "translation": "The firm from virtue falter not  They know the ills of evil thought"}, {"number": 137, "line1": "ஒழுக்கத்தின் எய்துவர் மேன்மை இழுக்கத்தின்", "line2": "எய்துவர் எய்தாப் பழி.", "translation": "Conduct good ennobles man,  Bad conduct entails disgrace mean"}, {"number": 138, "line1": "நன்றிக்கு வித்தாகும் நல்லொழுக்கம் தீயொழுக்கம்", "line2": "என்றும் இடும்பை தரும்.", "translation": "Good conduct sows seeds of blessings  Bad conduct endless evil brings"}, {"number": 139, "line1": "ஒழுக்க முடையவர்க்கு ஒல்லாவே தீய", "line2": "வழுக்கியும் வாயாற் சொலல்.", "translation": "Foul words will never fall from lips  Of righteous men even by slips"}, {"number": 140, "line1": "உலகத்தோடு ஒட்ட ஒழுகல் பலகற்றும்", "line2": "கல்லார் அறிவிலா தார்", "translation": "Though read much they are ignorant  Whose life is not world-accordant"}, {"number": 141, "line1": "பிறன்பொருளாள் பெட்டொழுகும் பேதைமை ஞாலத்து", "line2": "அறம்பொருள் கண்டார்கண் இல்.", "translation": "Who know the wealth and virtue's way  After other's wife do not stray"}, {"number": 142, "line1": "அறன்கடை நின்றாருள் எல்லாம் பிறன்கடை", "line2": "நின்றாரின் பேதையார் இல்.", "translation": "He is the worst law breaking boor  Who haunts around his neighbour's door"}, {"number": 143, "line1": "விளிந்தாரின் வேறல்லர் மன்ற தெளிந்தாரில்", "line2": "தீமை புரிந்து ஒழுகு வார்.", "translation": "The vile are dead who evil aim  And put faithful friends' wives to shame"}, {"number": 144, "line1": "எனைத்துணையர் ஆயினும் என்னாம் தினைத்துணையும்", "line2": "தேரான் பிறனில் புகல்.", "translation": "Their boasted greatness means nothing  When to another's wife they cling"}, {"number": 145, "line1": "எளிதென இல்லிறப்பான் எய்துமெஞ் ஞான்றும்", "line2": "விளியாது நிற்கும் பழி.", "translation": "Who trifles with another's wife  His guilty stain will last for life"}, {"number": 146, "line1": "பகைபாவம் அச்சம் பழியென நான்கும்", "line2": "இகவாவாம் இல்லிறப்பான் கண்.", "translation": "Hatred, sin, fear, and shame-these four  Stain adulterers ever more"}, {"number": 147, "line1": "அறனியலான் இல்வாழ்வான் என்பான் பிறனியலாள்", "line2": "பெண்மை நயவா தவன்.", "translation": "He is the righteous householder  His neighbour's wife who covets never"}, {"number": 148, "line1": "பிறன்மனை நோக்காத பேராண்மை சான்றோர்க்கு", "line2": "அறனொன்றோ ஆன்ற வொழுக்கு.", "translation": "They lead a high-souled manly life  The pure who eye not another's wife"}, {"number": 149, "line1": "நலக்குரியார் யாரெனின் நாமநீர் வைப்பின்", "line2": "பிறர்க்குரியாள் தோள்தோயா தார்.", "translation": "Good in storm bound earth is with those  Who clasp not arms of another's spouse"}, {"number": 150, "line1": "அறன்வரையான் அல்ல செயினும் பிறன்வரையாள்", "line2": "பெண்மை நயவாமை நன்று.", "translation": "Sinners breaking virtue's behest  Lust not for another's wife at least"}, {"number": 151, "line1": "அகழ்வாரைத் தாங்கும் நிலம்போலத் தம்மை", "line2": "இகழ்வார்ப் பொறுத்தல் தலை.", "translation": "As earth bears up with diggers too  To bear revilers is prime virtue"}, {"number": 152, "line1": "பொறுத்தல் இறப்பினை என்றும் அதனை", "line2": "மறத்தல் அதனினும் நன்று.", "translation": "Forgive insults is a good habit  Better it is to forget it"}, {"number": 153, "line1": "இன்மையுள் இன்மை விருந்தொரால் வன்மையுள்", "line2": "வன்மை மடவார்ப் பொறை.", "translation": "Neglect the guest is dearth of dearth  To bear with fools is strength of strength"}, {"number": 154, "line1": "நிறையுடைமை நீங்காமை வேண்டின் பொற்யுடைமை", "line2": "போற்றி யொழுகப் படும்.", "translation": "Practice of patient quality  Retains intact itegrity"}, {"number": 155, "line1": "ஒறுத்தாரை ஒன்றாக வையாரே வைப்பர்", "line2": "பொறுத்தாரைப் பொன்போற் பொதிந்து.", "translation": "Vengeance is not in esteem held  Patience is praised as hidden gold"}, {"number": 156, "line1": "ஒறுத்தார்க்கு ஒருநாளை இன்பம் பொறுத்தார்க்குப்", "line2": "பொன்றுந் துணையும் புகழ்.", "translation": "Revenge accords but one day's joy  Patience carries its praise for aye"}, {"number": 157, "line1": "திறனல்ல தற்பிறர் செய்யினும் நோநொந்து", "line2": "அறனல்ல செய்யாமை நன்று.", "translation": "Though others cause you wanton pain  Grieve not; from unjust harm refrain"}, {"number": 158, "line1": "மிகுதியான் மிக்கவை செய்தாரைத் தாந்தம்", "line2": "தகுதியான் வென்று விடல்.", "translation": "By noble forbearance vanquish  The proud that have caused you anguish"}, {"number": 159, "line1": "துறந்தாரின் தூய்மை உடையர் இறந்தார்வாய்", "line2": "இன்னாச்சொல் நோற்கிற் பவர்.", "translation": "More than ascetics they are pure  Who bitter tongues meekly endure"}, {"number": 160, "line1": "உண்ணாது நோற்பார் பெரியர் பிறர்சொல்லும்", "line2": "இன்னாச்சொல் நோற்பாரின் பின்.", "translation": "Who fast are great to do penance  Greater are they who bear offence"}, {"number": 161, "line1": "ஒழுக்காறாக் கொள்க ஒருவன்தன் நெஞ்சத்து", "line2": "அழுக்காறு இலாத இயல்பு.", "translation": "Deem your heart as virtuous  When your nature is not jealous"}, {"number": 162, "line1": "விழுப்பேற்றின் அஃதொப்பது இல்லையார் மாட்டும்", "line2": "அழுக்காற்றின் அன்மை பெறின்.", "translation": "No excellence excels the one  That by nature envies none"}, {"number": 163, "line1": "அறன்ஆக்கம் வேண்டாதான் என்பான் பிறனாக்கம்", "line2": "பேணாது அழுக்கறுப் பான்.", "translation": "Who envies others' good fortune  Can't prosper in virtue of his own"}, {"number": 164, "line1": "அழுக்காற்றின் அல்லவை செய்யார் இழுக்காற்றின்", "line2": "ஏதம் படுபாக்கு அறிந்து.", "translation": "The wise through envy don't others wrong  Knowing that woes from evils throng"}, {"number": 165, "line1": "அழுக்காறு உடையார்க்கு அதுசாலும் ஒன்னார்", "line2": "வழுக்காயும் கேடீன் பது.", "translation": "Man shall be wrecked by envy's whim  Even if enemies spare him"}, {"number": 166, "line1": "கொடுப்பது அழுக்கறுப்பான் சுற்றம் உடுப்பதூஉம்", "line2": "உண்பதூஉம் இன்றிக் கெடும்.", "translation": "Who envies gifts shall suffer ruin  Without food and clothes with his kin"}, {"number": 167, "line1": "அவ்வித்து அழுக்காறு உடையானைச் செய்யவள்", "line2": "தவ்வையைக் காட்டி விடும்.", "translation": "Fortune deserts the envious  Leaving misfortune omnious"}, {"number": 168, "line1": "அழுக்காறு எனஒரு பாவி திருச்செற்றுத்", "line2": "தீயுழி உய்த்து விடும்.", "translation": "Caitiff envy despoils wealth  And drags one into evil path"}, {"number": 169, "line1": "அவ்விய நெஞ்சத்தான் ஆக்கமும் செவ்வியான்", "line2": "கேடும் நினைக்கப் படும்.", "translation": "Why is envy rich, goodmen poor  People with surprise think over"}, {"number": 170, "line1": "அழுக்கற்று அகன்றாரும் இல்லை அஃதுஇல்லார்", "line2": "பெருக்கத்தில் தீர்ந்தாரும் இல்.", "translation": "The envious prosper never  The envyless prosper ever"}, {"number": 171, "line1": "நடுவின்றி நன்பொருள் வெஃகின் குடிபொன்றிக்", "line2": "குற்றமும் ஆங்கே தரும்.", "translation": "Who covets others' honest wealth  That greed ruins his house forthwith"}, {"number": 172, "line1": "படுபயன் வெஃகிப் பழிப்படுவ செய்யார்", "line2": "நடுவன்மை நாணு பவர்.", "translation": "Who shrink with shame from sin, refrain  From coveting which brings ruin"}, {"number": 173, "line1": "சிற்றின்பம் வெஃகி அறனல்ல செய்யாரே", "line2": "மற்றின்பம் வேண்டு பவர்.", "translation": "For spiritual bliss who long  For fleeting joy commit no wrong"}, {"number": 174, "line1": "இலமென்று வெஃகுதல் செய்யார் புலம்வென்ற", "line2": "புன்மையில் காட்சி யவர்.", "translation": "The truth-knowers of sense-control  Though in want covet not at all"}, {"number": 175, "line1": "அஃகி அகன்ற அறிவென்னாம் யார்மாட்டும்", "line2": "வெஃகி வெறிய செயின்.", "translation": "What is one's subtle wisdom worth  If it deals ill with all on earth"}, {"number": 176, "line1": "அருள்வெஃகி ஆற்றின்கண் நின்றான் பொருள்வெஃகிப்", "line2": "பொல்லாத சூழக் கெடும்.", "translation": "Who seeks for grace on righteous path  Suffers by evil covetous wealth"}, {"number": 177, "line1": "வேண்டற்க வெஃகியாம் ஆக்கம் விளைவயின்", "line2": "மாண்டற் கரிதாம் பயன்.", "translation": "Shun the fruit of covetousness  All its yield is inglorious"}, {"number": 178, "line1": "அஃகாமை செல்வத்திற்கு யாதெனின் வெஃகாமை", "line2": "வேண்டும் பிறன்கைப் பொருள்.", "translation": "The mark of lasting wealth is shown  By not coveting others' own"}, {"number": 179, "line1": "அறனறிந்து வெஃகா அறிவுடையார்ச் சேரும்", "line2": "திறன்அறிந் தாங்கே திரு.", "translation": "Fortune seeks the just and wise  Who are free from coveting vice"}, {"number": 180, "line1": "இறலீனும் எண்ணாது வெஃகின் விறல்ஈனும்", "line2": "வேண்டாமை என்னுஞ் செருக்கு.", "translation": "Desireless, greatness conquers all;  Coveting misers ruined fall"}, {"number": 181, "line1": "அறங்கூறான் அல்ல செயினும் ஒருவன்", "line2": "புறங்கூறான் என்றல் இனிது.", "translation": "Though a man from virtue strays,  To keep from slander brings him praise"}, {"number": 182, "line1": "அறனழீஇ அல்லவை செய்தலின் தீதே", "line2": "புறனழீஇப் பொய்த்து நகை.", "translation": "Who bite behind, and before smile  Are worse than open traitors vile"}, {"number": 183, "line1": "புறங்கூறிப் பொய்த்துயிர் வாழ்தலின் சாதல்", "line2": "அறங்கூற்றும் ஆக்கத் தரும்.", "translation": "Virtue thinks it better to die,  Than live to backbite and to lie"}, {"number": 184, "line1": "கண்ணின்று கண்ணறச் சொல்லினும் சொல்லற்க", "line2": "முன்னின்று பின்நோக்காச் சொல்.", "translation": "Though harsh you speak in one's presence  Abuse is worse in his absence"}, {"number": 185, "line1": "அறஞ்சொல்லும் நெஞ்சத்தான் அன்மை புறஞ்சொல்லும்", "line2": "புன்மையாற் காணப் படும்.", "translation": "Who turns to slander makes it plain  His praise of virtue is in vain"}, {"number": 186, "line1": "பிறன்பழி கூறுவான் தன்பழி யுள்ளும்", "line2": "திறன்தெரிந்து கூறப் படும்.", "translation": "His failings will be found and shown,  Who makes another's failings known"}, {"number": 187, "line1": "பகச்சொல்லிக் கேளிர்ப் பிரிப்பர் நகச்சொல்லி", "line2": "நட்பாடல் தேற்றா தவர்.", "translation": "By pleasing words who make not friends  Sever their hearts by hostile trends"}, {"number": 188, "line1": "துன்னியார் குற்றமும் தூற்றும் மரபினார்", "line2": "என்னைகொல் ஏதிலார் மாட்டு.", "translation": "What will they not to strangers do  Who bring their friends' defects to view?"}, {"number": 189, "line1": "அறன்நோக்கி ஆற்றுங்கொல் வையம் புறன்நோக்கிப்", "line2": "புன்சொல் உரைப்பான் பொறை.", "translation": "The world in mercy bears his load  Who rants behind words untoward"}, {"number": 190, "line1": "ஏதிலார் குற்றம்போல் தங்குற்றங் காண்கிற்பின்", "line2": "தீதுண்டோ மன்னும் உயிர்க்கு.", "translation": "No harm would fall to any man  If each his own defect could scan"}, {"number": 191, "line1": "பல்லார் முனியப் பயனில சொல்லுவான்", "line2": "எல்லாரும் எள்ளப் படும்.", "translation": "With silly words who insults all  Is held in contempt as banal"}, {"number": 192, "line1": "பயனில பல்லார்முன் சொல்லல் நயனில", "line2": "நட்டார்கண் செய்தலிற் றீது.", "translation": "Vain talk before many is worse  Than doing to friends deeds adverse"}, {"number": 193, "line1": "நயனிலன் என்பது சொல்லும் பயனில", "line2": "பாரித் துரைக்கும் உரை.", "translation": "The babbler's hasty lips proclaim  That \\\"good-for-nothing\\\" is his name"}, {"number": 194, "line1": "நயன்சாரா நன்மையின் நீக்கும் பயன்சாராப்", "line2": "பண்பில்சொல் பல்லா ரகத்து.", "translation": "Vain words before an assembly  Will make all gains and goodness flee"}, {"number": 195, "line1": "சீர்மை சிறப்பொடு நீங்கும் பயனில", "line2": "நீர்மை யுடையார் சொலின்.", "translation": "Glory and grace will go away  When savants silly nonsense say"}, {"number": 196, "line1": "பயனில்சொல் பாராட்டு வானை மகன்எனல்", "line2": "மக்கட் பதடி யெனல்.", "translation": "Call him a human chaff who prides  Himself in weightless idle words"}, {"number": 197, "line1": "நயனில சொல்லினுஞ் சொல்லுக சான்றோர்", "line2": "பயனில சொல்லாமை நன்று.", "translation": "Let not men of worth vainly quack  Even if they would roughly speak"}, {"number": 198, "line1": "அரும்பயன் ஆயும் அறிவினார் சொல்லார்", "line2": "பெரும்பயன் இல்லாத சொல்.", "translation": "The wise who weigh the worth refrain  From words that have no grain and brain"}, {"number": 199, "line1": "பொருள்தீர்ந்த பொச்சாந்துஞ் சொல்லார் மருள்தீர்ந்த", "line2": "மாசறு காட்சி யவர்.", "translation": "The wise of spotless self-vision  Slip not to silly words-mention"}, {"number": 200, "line1": "சொல்லுக சொல்லிற் பயனுடைய சொல்லற்க", "line2": "சொல்லிற் பயனிலாச் சொல்.", "translation": "To purpose speak the fruitful word  And never indulge in useless load"}, {"number": 201, "line1": "தீவினையார் அஞ்சார் விழுமியார் அஞ்சுவர்", "line2": "தீவினை என்னும் செருக்கு.", "translation": "Sinners fear not the pride of sin  The worthy dread the ill within"}, {"number": 202, "line1": "தீயவை தீய பயத்தலால் தீயவை", "line2": "தீயினும் அஞ்சப் படும்.", "translation": "Since evil begets evil dire  Fear ye evil more than fire"}, {"number": 203, "line1": "அறிவினுள் எல்லாந் தலையென்ப தீய", "line2": "செறுவார்க்கும் செய்யா விடல்.", "translation": "The wisest of the wise are those  Who injure not even their foes"}, {"number": 204, "line1": "மறந்தும் பிறன்கேடு சூழற்க சூழின்", "line2": "அறஞ்சூழம் சூழ்ந்தவன் கேடு.", "translation": "His ruin virtue plots who plans  The ruin of another man's"}, {"number": 205, "line1": "இலன்என்று தீயவை செய்யற்க செய்யின்", "line2": "இலனாகும் மற்றும் பெயர்த்து.", "translation": "Who makes poverty plea for ill  Shall reduce himself poorer still"}, {"number": 206, "line1": "தீப்பால தான்பிறர்கண் செய்யற்க நோய்ப்பால", "line2": "தன்னை அடல்வேண்டா தான்.", "translation": "From wounding others let him refrain  Who would from harm himself remain"}, {"number": 207, "line1": "எனைப்பகை யுற்றாரும் உய்வர் வினைப்பகை", "line2": "வீயாது பின்சென்று அடும்.", "translation": "Men may escape other foes and live  But sin its deadly blow will give"}, {"number": 208, "line1": "தீயவை செய்தார் கெடுதல் நிழல்தன்னை", "line2": "வீயாது அஇஉறைந் தற்று.", "translation": "Ruin follows who evil do  As shadow follows as they go"}, {"number": 209, "line1": "தன்னைத்தான் காதல னாயின் எனைத்தொன்றும்", "line2": "துன்னற்க தீவினைப் பால்.", "translation": "Let none who loves himself at all  Think of evil however small"}, {"number": 210, "line1": "அருங்கேடன் என்பது அறிக மருங்கோடித்", "line2": "தீவினை செய்யான் எனின்.", "translation": "He is secure, know ye, from ills  Who slips not right path to do evils"}, {"number": 211, "line1": "கைம்மாறு வேண்டா கடப்பாடு மாரிமாட்டு", "line2": "என் ஆற்றுங் கொல்லோ உலகு.", "translation": "Duty demands nothing in turn;  How can the world recompense rain?"}, {"number": 212, "line1": "தாளாற்றித் தந்த பொருளெல்லாம் தக்கார்க்கு", "line2": "வேளாண்மை செய்தற் பொருட்டு.", "translation": "All the wealth that toils give  Is meant to serve those who deserve"}, {"number": 213, "line1": "புத்தே ளுலகத்தும் ஈண்டும் பெறலரிதே", "line2": "ஒப்புரவின் நல்ல பிற.", "translation": "In heav'n and earth 'tis hard to find  A greater good than being kind"}, {"number": 214, "line1": "ஒத்த தறவோன் உயிர்வாழ்வான் மற்றையான்", "line2": "செத்தாருள் வைக்கப் படும்.", "translation": "He lives who knows befitting act  Others are deemed as dead in fact"}, {"number": 215, "line1": "ஊருணி நீர்நிறைந் தற்றே உலகவாம்", "line2": "பேரறி வாளன் திரு.", "translation": "The wealth that wise and kind do make  Is like water that fills a lake"}, {"number": 216, "line1": "பயன்மரம் உள்ளூர்ப் பழுத்தற்றால் செல்வம்", "line2": "நயனுடை யான்கண் படின்.", "translation": "Who plenty gets and plenty gives  Is like town-tree teeming with fruits"}, {"number": 217, "line1": "மருந்தாகித் தப்பா மரத்தற்றால் செல்வம்", "line2": "பெருந்தகை யான்கண் படின்.", "translation": "The wealth of a wide-hearted soul  Is a herbal tree that healeth all"}, {"number": 218, "line1": "இடனில் பருவத்தும் ஒப்புரவிற்கு ஒல்கார்", "line2": "கடனறி காட்சி யவர்.", "translation": "Though seers may fall on evil days  Their sense of duty never strays"}, {"number": 219, "line1": "நயனுடையான் நல்கூர்ந்தா னாதல் செயும்நீர", "line2": "செய்யாது அமைகலா வாறு.", "translation": "The good man's poverty and grief  Is want of means to give relief"}, {"number": 220, "line1": "ஒப்புரவி னால்வரும் கேடெனின் அஃதொருவன்", "line2": "விற்றுக்கோள் தக்க துடைத்து.", "translation": "By good if ruin comes across  Sell yourself to save that loss"}, {"number": 221, "line1": "வறியார்க்கொன்று ஈவதே ஈகைமற் றெல்லாம்", "line2": "குறியெதிர்ப்பை நீர துடைத்து.", "translation": "To give the poor is charity  The rest is loan and vanity"}, {"number": 222, "line1": "நல்லாறு எனினும் கொளல்தீது மேலுலகம்", "line2": "இல்லெனினும் ஈதலே நன்று.", "translation": "To beg is bad e'en from the good  To give is good, were heaven forbid"}, {"number": 223, "line1": "இலனென்னும் எவ்வம் உரையாமை ஈதல்", "line2": "குலனுடையான் கண்ணே யுள.", "translation": "No pleading, \\\"I am nothing worth,\\\"  But giving marks a noble birth"}, {"number": 224, "line1": "இன்னாது இரக்கப் படுதல் இரந்தவர்", "line2": "இன்முகங் காணும் அளவு.", "translation": "The cry for alms is painful sight  Until the giver sees him bright"}, {"number": 225, "line1": "ஆற்றுவார் ஆற்றல் பசிஆற்றல் அப்பசியை", "line2": "மாற்றுவார் ஆற்றலின் பின்.", "translation": "Higher's power which hunger cures  Than that of penance which endures"}, {"number": 226, "line1": "அற்றார் அழிபசி தீர்த்தல் அஃதொருவன்", "line2": "பெற்றான் பொருள்வைப் புழி.", "translation": "Drive from the poor their gnawing pains  If room you seek to store your gains"}, {"number": 227, "line1": "பாத்தூண் மரீஇ யவனைப் பசியென்னும்", "line2": "தீப்பிணி தீண்டல் அரிது.", "translation": "Who shares his food with those who need  Hunger shall not harm his creed"}, {"number": 228, "line1": "ஈத்துவக்கும் இன்பம் அறியார்கொல் தாமுடைமை", "line2": "வைத்திழக்கும் வன்க ணவர்.", "translation": "The joy of give and take they lose  Hard-hearted rich whose hoarding fails"}, {"number": 229, "line1": "இரத்தலின் இன்னாது மன்ற நிரப்பிய", "line2": "தாமே தமியர் உணல்.", "translation": "Worse than begging is that boarding  Alone what one's greed is hoarding"}, {"number": 230, "line1": "சாதலின் இன்னாத தில்லை இனிததூஉம்", "line2": "ஈதல் இயையாக் கடை.", "translation": "Nothing is more painful than death  Yet more is pain of giftless dearth"}, {"number": 231, "line1": "ஈதல் இசைபட வாழ்தல் அதுவல்லது", "line2": "ஊதியம் இல்லை உயிர்க்கு.", "translation": "They gather fame who freely give  The greatest gain for all that live"}, {"number": 232, "line1": "உரைப்பார் உரைப்பவை எல்லாம் இரப்பார்க்கொன்று", "line2": "ஈவார்மேல் நிற்கும் புகழ்.", "translation": "The glory of the alms-giver  Is praised aloud as popular"}, {"number": 233, "line1": "ஒன்றா உலகத்து உயர்ந்த புகழல்லால்", "line2": "பொன்றாது நிற்பதொன் றில்.", "translation": "Nothing else lasts on earth for e'er  Saving high fame of the giver!"}, {"number": 234, "line1": "நிலவரை நீள்புகழ் ஆற்றின் புலவரைப்", "line2": "போற்றாது புத்தேள் உலகு.", "translation": "From hailing gods heavens will cease  To hail the men of lasting praise"}, {"number": 235, "line1": "நத்தம்போல் கேடும் உளதாகும் சாக்காடும்", "line2": "வித்தகர்க் கல்லால் அரிது.", "translation": "Fame in fall and life in death  Are rare but for the soulful worth"}, {"number": 236, "line1": "தோன்றின் புகழொடு தோன்றுக அஃதிலார்", "line2": "தோன்றலின் தோன்றாமை நன்று.", "translation": "Be born with fame if birth you want  If not of birth you must not vaunt"}, {"number": 237, "line1": "புகழ்பட வாழாதார் தந்நோவார் தம்மை", "line2": "இகழ்வாரை நோவது எவன்?", "translation": "Why grieve at those who blame the shame  Of those who cannot live in fame?"}, {"number": 238, "line1": "வசையென்ப வையத்தார்க் கெல்லாம் இசையென்னும்", "line2": "எச்சம் பெறாஅ விடின்.", "translation": "To men on earth it is a shame  Not to beget the child of fame"}, {"number": 239, "line1": "வசையிலா வண்பயன் குன்றும் இசையிலா", "line2": "யாக்கை பொறுத்த நிலம்.", "translation": "The land will shrink in yield if men  O'erburden it without renown"}, {"number": 240, "line1": "வசையொழிய வாழ்வாரே வாழ்வார் இசையொழிய", "line2": "வாழ்வாரே வாழா தவர்.", "translation": "They live who live without blemish  The blameful ones do not flurish"}, {"number": 241, "line1": "அருட்செல்வம் செல்வத்துள் செல்வம் பொருட்செல்வம்", "line2": "பூரியார் கண்ணும் உள.", "translation": "The wealth of wealth is wealth of grace  Earthly wealth e'en the basest has"}, {"number": 242, "line1": "நல்லாற்றாள் நாடி அருளாள்க பல்லாற்றால்", "line2": "தேரினும் அஃதே துணை.", "translation": "Seek by sound ways good compassion;  All faiths mark that for-salvation"}, {"number": 243, "line1": "அருள்சேர்ந்த நெஞ்சினார்க் கில்லை இருள்சேர்ந்த", "line2": "இன்னா உலகம் புகல்.", "translation": "The hearts of mercy shall not go  Into dark worlds of gruesome woe"}, {"number": 244, "line1": "மன்னுயிர் ஓம்பி அருளாள்வார்க்கு இல்லென்ப", "line2": "தன்னுயிர் அஞ்சும் வினை.", "translation": "His soul is free from dread of sins  Whose mercy serveth all beings"}, {"number": 245, "line1": "அல்லல் அருளாள்வார்க்கு இல்லை வளிவழங்கும்", "line2": "மல்லன்மா ஞாலங் கரி.", "translation": "The wide wind-fed world witness bears:  Men of mercy meet not sorrows"}, {"number": 246, "line1": "பொருள்நீங்கிப் பொச்சாந்தார் என்பர் அருள்நீங்கி", "line2": "அல்லவை செய்தொழுகு வார்.", "translation": "Who grace forsake and graceless act  The former loss and woes forget"}, {"number": 247, "line1": "அருளில்லார்க்கு அவ்வுலகம் இல்லை பொருளில்லார்க்கு", "line2": "இவ்வுலகம் இல்லாகி யாங்கு.", "translation": "This world is not for weathless ones  That world is not for graceless swines"}, {"number": 248, "line1": "பொருளற்றார் பூப்பர் ஒருகால் அருளற்றார்", "line2": "அற்றார்மற் றாதல் அரிது.", "translation": "The wealthless may prosper one day;  The graceless never bloom agay"}, {"number": 249, "line1": "தெருளாதான் மெய்ப்பொருள் கண்டற்றால் தேரின்", "line2": "அருளாதான் செய்யும் அறம்.", "translation": "Like Truth twisted by confused mind  Wisdom is vain in hearts unkind"}, {"number": 250, "line1": "வலியார்முன் தன்னை நினைக்கதான் தன்னின்", "line2": "மெலியார்மேல் செல்லு மிடத்து.", "translation": "Think how you feel before the strong  When to the feeble you do wrong"}, {"number": 251, "line1": "தன்னூன் பெருக்கற்குத் தான்பிறிது ஊனுண்பான்", "line2": "எங்ஙனம் ஆளும் அருள்?", "translation": "What graciousness can one command  who feeds his flesh by flesh gourmand"}, {"number": 252, "line1": "பொருளாட்சி போற்றாதார்க்கு இல்லை அருளாட்சி", "line2": "ஆங்கில்லை ஊன்தின் பவர்க்கு.", "translation": "The thriftless have no property  And flesh-eaters have no pity"}, {"number": 253, "line1": "படைகொண்டார் நெஞ்சம்போல் நன்னூக்காது ஒன்றன்", "line2": "உடல்சுவை உண்டார் மனம்.", "translation": "Who wields a steel is steel-hearted  Who tastes body is hard-hearted"}, {"number": 254, "line1": "அருளல்ல தியாதெனிற் கொல்லாமை கோறல்", "line2": "பொருளல்லது அவ்வூன் தினல்.", "translation": "If merciless it is to kill,  To kill and eat is disgraceful"}, {"number": 255, "line1": "உண்ணாமை உள்ளது உயிர்நிலை ஊனுண்ண", "line2": "அண்ணாத்தல் செய்யாது அளறு.", "translation": "Off with flesh; a life you save  The eater hell's mouth shall not waive!"}, {"number": 256, "line1": "தினற்பொருட்டால் கொல்லாது உலகெனின் யாரும்", "line2": "விலைப்பொருட்டால் ஊன்றருவா ரில்.", "translation": "None would kill and sell the flesh  For eating it if they don't wish"}, {"number": 257, "line1": "உண்ணாமை வேண்டும் புலாஅல் பிறிதொன்றன்", "line2": "புண்ணது உணர்வார்ப் பெறின்.", "translation": "From eating flesh men must abstain  If they but feel the being's pain"}, {"number": 258, "line1": "செயிரின் தலைப்பிரிந்த காட்சியார் உண்ணார்", "line2": "உயிரின் தலைப்பிரிந்த ஊன்.", "translation": "Whose mind from illusion is freed  Refuse on lifeless flesh to feed"}, {"number": 259, "line1": "அவிசொரிந் தாயிரம் வேட்டலின் ஒன்றன்", "line2": "உயிர்செகுத் துண்ணாமை நன்று.", "translation": "Not to-kill-and-eat, truly  Excels thousand pourings of ghee!"}, {"number": 260, "line1": "கொல்லான் புலாலை மறுத்தானைக் கைகூப்பி", "line2": "எல்லா உயிருந் தொழும்.", "translation": "All lives shall lift their palms to him  Who eats not flesh nor kills with whim"}, {"number": 261, "line1": "உற்றநோய் நோன்றல் உயிர்க்குறுகண் செய்யாமை", "line2": "அற்றே தவத்திற் குரு.", "translation": "Pains endure; pain not beings  This is the type of true penance"}, {"number": 262, "line1": "தவமும் தவமுடையார்க்கு ஆகும் அதனை", "line2": "அஃதிலார் மேற்கொள் வது.", "translation": "Penance is fit for penitents  Not for him who in vain pretends"}, {"number": 263, "line1": "துறந்தார்க்குத் துப்புரவு வேண்டி மறந்தார்கொல்", "line2": "மற்றை யவர்கள் தவம்.", "translation": "Is it to true penitent's aid,  That others austere path avoid?"}, {"number": 264, "line1": "ஒன்னார்த் தெறலும் உவந்தாரை ஆக்கலும்", "line2": "எண்ணின் தவத்தான் வரும்.", "translation": "In penance lies the power to save  The friends and foil the foe and knave"}, {"number": 265, "line1": "வேண்டிய வேண்டியாங் கெய்தலால் செய்தவம்", "line2": "ஈண்டு முயலப் படும்.", "translation": "What they wish as they wish is won  Here hence by men penance is done"}, {"number": 266, "line1": "தவஞ்செய்வார் தங்கருமஞ் செய்வார்மற் றல்லார்", "line2": "அவஞ்செய்வார் ஆசையுட் பட்டு.", "translation": "Who do penance achieve their aim  Others desire-rid themselves harm"}, {"number": 267, "line1": "சுடச்சுடரும் பொன்போல் ஒளிவிடும் துன்பஞ்", "line2": "சுடச்சுட நோற்கிற் பவர்க்கு.", "translation": "Pure and bright gets the gold in fire;  and so the life by pain austere"}, {"number": 268, "line1": "தன்னுயிர் தான்அறப் பெற்றானை ஏனைய", "line2": "மன்னுயி ரெல்லாந் தொழும்.", "translation": "He worship wins from every soul  Who Master is by soul control"}, {"number": 269, "line1": "கூற்றம் குதித்தலும் கைகூடும் நோற்றலின்", "line2": "ஆற்றல் தலைப்பட் டவர்க்குல்.", "translation": "They can even defy death  Who get by penance godly strenth"}, {"number": 270, "line1": "இலர்பல ராகிய காரணம் நோற்பார்", "line2": "சிலர்பலர் நோலா தவர்.", "translation": "Many are poor and few are rich  For they care not for penance much"}, {"number": 271, "line1": "வஞ்ச மனத்தான் படிற்றொழுக்கம் பூதங்கள்", "line2": "ஐந்தும் அகத்தே நகும்.", "translation": "Elements five of feigned life  Of a sly hypocrite within laugh"}, {"number": 272, "line1": "வானுயர் தோற்றம் எவன்செய்யும் தன்னெஞ்சம்", "line2": "தான்அறி குற்றப் படின்.", "translation": "Of what avail are sky-high shows  When guild the conscience gnaws and knows"}, {"number": 273, "line1": "வலியில் நிலைமையான் வல்லுருவம் பெற்றம்", "line2": "புலியின்தோல் போர்த்துமேய்ந் தற்று.", "translation": "Vaunting sainthood while week within  Seems a grazer with tiger skin"}, {"number": 274, "line1": "தவமறைந்து அல்லவை செய்தல் புதல்மறைந்து", "line2": "வேட்டுவன் புள்சிமிழ்த் தற்று.", "translation": "Sinning in saintly show is like  Fowlers in ambush birds to strike"}, {"number": 275, "line1": "பற்றற்றேம் என்பார் படிற்றொழுக்கம் எற்றெற்றென்று", "line2": "ஏதம் பலவுந் தரும்.", "translation": "Who false within but freedom feign  Shall moan \\\"What have we done\\\" with pain"}, {"number": 276, "line1": "நெஞ்சின் துறவார் துறந்தார்போல் வஞ்சித்து", "line2": "வாழ்வாரின் வன்கணார் இல்.", "translation": "Vilest is he who seems a saint  Cheating the world without restraint"}, {"number": 277, "line1": "புறங்குன்றி கண்டனைய ரேனும் அகங்குன்றி", "line2": "முக்கிற் கரியார் உடைத்து.", "translation": "Berry-red is his outward view,  Black like its nose his inward hue"}, {"number": 278, "line1": "மனத்தது மாசாக மாண்டார் நீராடி", "line2": "மறைந்தொழுகு மாந்தர் பலர்.", "translation": "Filthy in mind some bathe in streams  Hiding sins in showy extremes"}, {"number": 279, "line1": "கணைகொடிது யாழ்கோடு செவ்விதுஆங் கன்ன", "line2": "வினைபடு பாலால் கொளல்.", "translation": "Know men by acts and not by forms  Strait arrow kills, bent lute but charms"}, {"number": 280, "line1": "மழித்தலும் நீட்டலும் வேண்டா உலகம்", "line2": "பழித்தது ஒழித்து விடின்.", "translation": "No balding nor tangling the hair!  Abstain from condemned acts with care"}, {"number": 281, "line1": "எள்ளாமை வேண்டுவான் என்பான் எனைத்தொன்றும்", "line2": "கள்ளாமை காக்கதன் நெஞ்சு.", "translation": "Let him who would reproachless be  From all frauds guard his conscience free"}, {"number": 282, "line1": "உள்ளத்தால் உள்ளலும் தீதே பிறன்பொருளைக்", "line2": "கள்ளத்தால் கள்வேம் எனல்.", "translation": "\\\"We will by fraud win other's wealth\\\"  Even this thought is sin and stealth"}, {"number": 283, "line1": "களவினால் ஆகிய ஆக்கம் அளவிறந்து", "line2": "ஆவது போலக் கெடும்.", "translation": "The gain by fraud may overflow  But swift to ruin it shall go"}, {"number": 284, "line1": "களவின்கண் கன்றிய காதல் விளைவின்கண்", "line2": "வீயா விழுமம் தரும்.", "translation": "The fruit that fraud and greed obtain  Shall end in endless grief and pain"}, {"number": 285, "line1": "அருள்கருதி அன்புடைய ராதல் பொருள்கருதிப்", "line2": "பொச்சாப்புப் பார்ப்பார்கண் இல்.", "translation": "Love and Grace are not their worth  Who watch to waylay dozer's wealth"}, {"number": 286, "line1": "அளவின்கண் நின்றொழுகல் ஆற்றார் களவின்கண்", "line2": "கன்றிய காத லவர்.", "translation": "They cannot walk in measured bounds  who crave and have covetous ends"}, {"number": 287, "line1": "களவென்னும் காரறி வாண்மை அளவென்னும்", "line2": "ஆற்றல் புரிந்தார்கண்ட இல்.", "translation": "Men of measured wisdom shun  Black art of fraud and what it won"}, {"number": 288, "line1": "அளவறிந்தார் நெஞ்சத் தறம்போல நிற்கும்", "line2": "களவறிந்தார் நெஞ்சில் கரவு.", "translation": "Virtue abides in righteous hearts  Into minds of frauds deceit darts"}, {"number": 289, "line1": "அளவல்ல செய்தாங்கே வீவர் களவல்ல", "line2": "மற்றைய தேற்றா தவர்.", "translation": "They perish in their perfidy  Who know nothing but pilfery"}, {"number": 290, "line1": "கள்வார்க்குத் தள்ளும் உயிர்நிலை கள்வார்க்குத்", "line2": "தள்ளாது புத்தே ளுளகு.", "translation": "Even the body rejects thieves;  The honest men, heaven receives"}, {"number": 291, "line1": "வாய்மை எனப்படுவது யாதெனின் யாதொன்றும்", "line2": "தீமை இலாத சொலல்.", "translation": "If \\\"What is truth\\\"? the question be,  It is to speak out evil-free"}, {"number": 292, "line1": "பொய்மையும் வாய்மை யிடத்த புரைதீர்ந்த", "line2": "நன்மை பயக்கும் எனின்.", "translation": "E'en falsehood may for truth suffice,  When good it brings removing vice"}, {"number": 293, "line1": "தன்நெஞ் சறிவது பொய்யற்க பொய்த்தபின்", "line2": "தன்நெஞ்சே தன்னைச் சுடும்.", "translation": "Let not a man knowingly lie;  Conscience will scorch and make him sigh"}, {"number": 294, "line1": "உள்ளத்தாற் பொய்யா தொழுகின் உலகத்தார்", "line2": "உள்ளத்து ளெல்லாம் உளன்.", "translation": "He lives in loving hearts of all  Who serves the Truth serene in soul"}, {"number": 295, "line1": "மனத்தொடு வாய்மை மொழியின் தவத்தொடு", "line2": "தானஞ்செய் வாரின் தலை.", "translation": "To speak the truth from heart sincere  Is more than giving and living austere"}, {"number": 296, "line1": "பொய்யாமை அன்ன புகழில்லை எய்யாமை", "line2": "எல்லா அறமுந் தரும்.", "translation": "Not to lie brings all the praise  All virtues from Truth arise"}, {"number": 297, "line1": "பொய்யாமை பொய்யாமை ஆற்றின் அறம்பிற", "line2": "செய்யாமை செய்யாமை நன்று.", "translation": "Lie not lie not Naught else you need  All virtues are in Truth indeed"}, {"number": 298, "line1": "புறள்தூய்மை நீரான் அமையும் அகந்தூய்மை", "line2": "வாய்மையால் காணப் படும்.", "translation": "Water makes you pure outward  Truth renders you pure inward"}, {"number": 299, "line1": "எல்லா விளக்கும் விளக்கல்ல சான்றோர்க்குப்", "line2": "பொய்யா விளக்கே விளக்கு.", "translation": "All lights are not lights for the wise;  Truth light is light bright like Sun-light"}, {"number": 300, "line1": "யாமெய்யாக் கண்டவற்றுள் இல்லை எனைத்தொன்றும்", "line2": "வாய்மையின் நல்ல பிற.", "translation": "Of all the things we here have seen  Nothing surpasses Truth serene!"}, {"number": 301, "line1": "செல்லிடத்துக் காப்பான் சினங்காப்பான் அல்லிடத்துக்", "line2": "காக்கின்என் காவாக்கால் என்?", "translation": "Anger against the weak is wrong  It is futile against the strong"}, {"number": 302, "line1": "செல்லா இடத்துச் சினந்தீது செல்லிடத்தும்", "line2": "இல்அதனின் தீய பிற.", "translation": "Vain is wrath against men of force  Against the meek it is still worse"}, {"number": 303, "line1": "மறத்தல் வெகுளியை யார்மாட்டும் தீய", "line2": "பிறத்தல் அதனான் வரும்.", "translation": "Off with wrath with any one  It is the source of sin and pain"}, {"number": 304, "line1": "நகையும் உவகையும் கொல்லும் சினத்தின்", "line2": "பகையும் உளவோ பிற.", "translation": "Is there a foe like harmful ire  Which kills the smile and joyful cheer?"}, {"number": 305, "line1": "தன்னைத்தான் காக்கின் சினங்காக்க காவாக்கால்", "line2": "தன்னையே கொல்லுஞ் சினம்.", "translation": "Thyself to save, from wrath away!  If not thyself the wrath will slay"}, {"number": 306, "line1": "சினமென்னும் சேர்ந்தாரைக் கொல்லி இனமென்னும்", "line2": "ஏமப் புணையைச் சுடும்.", "translation": "Friend-killer is the fatal rage  It burns the helpful kinship-barge"}, {"number": 307, "line1": "சினத்தைப் பொருளென்று கொண்டவன் கேடு", "line2": "நிலத்தறைந்தான் கைபிழையா தற்று.", "translation": "The wrath-lover to doom is bound  Like failless-hand that strikes the ground"}, {"number": 308, "line1": "இணர்எரி தோய்வன்ன இன்னா செயினும்", "line2": "புணரின் வெகுளாமை நன்று.", "translation": "Save thy soul from burning ire  Though tortured like the touch of fire"}, {"number": 309, "line1": "உள்ளிய தெல்லாம் உடனெய்தும் உள்ளத்தால்", "line2": "உள்ளான் வெகுளி எனின்.", "translation": "Wishes he gains as he wishes  If man refrains from rage vicious!"}, {"number": 310, "line1": "இறந்தார் இறந்தார் அனையர் சினத்தைத்", "line2": "துறந்தார் துறந்தார் துணை.", "translation": "Dead are they who are anger-fed  Saints are they from whom wrath has fled"}, {"number": 311, "line1": "சிறப்பீனும் செல்வம் பெறினும் பிறர்க்குஇன்னா", "line2": "செய்யாமை மாசற்றார் கோள்.", "translation": "The pure by faith mean pain to none  Though princely wealth by that is won"}, {"number": 312, "line1": "கறுத்துஇன்னா செய்தவக் கண்ணும் மறுத்தின்னா", "line2": "செய்யாமை மாசற்றார் கோள்.", "translation": "The spotless hearts seek not revenge  Though Malice does the worst in rage"}, {"number": 313, "line1": "செய்யாமல் செற்றார்க்கும் இன்னாத செய்தபின்", "line2": "உய்யா விழுமந் தரும்.", "translation": "Revenging even causeless hate  Bad-blood breeds and baneful heat"}, {"number": 314, "line1": "இன்னாசெய் தாரை ஒறுத்தல் அவர்நாண", "line2": "நன்னயஞ் செய்து விடல்.", "translation": "Doing good-turns, put them to shame  Thus chide the evil who do harm"}, {"number": 315, "line1": "அறிவினான் ஆகுவ துண்டோ பிறிதின்நோய்", "line2": "தந்நோய்போல் போற்றாக் கடை.", "translation": "What does a man from wisdom gain  If he pines not at other's pain?"}, {"number": 316, "line1": "இன்னா எனத்தான் உணர்ந்தவை துன்னாமை", "line2": "வேண்டும் பிறன்கண் செயல்.", "translation": "What you feel as pain to yourself  Do it not to the other-self"}, {"number": 317, "line1": "எனைத்தானும் எஞ்ஞான்றும் யார்க்கும் மனத்தானாம்", "line2": "மாணாசெய் யாமை தலை.", "translation": "Any, anywhere injure not  At any time even in thought"}, {"number": 318, "line1": "தன்னுயிர்ககு ஏன்னாமை தானறிவான் என்கொலோ", "line2": "மன்னுயிர்க்கு இன்னா செயல்.", "translation": "How can he injure other souls  Who in his life injury feels"}, {"number": 319, "line1": "பிறர்க்கின்னா முற்பகல் செய்யின் தமக்குஇன்னா", "line2": "பிற்பகல் தாமே வரும்.", "translation": "Harm others in the forenoon  Harm seeks thee in afternoon"}, {"number": 320, "line1": "நோயெல்லாம் நோய்செய்தார் மேலவாம் நோய்செய்யார்", "line2": "நோயின்மை வேண்டு பவர்.", "translation": "No harm is done by peace-lovers  For pains rebound on pain-givers"}, {"number": 321, "line1": "அறவினை யாதெனின் கொல்லாமை கோறல்", "line2": "பிறவினை எல்லாந் தரும்.", "translation": "What is Virtue? 'Tis not to kill  For killing causes every ill"}, {"number": 322, "line1": "பகுத்துண்டு பல்லுயிர் ஓம்புதல் நூலோர்", "line2": "தொகுத்தவற்றுள் எல்லாந் தலை.", "translation": "Share the food and serve all lives  This is the law of all the laws"}, {"number": 323, "line1": "ஒன்றாக நல்லது கொல்லாமை மற்றதன்", "line2": "பின்சாரப் பொய்யாமை நன்று.", "translation": "Not to kill is unique good  The next, not to utter falsehood"}, {"number": 324, "line1": "நல்லாறு எனப்படுவது யாதெனின் யாதொன்றும்", "line2": "கொல்லாமை சூழும் நெறி.", "translation": "What way is good? That we can say  The way away from heat to slay"}, {"number": 325, "line1": "நிலைஅஞ்சி நீத்தாருள் எல்லாம் கொலைஅஞ்சிக்", "line2": "கொல்லாமை சூழ்வான் தலை.", "translation": "Of saints who renounce birth-fearing  The head is he who dreads killing"}, {"number": 326, "line1": "கொல்லாமை மேற்கொண் டொழுகுவான் வாழ்நாள்மேல்", "line2": "செல்லாது உயிருண்ணுங் கூற்று.", "translation": "Life-eating-Death shall spare the breath  Of him who no life puts to death"}, {"number": 327, "line1": "தன்னுயிர் நீப்பினும் செய்யற்க தான்பிறிது", "line2": "இன்னுயிர் நீக்கும் வினை.", "translation": "Kill not life that others cherish  Even when your life must perish"}, {"number": 328, "line1": "நன்றாகும் ஆக்கம் பெரிதெனினும் சான்றோர்க்குக்", "line2": "கொன்றாகும் ஆக்கங் கடை.", "translation": "The gain of slaughter is a vice  Though deemed good in sacrifice"}, {"number": 329, "line1": "கொலைவினைய ராகிய மாக்கள் புலைவினையர்", "line2": "புன்மை தெரிவா ரகத்து.", "translation": "Those who live by slaying are  Eaters of carrion bizarre!"}, {"number": 330, "line1": "உயிருடம்பின் நீக்கியா ரென்ப செயிருடம்பின்", "line2": "செல்லாத்தீ வாழ்க்கை யவர்.", "translation": "The loathsome poor sickly and sore  Are killers stained by blood before"}, {"number": 331, "line1": "நில்லாத வற்றை நிலையின என்றுணரும்", "line2": "புல்லறி வாண்மை கடை.", "translation": "The worst of follies it is told  The fleeting as lasting to hold"}, {"number": 332, "line1": "கூத்தாட்டு அவைக்குழாத் தற்றே பெருஞ்செல்வம்", "line2": "போக்கும் அதுவிளிந் தற்று.", "translation": "Like a drama-crowd wealth gathers  Like passing show its pride too goes"}, {"number": 333, "line1": "அற்கா இயல்பிற்றுச் செல்வம் அதுபெற்றால்", "line2": "அற்குப ஆங்கே செயல்.", "translation": "Wealth wanes away; but when it comes  Take care to do enduring things"}, {"number": 334, "line1": "நாளென ஒன்றுபோற் காட்டி உயிர்ஈரும்", "line2": "வாளது உணர்வார்ப் பெறின்.", "translation": "The showy day is but a saw  Your life, know that, to file and gnaw"}, {"number": 335, "line1": "நாச்செற்று விக்குள்மேல் வாராமுன் நல்வினை", "line2": "மேற்சென்று செய்யப் படும்", "translation": "Ere tongue benumbs and hiccough comes  Rise up to do good deeds betimes"}, {"number": 336, "line1": "நெருநல் உளனொருவன் இன்றில்லை என்னும்", "line2": "பெருமை உடைத்துஇவ் வுலகு.", "translation": "One was yesterday; not today!"}, {"number": 337, "line1": "ஒருபொழுதும் வாழ்வது அறியார் கருதுப", "line2": "கோடியும் அல்ல பல.", "translation": "Man knows not his next moment  On crores of things he is intent"}, {"number": 338, "line1": "குடம்பை தனித்துஒழியப் புள்பறந் தற்றே", "line2": "உடம்பொடு உயிரிடை நட்பு.", "translation": "The soul from body any day  Like bird from egg-shell flies away"}, {"number": 339, "line1": "உறங்கு வதுபோலுஞ் சாக்காடு உறங்கி", "line2": "விழிப்பது போலும் பிறப்பு.", "translation": "Death is like a slumber deep  And birth like waking from that sleep"}, {"number": 340, "line1": "புக்கில் அமைந்தின்று கொல்லோ உடம்பினுள்", "line2": "துச்சில் இருந்த உயிர்க்கு.", "translation": "The life berthed in this body shows  A fixed home it never knows"}, {"number": 341, "line1": "யாதனின் யாதனின் நீங்கியான் நோதல்", "line2": "அதனின் அதனின் இலன்.", "translation": "From what from what a man is free  From that, from that his torments flee"}, {"number": 342, "line1": "வேண்டின்உண் டாகத் துறக்க துறந்தபின்", "line2": "ஈண்டுஇயற் பால பல.", "translation": "Give up all to gain the True  And endless joys shall hence seek you"}, {"number": 343, "line1": "அடல்வேண்டும் ஐந்தன் புலத்தை விடல்வேண்டும்", "line2": "வேண்டிய வெல்லாம் ஒருங்கு.", "translation": "Curb the senses five and renounce  The carving desires all at once"}, {"number": 344, "line1": "இயல்பாகும் நோன்பிற்கொன்று இன்மை உடைமை", "line2": "மயலாகும் மற்றும் பெயர்த்து.", "translation": "To have nothing is law of vows  Having the least deludes and snares"}, {"number": 345, "line1": "மற்றும் தொடர்ப்பாடு எவன்கொல் பிறப்பறுக்கல்", "line2": "உற்றார்க்கு உடம்பும் மிகை.", "translation": "Why add to bonds while this body  Is too much for saints to be birth-free"}, {"number": 346, "line1": "யான்எனது என்னும் செருக்குஅறுப்பான் வானோர்க்கு", "line2": "உயர்ந்த உலகம் புகும்.", "translation": "Who curbs the pride of I and mine  Gets a world rare for gods to gain"}, {"number": 347, "line1": "பற்றி விடாஅ இடும்பைகள் பற்றினைப்", "line2": "பற்றி விடாஅ தவர் க்கு.", "translation": "Grief clings on and on to those  Who cling to bonds without release"}, {"number": 348, "line1": "தலைப்பட்டார் தீரத் துறந்தார் மயங்கி", "line2": "வலைப்பட்டார் மற்றை யவர்.", "translation": "Who renounce all are free from care  Others suffer delusive snare"}, {"number": 349, "line1": "பற்றற்ற கண்ணே பிறப்பறுக்கும் மற்று", "line2": "நிலையாமை காணப் படும்.", "translation": "Bondage cut off, rebirth is off  The world then seems instable stuff"}, {"number": 350, "line1": "பற்றுக பற்றற்றான் பற்றினை அப்பற்றைப்", "line2": "பற்றுக பற்று விடற்கு.", "translation": "Bind Thyself to the unbound one  That binding breaks all bonds anon"}, {"number": 351, "line1": "பொருளல்ல வற்றைப் பொருளென்று உணரும்", "line2": "மருளானாம் மாணாப் பிறப்பு.", "translation": "That error entails ignoble birth  Which deems vain things as things of worth"}, {"number": 352, "line1": "இருள்நீங்கி இன்பம் பயக்கும் மருள்நீங்கி", "line2": "மாசறு காட்சி யவர்க்கு.", "translation": "Men of spotless pure insight  Enjoy delight devoid of night"}, {"number": 353, "line1": "ஐயத்தின் நீங்கித் தெளிந்தார்க்கு வையத்தின்", "line2": "வானம் நணிய துடைத்து.", "translation": "To doubtless minds whose heart is clear  More than earth heaven is near"}, {"number": 354, "line1": "ஐயுணர்வு எய்தியக் கண்ணும் பயமின்றே", "line2": "மெய்யுணர்வு இல்லா தவர்க்கு.", "translation": "Knowledge of five senses is vain  Without knowing the Truth within"}, {"number": 355, "line1": "எப்பொருள் எத்தன்மைத் தாயினும் அப்பொருள்", "line2": "மெய்ப்பொருள் காண்பது அறிவு.", "translation": "Knowledge is truth of things to find  In every case of every kind"}, {"number": 356, "line1": "கற்றீண்டு மெய்ப்பொருள் கண்டார் தலைப்படுவர்", "line2": "மற்றீண்டு வாரா நெறி.", "translation": "Who learn and here the Truth discern  Enter the path of non-return"}, {"number": 357, "line1": "ஓர்த்துள்ளம் உள்ளது உணரின் ஒருதலையாப்", "line2": "பேர்த்துள்ள வேண்டா பிறப்பு.", "translation": "One-minded sage sees inner-truth  He is free from thoughts of rebirth"}, {"number": 358, "line1": "பிறப்பென்னும் பேதைமை நீங்கச் சிறப்பென்னும்", "line2": "செம்பொருள் காண்பது அறிவு.", "translation": "It is knowledge to know Self-Truth  And remove the folly of birth"}, {"number": 359, "line1": "சார்புணர்ந்து சார்பு கெடஒழுகின் மற்றழித்துச்", "line2": "சார்தரா சார்தரு நோய்.", "translation": "Know the Refuge; off with bondage  Be free from ills of thraldom, O sage"}, {"number": 360, "line1": "காமம் வெகுளி மயக்கம் இவ்மூன்றன்", "line2": "நாமம் கெடக்கெடும் நோய்.", "translation": "Woes expire when lust, wrath, folly  Expire even to name, fully"}, {"number": 361, "line1": "அவாஎன்ப எல்லா உயிர்க்கும் எஞ்ஞான்றும்", "line2": "தவாஅப் பிறப்பீனும் வித்து.", "translation": "Desire to all, always is seed  From which ceaseless births proceed"}, {"number": 362, "line1": "வேண்டுங்கால் வேண்டும் பிறவாமை மற்றது", "line2": "வேண்டாமை வேண்ட வரும்.", "translation": "If long thou must, long for non-birth  It comes by longing no more for earth"}, {"number": 363, "line1": "வேண்டாமை அன்ன விழுச்செல்வம் ஈண்டில்லை", "line2": "ஆண்டும் அஃதொப்பது இல்.", "translation": "No such wealth is here and there  As peerless wealth of non-desire"}, {"number": 364, "line1": "தூஉய்மை என்பது அவாவின்மை மற்றது", "line2": "வாஅய்மை வேண்ட வரும்.", "translation": "To nothing crave is purity  That is the fruit of verity"}, {"number": 365, "line1": "அற்றவர் என்பார் அவாஅற்றார் மற்றையார்", "line2": "அற்றாக அற்றது இலர்.", "translation": "The free are those who desire not  The rest not free in bonds are caught"}, {"number": 366, "line1": "அஞ்சுவ தோரும் அறனே ஒருவனை", "line2": "வஞ்சிப்ப தோரும் அவா.", "translation": "Dread desire; Virtue is there  To every soul desire is snare!"}, {"number": 367, "line1": "அவாவினை ஆற்ற அறுப்பின் தவாவினை", "line2": "தான்வேண்டு மாற்றான் வரும்.", "translation": "Destroy desire; deliverance  Comes as much as you aspire hence"}, {"number": 368, "line1": "அவாஇல்லார்க் கில்லாகுந் துன்பம் அஃதுண்டேல்", "line2": "தவாஅது மேன்மேல் வரும்.", "translation": "Desire extinct no sorrow-taints  Grief comes on grief where it pretends"}, {"number": 369, "line1": "இன்பம் இடையறா தீண்டும் அவாவென்னும்", "line2": "துன்பத்துள் துன்பங் கெடின்.", "translation": "Desire, the woe of woes destroy  Joy of joys here you enjoy"}, {"number": 370, "line1": "ஆரா இயற்கை அவாநீப்பின் அந்நிலையே", "line2": "பேரா இயற்கை தரும்.", "translation": "Off with desire insatiate  You gain the native blissful state"}, {"number": 371, "line1": "ஆகூழால் தோன்றும் அசைவின்மை கைப்பொருள்", "line2": "போகூழால் தோன்றும் மடி.", "translation": "Efforts succeed by waxing star  Wealth-losing brings waning star"}, {"number": 372, "line1": "பேதைப் படுக்கும் இழவூழ் அறிவகற்றும்", "line2": "ஆகலூழ் உற்றக் கடை.", "translation": "Loss-fate makes a dull fool of us  Gain-fate makes us prosperous, wise!"}, {"number": 373, "line1": "நுண்ணிய நூல்பல கற்பினும் மற்றுந்தன்", "line2": "உண்மை யறிவே மிகும்.", "translation": "What matters subtle study deep?  Levels of innate wisdom-keep"}, {"number": 374, "line1": "இருவேறு உலகத்து இயற்கை திருவேறு", "line2": "தெள்ளிய ராதலும் வேறு.", "translation": "Two natures in the world obtain  Some wealth and others wisdom gain"}, {"number": 375, "line1": "நல்லவை எல்லாஅந் தீயவாம் தீயவும்", "line2": "நல்லவாம் செல்வம் செயற்கு.", "translation": "In making wealth fate changes mood;  The good as bad and bad as good"}, {"number": 376, "line1": "பரியினும் ஆகாவாம் பாலல்ல உய்த்துச்", "line2": "சொரியினும் போகா தம.", "translation": "Things not thine never remain  Things destined are surely thine"}, {"number": 377, "line1": "வகுத்தான் வகுத்த வகையல்லால் கோடி", "line2": "தொகுத்தார்க்கு துய்த்தல் அரிது.", "translation": "Who crores amass enjoy but what  The Dispenser's decrees allot"}, {"number": 378, "line1": "துறப்பார்மன் துப்புர வில்லார் உறற்பால", "line2": "ஊட்டா கழியு மெனின்.", "translation": "The destitute desire will quit  If fate with ills visit them not"}, {"number": 379, "line1": "நன்றாங்கால் நல்லவாக் காண்பவர் அன்றாங்கால்", "line2": "அல்லற் படுவ தெவன்?", "translation": "Who good in time of good perceive  In evil time why should they grieve?"}, {"number": 380, "line1": "ஊழிற் பெருவலி யாவுள மற்றொன்று", "line2": "சூழினுந் தான்முந் துறும்.", "translation": "What power surpasses fate? Its will  Persists against the human skill"}, {"number": 381, "line1": "படைகுடி கூழ்அமைச்சு நட்பரண் ஆறும்", "line2": "உடையான் அரசருள் ஏறு.", "translation": "People, troops, wealth, forts, council, friends  Who owns these six is lion of kings"}, {"number": 382, "line1": "அஞ்சாமை ஈகை அறிவூக்கம் இந்நான்கும்", "line2": "எஞ்சாமை வேந்தர்க் கியல்பு.", "translation": "Courage, giving, knowledge and zeal  Are four failless features royal"}, {"number": 383, "line1": "தூங்காமை கல்வி துணிவுடைமை இம்மூன்றும்", "line2": "நீங்கா நிலனான் பவர்க்கு.", "translation": "Alertness, learning bravery  Are adjuncts three of monarchy"}, {"number": 384, "line1": "அறனிழுக்கா தல்லவை நீக்கி மறனிழுக்கா", "line2": "மானம் உடைய தரசு.", "translation": "A brave noble king refrains from vice  Full of virtue and enterprise"}, {"number": 385, "line1": "இயற்றலும் ஈட்டலுங் காத்தலும் காத்த", "line2": "வகுத்தலும் வல்ல தரசு.", "translation": "The able king gets, stores and guards  And spends them for people's safeguards"}, {"number": 386, "line1": "காட்சிக் கெளியன் கடுஞ்சொல்லன் அல்லனேல்", "line2": "மீக்கூறும் மன்னன் நிலம்", "translation": "That land prospers where the king is  Easy to see, not harsh of words"}, {"number": 387, "line1": "இன்சொலால் ஈத்தளிக்க வல்லார்க்குத் தன்சொலால்", "line2": "தான்கண் டனைத்திவ் வுலகு.", "translation": "The world commends and acts his phrase  Who sweetly speaks and gives with grace"}, {"number": 388, "line1": "முறைசெய்து காப்பாற்றும் மன்னவன் மக்கட்கு", "line2": "இறையென்று வைக்கப் படும்.", "translation": "He is the Lord of men who does  Sound justice and saves his race"}, {"number": 389, "line1": "செவிகைப்பச் சொற்பொறுக்கும் பண்புடை வேந்தன்", "line2": "கவிகைக்கீழ்த் தங்கும் உலகு.", "translation": "Under his shelter thrives the world  Who bears remarks bitter and bold"}, {"number": 390, "line1": "கொடையளி செங்கோல் குடியோம்பல் நான்கும்", "line2": "உடையானாம் வேந்தர்க் கொளி.", "translation": "He is the Light of Kings who has  Bounty, justice, care and grace"}, {"number": 391, "line1": "கற்க கசடறக் கற்பவை கற்றபின்", "line2": "நிற்க அதற்குத் தக.", "translation": "Lore worth learning, learn flawlessly  Live by that learning thoroughly"}, {"number": 392, "line1": "எண்ணென்ப ஏனை எழுத்தென்ப இவ்விரண்டும்", "line2": "கண்ணென்ப வாழும் உயிர்க்கு.", "translation": "Letter, number, art and science  Of living kind both are the eyes"}, {"number": 393, "line1": "கண்ணுடையர் என்பவர் கற்றோர் முகத்திரண்டு", "line2": "புண்ணுடையர் கல்லா தவர்.", "translation": "The learned alone have eyes on face  The ignorant two sores of disgrace"}, {"number": 394, "line1": "உவப்பத் தலைக்கூடி உள்ளப் பிரிதல்", "line2": "அனைத்தே புலவர் தொழில்.", "translation": "To meet with joy and part with thought  Of learned men this is the art"}, {"number": 395, "line1": "உடையார்முன் இல்லார்போல் ஏக்கற்றுங் கற்றார்", "line2": "கடையரே கல்லா தவர்.", "translation": "Like poor before rich they yearn:  For knowledge: the low never learn"}, {"number": 396, "line1": "தொட்டனைத் தூறும் மணற்கேணி மாந்தர்க்குக்", "line2": "கற்றனைத் தூறும் அறிவு.", "translation": "As deep you dig the sand spring flows  As deep you learn the knowledge grows"}, {"number": 397, "line1": "யாதானும் நாடாமால் ஊராமால் என்னொருவன்", "line2": "சாந்துணையுங் கல்லாத வாறு.", "translation": "All lands and towns are learner's own  Why not till death learning go on!"}, {"number": 398, "line1": "ஒருமைக்கண் தான்கற்ற கல்வி ஒருவற்கு", "line2": "எழுமையும் ஏமாப் புடைத்து.", "translation": "The joy of learning in one birth  Exalts man upto his seventh"}, {"number": 399, "line1": "தாமின் புறுவது உலகின் புறக்கண்டு", "line2": "காமுறுவர் கற்றறிந் தார்.", "translation": "The learned foster learning more  On seeing the world enjoy their lore"}, {"number": 400, "line1": "கேடில் விழுச்செல்வம் கல்வி யொருவற்கு", "line2": "மாடல்ல மற்றை யவை.", "translation": "Learning is wealth none could destroy  Nothing else gives genuine joy"}, {"number": 401, "line1": "அரங்கின்றி வட்டாடி யற்றே நிரம்பிய", "line2": "நூலின்றிக் கோட்டி கொளல்.", "translation": "Like play of chess on squareless board  Vain is imperfect loreless word"}, {"number": 402, "line1": "கல்லாதான் சொற்கா முறுதல் முலையிரண்டும்", "line2": "இல்லாதாள் பெண்காமுற் றற்று.", "translation": "Unlearned man aspiring speech  Is breastless lady's love-approach"}, {"number": 403, "line1": "கல்லா தவரும் நனிநல்லர் கற்றார்முன்", "line2": "சொல்லா திருக்கப் பெறின்.", "translation": "Ev'n unread men are good and wise  If before the wise, they hold their peace"}, {"number": 404, "line1": "கல்லாதான் ஒட்பம் கழியநன் றாயினும்", "line2": "கொள்ளார் அறிவுடை யார்.", "translation": "The unread's wit though excellent  Is not valued by the savant"}, {"number": 405, "line1": "கல்லா ஒருவன் தகைமை தலைப்பெய்து", "line2": "சொல்லாடச் சோர்வு படும்.", "translation": "A man untaught when speech he vaunts  Sadly fails before savants"}, {"number": 406, "line1": "உளரென்னும் மாத்திரையர் அல்லால் பயவாக்", "line2": "களரனையர் கல்லா தவர்.", "translation": "People speak of untaught minds  \\\"They just exist like barren lands\\\""}, {"number": 407, "line1": "நுண்மாண் நுழைபுலம் இல்லான் எழில்நலம்", "line2": "மண்மாண் புனைபாவை யற்று.", "translation": "Like painted clay-doll is his show  Grand subtle lore who fails to know"}, {"number": 408, "line1": "நல்லார்கண் பட்ட வறுமையின் இன்னாதே", "line2": "கல்லார்கண் பட் ட திரு.", "translation": "Wealth in the hand of fools is worse  Than a learned man's empty purse"}, {"number": 409, "line1": "மேற்பிறந்தா ராயினும் கல்லாதார் கீழ்ப்பிறந்தும்", "line2": "கற்றார் அனைத்திலர் பாடு.", "translation": "Lower are fools of higher birth  Than low-born men of learning's worth"}, {"number": 410, "line1": "விலங்கொடு மக்கள் அனையர் இலங்குநூல்", "line2": "கற்றாரோடு ஏனை யவர்.", "translation": "Like beasts before men, dunces are  Before scholars of shining lore"}, {"number": 411, "line1": "செல்வத்துட் செல்வஞ் செவிச்செல்வம் அச்செல்வம்", "line2": "செல்வத்து ளெல்லாந் தலை.", "translation": "Wealth of wealths is listening's wealth  It is the best of wealths on earth"}, {"number": 412, "line1": "செவுக்குண வில்லாத போழ்து சிறிது", "line2": "வயிற்றுக்கும் ஈயப் படும்.", "translation": "Some food for the stomach is brought  When the ear gets no food for thought"}, {"number": 413, "line1": "செவியுணவிற் கேள்வி யுடையார் அவியுணவின்", "line2": "ஆன்றாரோ டொப்பர் நிலத்து.", "translation": "Whose ears get lots of wisdom-food  Equal gods on oblations fed"}, {"number": 414, "line1": "கற்றில னாயினுங் கேட்க அஃதொருவற்கு", "line2": "ஒற்கத்தின் ஊற்றாந் துணை.", "translation": "Though not learned, hear and heed  That serves a staff and stay in need"}, {"number": 415, "line1": "இழுக்கல் உடையுழி ஊற்றுக்கோல் அற்றே", "line2": "ஒழுக்க முடையார்வாய்ச் சொல்.", "translation": "Virtuous men's wisdom is found  A strong staff on slippery ground"}, {"number": 416, "line1": "எனைத்தானும் நல்லவை கேட்க அனைத்தானும்", "line2": "ஆன்ற பெருமை தரும்.", "translation": "Lend ear to good words however few  That much will highly exalt you"}, {"number": 417, "line1": "பிழைத்துணர்ந்தும் பேதைமை சொல்லா ரிழைத்துணர்ந்", "line2": "தீண்டிய கேள்வி யவர்.", "translation": "Who listen well and learn sharply  Not ev'n by slip speak foolishly"}, {"number": 418, "line1": "கேட்பினுங் கேளாத் தகையவே கேள்வியால்", "line2": "தோட்கப் படாத செவி.", "translation": "That ear though hearing is dulled  Which is not by wisdom drilled"}, {"number": 419, "line1": "நுணங்கிய கேள்விய ரல்லார் வணங்கிய", "line2": "வாயின ராதல் அரிது.", "translation": "A modest mouth is hard for those  Who care little to counsels wise"}, {"number": 420, "line1": "செவியிற் சுவையுணரா வாயுணர்வின் மாக்கள்", "line2": "அவியினும் வாழினும் என்?", "translation": "Who taste by mouth and not by ear  What if they fare ill or well here?"}, {"number": 421, "line1": "அறிவற்றங் காக்குங் கருவி செறுவார்க்கும்", "line2": "உள்ளழிக்க லாகா அரண்.", "translation": "Wisdom's weapon wards off all woes  It is a fort defying foes"}, {"number": 422, "line1": "சென்ற இடத்தால் செலவிடா தீதொரீஇ", "line2": "நன்றின்பால் உய்ப்ப தறிவு.", "translation": "Wisdom checks the straying senses  Expels evils, impels goodness"}, {"number": 423, "line1": "எப்பொருள் யார்யார்வாய்க் கேட்பினும் அப்பொருள்", "line2": "மெய்ப்பொருள் காண்ப தறிவு.", "translation": "To grasp the Truth from everywhere  From everyone is wisdom fair"}, {"number": 424, "line1": "எண்பொருள வாகச் செலச்சொல்லித் தான்பிறர்வாய்", "line2": "நுண்பொருள் காண்ப தறிவு.", "translation": "Speaking out thoughts in clear trends  Wisdom subtle sense comprehends"}, {"number": 425, "line1": "உலகம் தழீஇய தொட்பம் மலர்தலும்", "line2": "கூம்பலும் இல்ல தறிவு.", "translation": "The wise-world the wise befriend  They bloom nor gloom, equal in mind"}, {"number": 426, "line1": "எவ்வ துறைவது உலகம் உலகத்தோடு", "line2": "அவ்வ துறைவ தறிவு.", "translation": "As moves the world so move the wise  In tune with changing times and ways"}, {"number": 427, "line1": "அறிவுடையார் ஆவ தறிவார் அறிவிலார்", "line2": "அஃதறி கல்லா தவர்.", "translation": "The wise foresee what is to come  The unwise lack in that wisdom"}, {"number": 428, "line1": "அஞ்சுவ தஞ்சாமை பேதைமை அஞ்சுவது", "line2": "அஞ்சல் அறிவார் தொழில்.", "translation": "Fear the frightful and act wisely  Not to fear the frightful's folly"}, {"number": 429, "line1": "எதிரதாக் காக்கும் அறிவினார்க் கில்லை", "line2": "அதிர வருவதோர் நோய்.", "translation": "No frightful evil shocks the wise  Who guard themselves against surprise"}, {"number": 430, "line1": "அறிவுடையார் எல்லா முடையார் அறிவிலார்", "line2": "என்னுடைய ரேனும் இலர்.", "translation": "Who have wisdom they are all full  Whatev'r they own, misfits are nil"}, {"number": 431, "line1": "செருக்குஞ் சினமும் சிறுமையும் இல்லார்", "line2": "பெருக்கம் பெருமித நீர்த்து.", "translation": "Plenty is their prosperity  Who're free from wrath pride lust petty"}, {"number": 432, "line1": "இவறலும் மாண்பிறந்த மானமும் மாணா", "line2": "உவகையும் ஏதம் இறைக்கு.", "translation": "Mean pride, low pleasure, avarice  These add blemishes to a prince"}, {"number": 433, "line1": "தினைத்துணையாங் குற்றம் வரினும் பனைத்துணையாக்", "line2": "கொள்வர் பழிநாணு வார்.", "translation": "Though millet-small their faults might seem  Men fearing disgrace, Palm-tall deem"}, {"number": 434, "line1": "குற்றமே காக்க பொருளாகக் குற்றமே", "line2": "அற்றந் த்ரூஉம் பகை.", "translation": "Watch like treasure freedom from fault  Our fatal foe is that default"}, {"number": 435, "line1": "வருமுன்னர்க் காவாதான் வாழ்க்கை எரிமுன்னர்", "line2": "வைத்தூறு போலக் கெடும்.", "translation": "Who fails to guard himself from flaw  Loses his life like flame-lit straw"}, {"number": 436, "line1": "தன்குற்றம் நீக்கிப் பிறர்குற்றங் காண்கிற்பின்", "line2": "என்குற்ற மாகும் இறைக்கு?", "translation": "What fault can be the king's who cures  First his faults, then scans others"}, {"number": 437, "line1": "செயற்பால செய்யா திவறியான் செல்வம்", "line2": "உயற்பால தன்றிக் கெடும்.", "translation": "That miser's wealth shall waste and end  Who would not for a good cause spend"}, {"number": 438, "line1": "பற்றுள்ளம் என்னும் இவறன்மை எற்றுள்ளும்", "line2": "எண்ணப் படுவதொன் றன்று.", "translation": "The gripping greed of miser's heart  Is more than fault the worst apart"}, {"number": 439, "line1": "வியவற்க எஞ்ஞான்றும் தன்னை நயவற்க", "line2": "நன்றி பயவா வினை.", "translation": "Never boast yourself in any mood  Nor do a deed that does no good"}, {"number": 440, "line1": "காதல காதல் அறியாமை உய்க்கிற்பின்", "line2": "ஏதில ஏதிலார் நூல்.", "translation": "All designs of the foes shall fail  If one his wishes guards in veil"}, {"number": 441, "line1": "அறனறிந்து மூத்த அறிவுடையார் கேண்மை", "line2": "திறனறிந்து தேர்ந்து கொளல்.", "translation": "Weigh their worth and friendship gain  Of men of virtue and mature brain"}, {"number": 442, "line1": "உற்றநோய் நீக்கி உறாஅமை முற்காக்கும்", "line2": "பெற்றியார்ப் பேணிக் கொளல்.", "translation": "Cherish the help of men of skill  Who ward and safe-guard you from ill"}, {"number": 443, "line1": "அரியவற்று ளெல்லாம் அரிதே பெரியாரைப்", "line2": "பேணித் தமராக் கொளல்.", "translation": "Honour and have the great your own  Is rarest of the rare things known"}, {"number": 444, "line1": "தம்மிற் பெரியார் தமரா ஒழுகுதல்", "line2": "வன்மையு ளெல்லாந் தலை.", "translation": "To have betters as intimates  Power of all powers promotes"}, {"number": 445, "line1": "சூழ்வார்கண் ணாக ஒழுகலான் மன்னவன்", "line2": "சூழ்வாரைக் சூழ்ந்து கொளல்.", "translation": "Ministers are the monarch's eyes  Round him should be the right and wise"}, {"number": 446, "line1": "தக்கா ரினத்தனாய்த் தானொழுக வல்லானைச்", "line2": "செற்றார் செயக்கிடந்த தில்.", "translation": "To move with worthy friends who knows  Has none to fear from frightful foes"}, {"number": 447, "line1": "இடிக்குந் துணையாரை யாள்வரை யாரே", "line2": "கெடுக்குந் தகைமை யவர்.", "translation": "No foe can foil his powers  whose friends reprove him when he errs"}, {"number": 448, "line1": "இடிப்பாரை இல்லாத ஏமரா மன்னன்", "line2": "கெடுப்பா ரிலானுங் கெடும்.", "translation": "The careless king whom none reproves  Ruins himself sans harmful foes"}, {"number": 449, "line1": "முதலிலார்க ஊதிய மில்லை மதலையாஞ்", "line2": "சார்பிலார்க் கில்லை நிலை.", "translation": "No capital, no gain in trade  No prop secure sans good comrade"}, {"number": 450, "line1": "பல்லார் பகைகொளலிற் பத்தடுத்த தீமைத்தே", "line2": "நல்லார் தொடர்கை விடல்.", "translation": "To give up good friends is ten times worse  Than being hated by countless foes"}, {"number": 451, "line1": "சிற்றினம் அஞ்சும் பெருமை சிறுமைதான்", "line2": "சுற்றமாச் சூழ்ந்து விடும்.", "translation": "The ignoble the noble fear  The mean hold them as kinsmen dear"}, {"number": 452, "line1": "நிலத்தியல்பால் நீர்திரிந் தற்றாகும் மாந்தர்க்கு", "line2": "இனத்தியல்ப தாகும் அறிவு.", "translation": "With soil changes water's taste  With mates changes the mental state"}, {"number": 453, "line1": "மனத்தானாம் மாந்தர்க் குணர்ச்சி இனத்தானாம்", "line2": "இன்னான் எனப்படுஞ் சொல்.", "translation": "Wisdom depends upon the mind  The worth of man upon his friend"}, {"number": 454, "line1": "மனத்து ளதுபோலக் காட்டி ஒருவற்கு", "line2": "இனத்துள தாகும் அறிவு.", "translation": "Wisdom seems to come from mind  But it truly flows from the kind"}, {"number": 455, "line1": "மனந்தூய்மை செய்வினை தூய்மை இரண்டும்", "line2": "இனந்தூய்மை தூவா வரும்.", "translation": "Purity of the thought and deed  Comes from good company indeed"}, {"number": 456, "line1": "மனந்தூயார்க் கெச்சம்நன் றாகும் இனந்தூயார்க்கு", "line2": "இல்லைநன் றாகா வினை.", "translation": "Pure-hearted get good progeny  Pure friendship acts with victory"}, {"number": 457, "line1": "மனநலம் மன்னுயிர்க் காக்கம் இனநலம்", "line2": "எல்லாப் புகழும் தரும்.", "translation": "Goodness of mind increases gain  Good friendship fosters fame again"}, {"number": 458, "line1": "மனநலம் நன்குடைய ராயினும் சான்றோர்க்கு", "line2": "இனநலம் ஏமாப் புடைத்து.", "translation": "Men of wisdom, though good in mind  In friends of worth a new strength find"}, {"number": 459, "line1": "மனநலத்தின் ஆகும் மறுமைமற் றஃதும்", "line2": "இனநலத்தின் ஏமாப் புடைத்து.", "translation": "Good mind decides the future bliss  Good company gains strength to this"}, {"number": 460, "line1": "நல்லினத்தி னூங்குந் துணையில்லை தீயினத்தின்", "line2": "அல்லற் படுப்பதூஉம் இல்.", "translation": "No help good company exeeds;  The bad to untold anguish leads"}, {"number": 461, "line1": "அழிவதூஉம் ஆவதூஉம் ஆகி வழிபயக்கும்", "line2": "ஊதியமும் சூழ்ந்து செயல்.", "translation": "Weigh well output the loss and gain  And proper action ascertain"}, {"number": 462, "line1": "தெரிந்த இனத்தொடு தேர்ந்தெண்ணிச் செய்வார்க்கு", "line2": "அரும்பொருள் யாதொன்றும் இல்", "translation": "Nothing is hard for him who acts  With worthy counsels weighing facts"}, {"number": 463, "line1": "ஆக்கம் கருதி முதலிழக்கும் செய்வினை", "line2": "ஊக்கார் அறிவுடை யார்.", "translation": "The wise risk not their capital  In doubtful gains and lose their all"}, {"number": 464, "line1": "தெளிவி லதனைத் தொடங்கார் இளிவென்னும்", "line2": "ஏதப்பாடு அஞ்சு பவர்.", "translation": "They who scornful reproach fear  Commence no work not made clear"}, {"number": 465, "line1": "வகையறச் சூழா தெழுதல் பகைவரைப்", "line2": "பாத்திப் படுப்பதோ ராறு.", "translation": "Who marches without plans and ways  His field is sure to foster foes"}, {"number": 466, "line1": "செய்தக்க அல்ல செயக்கெடும் செய்தக்க", "line2": "செய்யாமை யானுங் கெடும்.", "translation": "Doing unfit action ruins Failing fit-act also ruins"}, {"number": 467, "line1": "எண்ணித் துணிக கருமம் துணிந்தபின்", "line2": "எண்ணுவம் என்பது இழுக்கு.", "translation": "Think and dare a proper deed  Dare and think is bad in need"}, {"number": 468, "line1": "ஆற்றின் வருந்தா வருத்தம் பலர்நின்று", "line2": "போற்றினும் பொத்துப் படும்.", "translation": "Toil without a plan ahead Is doomed to fall though supported"}, {"number": 469, "line1": "நன்றாற்ற லுள்ளுந் தவுறுண்டு அவரவர்", "line2": "பண்பறிந் தாற்றாக் கடை.", "translation": "Attune the deeds to habitude Or ev'n good leads to evil feud"}, {"number": 470, "line1": "எள்ளாத எண்ணிச் செயல்வேண்டும் தம்மோடு", "line2": "கொள்ளாத கொள்ளாது உலகு.", "translation": "Do deeds above reproachfulness The world refutes uncomely mess"}, {"number": 471, "line1": "வினைவலியும் தன்வலியும் மாற்றான் வலியும்", "line2": "துணைவலியும் தூக்கிச் செயல்.", "translation": "Judge act and might and foeman's strength The allies' strength and go at length"}, {"number": 472, "line1": "ஒல்வ தறிவது அறிந்ததன் கண்தங்கிச்", "line2": "செல்வார்க்குச் செல்லாதது இல்.", "translation": "Nothing hampers the firm who know What they can and how to go"}, {"number": 473, "line1": "உடைத்தம் வலியறியார் ஊக்கத்தின் ஊக்கி", "line2": "இடைக்கண் முரிந்தார் பலர்.", "translation": "Many know not their meagre might Their pride breaks up in boastful fight"}, {"number": 474, "line1": "அமைந்தாங் கொழுகான் அளவறியான் தன்னை", "line2": "வியந்தான் விரைந்து கெடும்.", "translation": "Who adapts not, outsteps measure And brags himself-his fall is sure"}, {"number": 475, "line1": "பீலிபெய் சாகாடும் அச்சிறும் அப்பண்டஞ்", "line2": "சால மிகுத்துப் பெயின்.", "translation": "Even the gentle peacock's plume Cart's axle breaks by gross volume"}, {"number": 476, "line1": "நுனிக்கொம்பர் ஏறினார் அஃதிறந் தூக்கின்", "line2": "உயிர்க்கிறுதி ஆகி விடும்.", "translation": "Beyond the branches' tip who skips Ends the life as his body rips"}, {"number": 477, "line1": "ஆற்றின் அறவறிந்து ஈக அதுபொருள்", "line2": "போற்றி வழங்கு நெறி.", "translation": "Know the limit; grant with measure This way give and guard your treasure"}, {"number": 478, "line1": "ஆகாறு அளவிட்டி தாயினுங் கேடில்லை", "line2": "போகாறு அகலாக் கடை.", "translation": "The outflow must not be excess No matter how small income is"}, {"number": 479, "line1": "அளவறிந்து வாழாதான் வாழ்க்கை உளபோல", "line2": "இல்லாகித் தோன்றாக் கெடும்.", "translation": "Who does not know to live in bounds His life seems rich but thins and ends"}, {"number": 480, "line1": "உளவரை தூக்காத ஒப்புர வாண்மை", "line2": "வளவரை வல்லைக் கெடும்.", "translation": "Wealth amassed quickly vanishes Sans level if one lavishes"}, {"number": 481, "line1": "பகல்வெல்லும் கூகையைக் காக்கை இகல்வெல்லும்", "line2": "வேந்தர்க்கு வேண்டும் பொழுது.", "translation": "By day the crow defeats the owl Kings need right time their foes to quell"}, {"number": 482, "line1": "பருவத்தோடு ஒட்ட ஒழுகல் திருவினைத்", "line2": "தீராமை ஆர்க்குங் கயிறு.", "translation": "Well-ordered seasoned act is cord That fortune binds in bon accord"}, {"number": 483, "line1": "அருவினை யென்ப உளவோ கருவியான்", "line2": "காலம் அற஧ந்து செயின்.", "translation": "What is hard for him who acts With proper means and time and tacts?"}, {"number": 484, "line1": "ஞாலம் கருதினுங் கைகூடுங் காலம்", "line2": "கருதி இடத்தாற் செயின்.", "translation": "Choose proper time and act and place Even the world you win with ease"}, {"number": 485, "line1": "காலம் கருதி இருப்பர் கலங்காது", "line2": "ஞாலம் கருது பவர்.", "translation": "Who want to win the world sublime Wait unruffled biding their time"}, {"number": 486, "line1": "ஊக்க முடையான் ஒடுக்கம் பொருதகர்", "line2": "தாக்கற்குப் பேருந் தகைத்து.", "translation": "By self-restraint stalwarts keep fit Like rams retreating but to butt"}, {"number": 487, "line1": "பொள்ளென ஆங்கே புறம்வேரார் காலம்பார்த்து", "line2": "உள்வேர்ப்பர் ஒள்ளி யவர்.", "translation": "The wise jut not their vital fire They watch their time with hidden ire"}, {"number": 488, "line1": "செறுநரைக் காணின் சுமக்க இறுவரை", "line2": "காணின் கிழக்காம் தலை.", "translation": "Bear with hostiles when you meet them Fell down their head in fateful time"}, {"number": 489, "line1": "எய்தற் கரியது இயைந்தக்கால் அந்நிலையே", "line2": "செய்தற் கரிய செயல்.", "translation": "When comes the season ripe and rare Dare and do hard things then and there"}, {"number": 490, "line1": "கொக்கொக்க கூம்பும் பருவத்து மற்றதன்", "line2": "குத்தொக்க சீர்த்த இடத்து.", "translation": "In waiting time feign peace like stork In fighting time strike like its peck"}, {"number": 491, "line1": "தொடங்கற்க எவ்வினையும் எள்ளற்க முற்றும்", "line2": "இடங்கண்ட பின்அல் லது.", "translation": "No action take, no foe despise Until you have surveyed the place"}, {"number": 492, "line1": "முரண்சேர்ந்த மொய்ம்பி னவர்க்கும் அரண்சேர்ந்தாம்", "line2": "ஆக்கம் பலவுந் தரும்.", "translation": "Many are gains of fortresses Ev'n to kings of power and prowess"}, {"number": 493, "line1": "ஆற்றாரும் ஆற்றி அடுப இடனறிந்து", "line2": "போற்றார்கண் போற்றிச் செயின்.", "translation": "Weaklings too withstand foe's offence In proper fields of strong defence"}, {"number": 494, "line1": "எண்ணியார் எண்ணம் இழப்பர் இடனறிந்து", "line2": "துன்னியார் துன்னிச் செயின்.", "translation": "If fighters fight in vantage field The plans of foes shall be baffled"}, {"number": 495, "line1": "நெடும்புனலுள் வெல்லும் முதலை அடும்புனலின்", "line2": "நீங்கின் அதனைப் பிற.", "translation": "In water crocodile prevails In land before others it fails"}, {"number": 496, "line1": "கடலோடா கால்வல் நெடுந்தேர் கடலோடும்", "line2": "நாவாயும் ஓடா நிலத்து.", "translation": "Sea-going ship goes not on shore Nor on sea the strong-wheeled car"}, {"number": 497, "line1": "அஞ்சாமை அல்லால் துணைவேண்டா எஞ்சாமை", "line2": "எண்ணி இடத்தால் செயின்.", "translation": "No aid but daring dash they need When field is chosen right for deed"}, {"number": 498, "line1": "சிறுபடையான் செல்லிடம் சேரின் உறுபடையான்", "line2": "ஊக்கம் அழிந்து விடும்.", "translation": "Though force is small, if place is right One quells a foe of well-armed might"}, {"number": 499, "line1": "சிறைநலனும் சீரும் இலரெனினும் மாந்தர்", "line2": "உறைநிலத்தோடு ஒட்டல் அரிது.", "translation": "To face a foe at home is vain Though fort and status are not fine"}, {"number": 500, "line1": "காலாழ் களரில் நரியடும் கண்ணஞ்சா", "line2": "வேலாள் முகத்த களிறு.", "translation": "A fox can kill a war tusker Fearless with feet in deep quagmire"}, {"number": 501, "line1": "அறம்பொருள் இன்பம் உயிரச்சம் நான்கின்", "line2": "திறந்தெரிந்து தேறப் படும்.", "translation": "Pleasure, gold, fear of life Virtue- Test by these four and trust the true"}, {"number": 502, "line1": "குடிப்பிறந்து குற்றத்தின் நீங்கி வடுப்பரியும்", "line2": "நாணுடையான் சுட்டே தெளிவு.", "translation": "Spotless name of noble birth Shamed of stain-that choice is worth"}, {"number": 503, "line1": "அரியகற்று ஆசற்றார் கண்ணும் தெரியுங்கால்", "line2": "இன்மை அரிதே வெளிறு.", "translation": "Though deep scholars of stainless sense Rare is freedom from ignorance"}, {"number": 504, "line1": "குணம்நாடிக் குற்றமும் நாடி அவற்றுள்", "line2": "மிகைநாடி மிக்க கொளல்.", "translation": "Good and evil in man weigh well Judge him by virtues which prevail"}, {"number": 505, "line1": "பெருமைக்கும் ஏனைச் சிறுமைக்கும் தத்தம்", "line2": "கருமமே கட்டளைக் கல்.", "translation": "By the touchstone of deeds is seen If any one is great or mean"}, {"number": 506, "line1": "அற்றாரைத் தேறுதல் ஓம்புக மற்றவர்", "line2": "பற்றிலர் நாணார் பழி.", "translation": "Choose not those men without kinsmen Without affine or shame of sin"}, {"number": 507, "line1": "காதன்மை கந்தா அறிவறியார்த் தேறுதல்", "line2": "பேதைமை எல்லாந் தரும்.", "translation": "On favour leaning fools you choose; Folly in all its forms ensues"}, {"number": 508, "line1": "தேரான் பிறனைத் தெளிந்தான் வழிமுறை", "line2": "தீரா இடும்பை தரும்.", "translation": "To trust an untried stranger brings Endless troubles on all our kins"}, {"number": 509, "line1": "தேறற்க யாரையும் தேராது தேர்ந்தபின்", "line2": "தேறுக தேறும் பொருள்.", "translation": "Trust not without testing and then Find proper work for trusted men"}, {"number": 510, "line1": "தேரான் தெளிவும் தெளிந்தான்கண் ஐயுறவும்", "line2": "தீரா இடும்பை தரும்.", "translation": "Trust without test; The trusted doubt; Both entail troubles in and out"}, {"number": 511, "line1": "நன்மையும் தீமையும் நாடி நலம்புரிந்த", "line2": "தன்மையான் ஆளப் படும்.", "translation": "Employ the wise who will discern The good and bad and do good turn"}, {"number": 512, "line1": "வாரி பெருக்கி வளம்படுத்து உற்றவை", "line2": "ஆராய்வான் செய்க வினை.", "translation": "Let him act who resource swells; Fosters wealth and prevents ills"}, {"number": 513, "line1": "அன்பறிவு தேற்றம் அவாவின்மை இந்நான்கும்", "line2": "நன்குடையான் கட்டே தெளிவு.", "translation": "Trust him in whom these four you see: Love, wit, non-craving, clarity"}, {"number": 514, "line1": "எனைவகையான் தேறியக் கண்ணும் வினைவகையான்", "line2": "வேறாகும் மாந்தர் பலர்.", "translation": "Though tried and found fit, yet we see Many differ before duty"}, {"number": 515, "line1": "அறிந்தாற்றிச் செய்கிற்பாற்கு அல்லால் வினைதான்", "line2": "சிறந்தானென்று ஏவற்பாற் றன்று.", "translation": "Wise able men with power invest Not by fondness but by hard test"}, {"number": 516, "line1": "செய்வானை நாடி வினைநாடிக் காலத்தோடு", "line2": "எய்த உணர்ந்து செயல்.", "translation": "Discern the agent and the deed And just in proper time proceed"}, {"number": 517, "line1": "இதனை இதனால் இவன்முடிக்கும் என்றாய்ந்து", "line2": "அதனை அவன்கண் விடல்.", "translation": "This work, by this, this man can do Like this entrust the duty due"}, {"number": 518, "line1": "வினைக்குரிமை நாடிய பின்றை அவனை", "line2": "அதற்குரிய னாகச் செயல்.", "translation": "His fitness for the duty scan Leave him to do the best he can"}, {"number": 519, "line1": "வினைக்கண் வினையுடையான் கேண்மைவே றாக", "line2": "நினைப்பானை நீங்கும் திரு.", "translation": "Who do duty for duty's sake Doubt them; and fortune departs quick"}, {"number": 520, "line1": "நாடோறும் நாடுக மன்னன் வினைசெய்வான்", "line2": "கோடாமை கோடா துலகு.", "translation": "Worker straight the world is straight The king must look to this aright"}, {"number": 521, "line1": "பற்றற்ற கண்ணும் பழைமைபா ராட்டுதல்", "line2": "சுற்றத்தார் கண்ணே உள.", "translation": "Let fortunes go; yet kinsmen know The old accustomed love to show"}, {"number": 522, "line1": "விருப்பறாச் சுற்றம் இயையின் அருப்பறா", "line2": "ஆக்கம் பலவும் தரும்.", "translation": "The gift of loving Kins bestows  Fadeless fortune's fresh flowers"}, {"number": 523, "line1": "அளவளா வில்லாதான் வாழ்க்கை குளவளாக்", "line2": "கோடின்றி நீர்நிறைந் தற்று.", "translation": "A kinless wealth is like a tank Which overflows without a bank"}, {"number": 524, "line1": "சுற்றத்தால் சுற்றப் படஒழுகல் செல்வந்தான்", "line2": "பெற்றத்தால் பெற்ற பயன்.", "translation": "The fruit of growing wealth is gained When kith and kin are happy found"}, {"number": 525, "line1": "கொடுத்தலும் இன்சொலும் ஆற்றின் அடுக்கிய", "line2": "சுற்றத்தால் சுற்றப் படும்.", "translation": "Loving words and liberal hand Encircle kith and kin around"}, {"number": 526, "line1": "பெருங்கொடையான் பேணான் வெகுளி அவனின்", "line2": "மருங்குடையார் மாநிலத்து இல்.", "translation": "Large giver and wrathless man Commands on earth countless kinsmen"}, {"number": 527, "line1": "காக்கை கரவா கரைந்துண்ணும் ஆக்கமும்", "line2": "அன்னநீ ரார்க்கே உள.", "translation": "The crows hide not; thy call and eat Welfare abides a man of heart"}, {"number": 528, "line1": "பொதுநோக்கான் வேந்தன் வரிசையா நோக்கின்", "line2": "அதுநோக்கி வாழ்வார் பலர்.", "translation": "From public gaze when kings perceive Each one's merits so many thrive"}, {"number": 529, "line1": "தமராகிக் தற்றுறந்தார் சுற்றம் அமராமைக்", "line2": "காரணம் இன்றி வரும்.", "translation": "Forsaken friends will come and stay When cause for discord goes away"}, {"number": 530, "line1": "உழைப்பிரிந்து காரணத்தின் வந்தானை வேந்தன்", "line2": "இழைத் திருந்து எண்ணிக் கொளல்.", "translation": "Who leaves and returns with motive The king should test him and receive"}, {"number": 531, "line1": "இறந்த வெகுளியின் தீதே சிறந்த", "line2": "உவகை மகிழ்ச்சியிற் சோர்வு.", "translation": "Worse than wrath in excess is Forgetfulness in joy-excess"}, {"number": 532, "line1": "பொச்சாப்புக் கொல்லும் புகழை அறிவினை", "line2": "நிச்ச நிரப்புக் கொன் றாங்கு.", "translation": "Negligence kills renown just as Ceaseless want wisdom destroys"}, {"number": 533, "line1": "பொச்சாப்பார்க் கில்லை புகழ்மை அதுஉலகத்து", "line2": "எப்பால்நூ லோர்க்கும் துணிவு.", "translation": "Forgetful nature fails of fame All schools of thinkers say the same"}, {"number": 534, "line1": "அச்ச முடையார்க்கு அரணில்லை ஆங்கில்லை", "line2": "பொச்சாப் புடையார்க்கு நன்கு.", "translation": "The fearful find no fortress here The forgetful find good never"}, {"number": 535, "line1": "முன்னுறக் காவாது இழுக்கியான் தன்பிழை", "line2": "பின்னூறு இரங்கி விடும்.", "translation": "Failing foresight the guardless man Shall rue his folly later on"}, {"number": 536, "line1": "இழுக்காமை யார்மாட்டும் என்றும் வழுக்காமை", "line2": "வாயின் அதுவொப்பது இல்.", "translation": "Forget none; watch with wakeful care Miss none; the gain is sans compare"}, {"number": 537, "line1": "அரியஎன்று ஆகாத இல்லைபொச் சாவாக்", "line2": "கருவியால் போற்றிச் செயின்.", "translation": "With cautious care pursue a thing Impossible there is nothing"}, {"number": 538, "line1": "புகழ்ந்தவை போற்றிச் செயல்வேண்டும் செய்யாது", "line2": "இகழ்ந்தார்க்கு எழுமையும் இல்.", "translation": "Do what the wise commend as worth If not, for seven births no mirth"}, {"number": 539, "line1": "இகழ்ச்சியின் கெட்டாரை உள்ளுக தாந்தம்", "line2": "மகிழ்ச்சியின் மைந்துறும் போழ்து.", "translation": "When joy deludes, their fate recall Whom negligence has made to fall"}, {"number": 540, "line1": "உள்ளியது எய்தல் எளிதுமன் மற்றுந்தான்", "line2": "உள்ளியது உள்ளப் பெறின்.", "translation": "Easy it is a thing to get When the mind on it is set"}, {"number": 541, "line1": "ஓர்ந்துகண் ணோடாது இறைபுரிந்து யார்மாட்டும்", "line2": "தேர்ந்துசெய் வஃதே முறை.", "translation": "Test and attest impartially Consult and act the laws justly"}, {"number": 542, "line1": "வானோக்கி வாழும் உலகெல்லாம் மன்னவன்", "line2": "கோல் நோக்கி வாழுங் குடி.", "translation": "The earth looks up to sky and thrives And mankind to king's rod of justice"}, {"number": 543, "line1": "அந்தணர் நூற்கும் அறத்திற்கும் ஆதியாய்", "line2": "நின்றது மன்னவன் கோல்.", "translation": "The Sage's scripture and virtue spring From the sceptre of a stately king"}, {"number": 544, "line1": "குடிதழீஇக் கோலோச்சும் மாநில மன்னன்", "line2": "அடிதழீஇ நிற்கும் உலகு.", "translation": "The world clings to the ruler's feet Whose sceptre clasps the people's heart"}, {"number": 545, "line1": "இயல்புளிக் கோலோச்சும் மன்னவன் நாட்ட", "line2": "பெயலும் விளையுளும் தொக்கு.", "translation": "Full rains and yields enrich the land Which is ruled by a righteous hand"}, {"number": 546, "line1": "வேலன்று வென்றி தருவது மன்னவன்", "line2": "கோலதூஉங் கோடா தெனின்.", "translation": "Not the spear but the sceptre straight That brings success to monarch's might"}, {"number": 547, "line1": "இறைகாக்கும் வையகம் எல்லாம் அவனை", "line2": "முறைகாக்கும் முட்டாச் செயின்.", "translation": "The king protects the entire earth And justice protects his royal worth"}, {"number": 548, "line1": "எண்பதத்தான் ஓரா முறைசெய்யா மன்னவன்", "line2": "தண்பதத்தான் தானே கெடும்.", "translation": "Hard of access, the unjust king He shall himself his ruin bring"}, {"number": 549, "line1": "குடிபுறங் காத்தோம்பிக் குற்றம் கடிதல்", "line2": "வடுவன்று வேந்தன் தொழில்.", "translation": "Save his subjects and chide the wrong Is flawless duty of a king"}, {"number": 550, "line1": "கொலையிற் கொடியாரை வேந்தொறுத்தல் பைங்கூழ்", "line2": "களைகட் டதனொடு நேர்.", "translation": "Killing killers, the king, behold Weeds removes from cropful field"}, {"number": 551, "line1": "கொலைமேற்கொண் டாரிற் கொடிதே அலைமேற்கொண்டு", "line2": "அல்லவை செய்தொழுகும் வேந்து.", "translation": "The unjust tyrant oppressor  Is worse than cruel murderer"}, {"number": 552, "line1": "வேலொடு நின்றான் இடுவென் றதுபோலும்", "line2": "கோலொடு நின்றான் இரவு.", "translation": "Sceptered tyrant exacting gold Is \\\"give\\\" of lanced robber bold"}, {"number": 553, "line1": "நாடொறும் நாடி முறைசெய்யா மன்னவன்", "line2": "நாடொறும் நாடு கெடும்.", "translation": "Spy wrongs daily and do justice Or day by day the realm decays"}, {"number": 554, "line1": "கூழுங் குடியும் ஒருங்கிழக்கும் கோல்கோடிச்", "line2": "சூழாது செய்யும் அரசு.", "translation": "The king shall wealth and subjects lose If his sceptre he dares abuse"}, {"number": 555, "line1": "அல்லற்பட்டு ஆற்றாது அழுதகண் ணீரன்றே", "line2": "செல்வத்தைத் தேய்க்கும் படை", "translation": "Groaning tears caused by tyrant's sway  File the royal wealth away"}, {"number": 556, "line1": "மன்னர்க்கு மன்னுதல் செங்கோன்மை அஃதின்றேல்", "line2": "மன்னாவாம் மன்னர்க் கொளி.", "translation": "Glory endures by sceptre right Without it wanes the royal light"}, {"number": 557, "line1": "துளியின்மை ஞாலத்திற்கு எற்றற்றே வேந்தன்", "line2": "அளியின்மை வாழும் உயிர்க்கு.", "translation": "Dry like the earth without rainfall Is graceless king to creatures all"}, {"number": 558, "line1": "இன்மையின் இன்னாது உடைமை முறைசெய்யா", "line2": "மன்னவன் கோற்கீழ்ப் படின்.", "translation": "To have is worse than having not If ruler is unjust despot"}, {"number": 559, "line1": "முறைகோடி மன்னவன் செய்யின் உறைகோடி", "line2": "ஒல்லாது வானம் பெயல்.", "translation": "The sky withdraws season's shower If the king misuses his power"}, {"number": 560, "line1": "ஆபயன் குன்றும் அறுதொழிலோர் நூல்மறப்பர்", "line2": "காவலன் காவான் எனின்.", "translation": "The *six-functioned forget their lore Cows give less if kings guard no more * the six functions are: learning, teaching,  giving,  getting, sacrificing, kindling sacrifice These are duties of Vedic savants"}, {"number": 561, "line1": "தக்காங்கு நாடித் தலைச்செல்லா வண்ணத்தால்", "line2": "ஒத்தாங்கு ஒறுப்பது வேந்து.", "translation": "A king enquires and gives sentence  Just to prevent future offence"}, {"number": 562, "line1": "கடிதோச்சி மெல்ல எறிக நெடிதாக்கம்", "line2": "நீங்காமை வேண்டு பவர்.", "translation": "Wield fast the rod but gently lay This strict mildness prolongs the sway"}, {"number": 563, "line1": "வெருவந்த செய்தொழுகும் வெங்கோல னாயின்", "line2": "ஒருவந்தம் ஒல்லைக் கெடும்.", "translation": "His cruel rod of dreadful deed Brings king's ruin quick indeed"}, {"number": 564, "line1": "இறைகடியன் என்றுரைக்கும் இன்னாச்சொல் வேந்தன்", "line2": "உறைகடுகி ஒல்லைக் கெடும்.", "translation": "As men the king a tyrant call  His days dwindled, hasten his fall"}, {"number": 565, "line1": "அருஞ்செவ்வி இன்னா முகத்தான் பெருஞ்செல்வம்", "line2": "பேஎய்கண் டன்னது உடைத்து.", "translation": "Whose sight is scarce, whose face is foul His wealth seems watched by a ghoul"}, {"number": 566, "line1": "கடுஞ்சொல்லன் கண்ணிலன் ஆயின் நெடுஞ்செல்வம்", "line2": "நீடின்றி ஆங்கே கெடும்.", "translation": "Whose word is harsh, whose sight is rude His wealth and power quickly fade"}, {"number": 567, "line1": "கடுமொழியும் கையிகந்த தண்டமும் வேந்தன்", "line2": "அடுமுரண் தேய்க்கும் அரம்.", "translation": "Reproofs rough and punishments rude Like files conquering power corrode"}, {"number": 568, "line1": "இனத்தாற்றி எண்ணாத வேந்தன் சினத்தாற்றிச்", "line2": "சீறிற் சிறுகும் திரு.", "translation": "The king who would not take counsels Rages with wrath-his fortune fails"}, {"number": 569, "line1": "செருவந்த போழ்திற் சிறைசெய்யா வேந்தன்", "line2": "வெருவந்து வெய்து கெடும்.", "translation": "The king who builds not fort betimes Fears his foes in wars and dies"}, {"number": 570, "line1": "கல்லார்ப் பிணிக்கும் கடுங்கோல் அதுவல்லது", "line2": "இல்லை நிலக்குப் பொறை.", "translation": "The crushing burden borne by earth Is tyrants bound to fools uncouth"}, {"number": 571, "line1": "கண்ணோட்டம் என்னும் கழிபெருங் காரிகை", "line2": "உண்மையான் உண்டிவ் வுலகு.", "translation": "Living in the world implies The bounteous dame of benign eyes"}, {"number": 572, "line1": "கண்ணோட்டத் துள்ளது உலகியல் அஃதிலார்", "line2": "உண்மை நிலக்குப் பொறை.", "translation": "World lives by looks of lovely worth Who lack them are burdens of earth"}, {"number": 573, "line1": "பண்என்னாம் பாடற்கு இயைபின்றேல் கண்என்னாம்", "line2": "கண்ணோட்டம் இல்லாத கண்.", "translation": "Of tuneless song what is the use? Without gracious looks what are eyes?"}, {"number": 574, "line1": "உளபோல் முகத்தெவன் செய்யும் அளவினால்", "line2": "கண்ணோட்டம் இல்லாத கண்.", "translation": "Except that they are on the face  What for are eyes sans measured grace"}, {"number": 575, "line1": "கண்ணிற்கு அணிகலம் கண்ணோட்டம் அஃதின்றேல்", "line2": "புண்ணென்று உணரப் படும்", "translation": "Kind looks are jewels for eyes to wear Without them they are felt as sore"}, {"number": 576, "line1": "மண்ணோ டியைந்த மரத்தனையர் கண்ணோ", "line2": "டியைந்துகண் ணோடா தவர்.", "translation": "Like trees on inert earth they grow Who don't eye to eye kindness show"}, {"number": 577, "line1": "கண்ணோட்டம் இல்லவர் கண்ணிலர் கண்ணுடையார்", "line2": "கண்ணோட்டம் இன்மையும் இல்.", "translation": "Ungracious men lack real eyes Men of real eyes show benign grace"}, {"number": 578, "line1": "கருமம் சிதையாமல் கண்ணோட வல்லார்க்கு", "line2": "உரிமை உடைத்திவ் வுலகு.", "translation": "Who gracious are but dutiful Have right for this earth beautiful"}, {"number": 579, "line1": "ஒறுத்தாற்றும் பண்பினார் கண்ணும்கண் ணோடிப்", "line2": "பொறுத்தாற்றும் பண்பே தலை.", "translation": "To be benign and bear with foes Who vex us is true virtue's phase"}, {"number": 580, "line1": "பெயக்கண்டும் நஞ்சுண் டமைவர் நயத்தக்க", "line2": "நாகரிகம் வேண்டு பவர்.", "translation": "Men of graceful courtesy Take hemlock and look cheerfully"}, {"number": 581, "line1": "ஒற்றும் உரைசான்ற நூலும் இவையிரண்டும்", "line2": "தெற்றென்க மன்னவன் கண்.", "translation": "A king should treat these two as eyes  The code of laws and careful spies"}, {"number": 582, "line1": "எல்லார்க்கும் எல்லாம் நிகழ்பவை எஞ்ஞான்றும்", "line2": "வல்லறிதல் வேந்தன் தொழில்.", "translation": "All that happens, always, to all  The king should know in full detail"}, {"number": 583, "line1": "ஒற்றினான் ஒற்றிப் பொருள்தெரியா மன்னவன்", "line2": "கொற்றங் கொளக்கிடந்தது இல்.", "translation": "Conquests are not for the monarch Who cares not for the Spy's remark"}, {"number": 584, "line1": "வினைசெய்வார் தம்சுற்றம் வேண்டாதார் என்றாங்கு", "line2": "அனைவரையும் ஆராய்வது ஒற்று.", "translation": "His officers, kinsmen and foes  Who watch keenly are worthy spies"}, {"number": 585, "line1": "கடாஅ உருவொடு கண்ணஞ்சாது யாண்டும்", "line2": "உகாஅமை வல்லதே ஒற்று.", "translation": "Fearless gaze, suspectless guise  Guarding secrets mark the spies"}, {"number": 586, "line1": "துறந்தார் படிவத்த ராகி இறந்தாராய்ந்து", "line2": "என்செயினும் சோர்விலது ஒற்று.", "translation": "Guised as monks they gather secrets They betray them not under threats"}, {"number": 587, "line1": "மறைந்தவை கேட்கவற் றாகி அறிந்தவை", "line2": "ஐயப்பாடு இல்லதே ஒற்று.", "translation": "A spy draws out other's secrets Beyond a doubt he clears his facts"}, {"number": 588, "line1": "ஒற்றொற்றித் தந்த பொருளையும் மற்றுமோர்", "line2": "ஒற்றினால் ஒற்றிக் கொளல்.", "translation": "The reports given by one spy By another spy verify"}, {"number": 589, "line1": "ஒற்றெற் றுணராமை ஆள்க உடன்மூவர்", "line2": "சொற்றொக்க தேறப் படும்.", "translation": "Engage the spies alone, apart When three agree confirm report"}, {"number": 590, "line1": "சிறப்பறிய ஒற்றின்கண் செய்யற்க செய்யின்", "line2": "புறப்படுத்தான் ஆகும் மறை.", "translation": "Give not the spy open reward It would divulge the secret heard!"}, {"number": 591, "line1": "உடையர் எனப்படுவது ஊக்கம் அஃதில்லார்", "line2": "உடையது உடையரோ மற்று.", "translation": "To own is to own energy All others own but lethargy"}, {"number": 592, "line1": "உள்ளம் உடைமை உடைமை பொருளுடைமை", "line2": "நில்லாது நீங்கி விடும்.", "translation": "Psychic heart is wealth indeed Worldly wealth departs in speed"}, {"number": 593, "line1": "ஆக்கம் இழந்தேமென்று அல்லாவார் ஊக்கம்", "line2": "ஒருவந்தம் கைத்துடை யார்.", "translation": "The strong in will do not complain  The loss of worldly wealth and gain"}, {"number": 594, "line1": "ஆக்கம் அதர்வினாய்ச் செல்லும் அசைவிலா", "line2": "ஊக்க முடையா னுழை.", "translation": "Fortune enquires, enters with boom Where tireless strivers have their home"}, {"number": 595, "line1": "வெள்ளத் தனைய மலர்நீட்டம் மாந்தர்தம்", "line2": "உள்ளத் தனையது உயர்வு.", "translation": "Water depth is lotus height  Mental strength is men's merit"}, {"number": 596, "line1": "உள்ளுவ தெல்லாம் உயர்வுள்ளல் மற்றது", "line2": "தள்ளினுந் தள்ளாமை நீர்த்து.", "translation": "Let thoughts be always great and grand  Though they fail their virtues stand"}, {"number": 597, "line1": "சிதைவிடத்து ஒல்கார் உரவோர் புதையம்பிற்", "line2": "பட்டுப்பா டூன்றுங் களிறு.", "translation": "Elephants are firm when arrows hit Great minds keep fit ev'n in defeat"}, {"number": 598, "line1": "உள்ளம் இலாதவர் எய்தார் உலகத்து", "line2": "வள்ளியம் என்னுஞ் செருக்கு.", "translation": "Heartless persons cannot boast \\\"We are liberal to our best\\\""}, {"number": 599, "line1": "பரியது கூர்ங்கோட்டது ஆயினும் யானை", "line2": "஦வ்ருஉம் புலிதாக் குறின்.", "translation": "Huge elephant sharp in tusk quails  When tiger, less in form, assails"}, {"number": 600, "line1": "உரமொருவற்கு உள்ள வெறுக்கைஅஃ தில்லார்", "line2": "மரம்மக்க ளாதலே வேறு.", "translation": "Mental courage is true manhood Lacking that man is like a wood"}, {"number": 601, "line1": "குடியென்னும் குன்றா விளக்கம் மடியென்னும்", "line2": "மாசூர மாய்ந்து கெடும்.", "translation": "Quenchless lamp of ancestry goes When foul idleness encloses"}, {"number": 602, "line1": "மடியை மடியா ஒழுகல் குடியைக்", "line2": "குடியாக வேண்டு பவர்.", "translation": "To make your home an ideal home Loath sloth as sloth; refuse it room"}, {"number": 603, "line1": "மடிமடிக் கொண்டொழுகும் பேதை பிறந்த", "line2": "குடிமடியும் தன்னினும் முந்து.", "translation": "The fool who fosters sluggishness Before he dies ruins his house"}, {"number": 604, "line1": "குடிமடிந்து குற்றம் பெருகும் மடிமடிந்து", "line2": "மாண்ட உஞற்றி லவர்க்கு.", "translation": "Who strive not high, sunk deep in sloth Ruin their house by evil growth"}, {"number": 605, "line1": "நெடுநீர் மறவி மடிதுயில் நான்கும்", "line2": "கெடுநீரார் காமக் கலன்.", "translation": "To lag, forget, idle and doze These four are pleasure boats of loss"}, {"number": 606, "line1": "படியுடையார் பற்றமைந்தக் கண்ணும் மடியுடையார்", "line2": "மாண்பயன் எய்தல் அரிது.", "translation": "With all the wealth of lords of earth The slothful gain nothing of worth"}, {"number": 607, "line1": "இடிபுரிந்து எள்ளுஞ்சொல் கேட்பர் மடிபுரிந்து", "line2": "மாண்ட உஞற்றி லவர்.", "translation": "The slothful lacking noble deeds Subject themselves to scornful words"}, {"number": 608, "line1": "மடிமை குடிமைக்கண் தங்கின்தன் ஒன்னார்க்கு", "line2": "அடிமை புகுத்தி விடும்.", "translation": "If sloth invades a noble house It will become a slave of foes"}, {"number": 609, "line1": "குடியாண்மை யுள்வந்த குற்றம் ஒருவன்", "line2": "மடியாண்மை மாற்றக் கெடும்.", "translation": "The blots on race and rule shall cease When one from sloth gets his release"}, {"number": 610, "line1": "மடியிலா மன்னவன் எய்தும் அடியளந்தான்", "line2": "தாஅய தெல்லாம் ஒருங்கு.", "translation": "The slothless king shall gain en masse *All regions trod by Lord apace * Hindu mythology holds that Lord Vishnu measured with his feet the three worlds"}, {"number": 611, "line1": "அருமை உடைத்தென்று அசாவாமை வேண்டும்", "line2": "பெருமை முயற்சி தரும்.", "translation": "Feel not frustrate saying This hard Who tries attains striving's reward"}, {"number": 612, "line1": "வினைக்கண் வினைகெடல் ஓம்பல் வினைக்குறை", "line2": "தீர்ந்தாரின் தீர்ந்தன்று உலகு.", "translation": "In doing work don't break and shirk The world will quit who quits his work"}, {"number": 613, "line1": "தாளாண்மை என்னும் தகைமைக்கண் தங்கிற்றே", "line2": "வேளாண்மை என்னுஞ் செருக்கு.", "translation": "On excellence of industry Depends magnanimous bounty"}, {"number": 614, "line1": "தாளாண்மை இல்லாதான் வேளாண்மை பேடிகை", "line2": "வாளாண்மை போலக் கெடும்.", "translation": "Bounty of man who never strives Like sword in eunuch's hand it fails"}, {"number": 615, "line1": "இன்பம் விழையான் வினைவிழைவான் தன்கேளிர்", "line2": "துன்பம் துடைத்தூன்றும் தூண்.", "translation": "Work who likes and not pleasure  Wipes grief of friends, pillar secure"}, {"number": 616, "line1": "முயற்சி திருவினை ஆக்கும் முயற்றின்மை", "line2": "இன்மை புகுத்தி விடும்.", "translation": "Industry adds prosperity Indolence brings but poverty"}, {"number": 617, "line1": "மடியுளாள் மாமுகடி என்ப மடியிலான்", "line2": "தாளுளான் தாமரையி னாள்.", "translation": "Illuck abides with sloth they say *Laxmi's gifts with labourers stay *Laxmi the Goddes of wealth and prosperity"}, {"number": 618, "line1": "பொறியின்மை யார்க்கும் பழியன்று அறிவறிந்து", "line2": "ஆள்வினை இன்மை பழி.", "translation": "Misfortune is disgrace to none The shame is nothing learnt or done"}, {"number": 619, "line1": "தெய்வத்தான் ஆகா தெனினும் முயற்சிதன்", "line2": "மெய்வருத்தக் கூலி தரும்.", "translation": "Though fate is against fulfilment Hard labour has ready payment"}, {"number": 620, "line1": "ஊழையும் உப்பக்கம் காண்பர் உலைவின்றித்", "line2": "தாழாது உஞற்று பவர்.", "translation": "Tireless Toiler's striving hand Shall leave even the fate behind"}, {"number": 621, "line1": "இடுக்கண் வருங்கால் நகுக அதனை", "line2": "அடுத்தூர்வது அஃதொப்ப தில்.", "translation": "Laugh away troubles; there is No other way to conquer woes"}, {"number": 622, "line1": "வெள்ளத் தனைய இடும்பை அறிவுடையான்", "line2": "உள்ளத்தின் உள்ளக் கெடும்.", "translation": "Deluging sorrows come to nought When wise men face them with firm thought"}, {"number": 623, "line1": "இடும்பைக்கு இடும்பை படுப்பர் இடும்பைக்கு", "line2": "இடும்பை படாஅ தவர்.", "translation": "Grief they face and put to grief Who grieve not grief by mind's relief"}, {"number": 624, "line1": "மடுத்தவா யெல்லாம் பகடன்னான் உற்ற", "line2": "இடுக்கண் இடர்ப்பாடு உடைத்து.", "translation": "Who pulls like bulls patiently on Causes grief to grieve anon"}, {"number": 625, "line1": "அடுக்கி வரினும் அழிவிலான் உற்ற", "line2": "இடுக்கண் இடுக்கட் படும்.", "translation": "Before the brave grief grieves and goes Who dare a host of pressing woes"}, {"number": 626, "line1": "அற்றேமென்று அல்லற் படுபவோ பெற்றேமென்று", "line2": "ஓம்புதல் தேற்றா தவர்.", "translation": "The wise that never gloat in gain Do not fret in fateful ruin"}, {"number": 627, "line1": "இலக்கம் உடம்பிடும்பைக் கென்று கலக்கத்தைக்", "line2": "கையாறாக் கொள்ளாதாம் மேல்.", "translation": "The wise worry no more of woes Knowing body's butt of sorrows"}, {"number": 628, "line1": "இன்பம் விழையான் இடும்பை இயல்பென்பான்", "line2": "துன்பம் உறுதல் இலன்.", "translation": "Who seek not joy, deem grief norm By sorrows do not come to harm"}, {"number": 629, "line1": "இன்பத்துள் இன்பம் விழையாதான் துன்பத்துள்", "line2": "துன்பம் உறுதல் இலன்.", "translation": "In joy to joy who is not bound In grief he grieves not dual round!"}, {"number": 630, "line1": "இன்னாமை இன்பம் எனக்கொளின் ஆகுந்தன்", "line2": "ஒன்னார் விழையுஞ் சிறப்பு.", "translation": "His glory is esteemed by foes Who sees weal in wanton woes!"}, {"number": 631, "line1": "கருவியும் காலமும் செய்கையும் செய்யும்", "line2": "அருவினையும் மாண்டது அமைச்சு.", "translation": "He is minister who chooses Right means, time, mode and rare ventures"}, {"number": 632, "line1": "வன்கண் குடிகாத்தல் கற்றறிதல் ஆள்வினையோடு", "line2": "ஐந்துடன் மாண்டது அமைச்சு.", "translation": "With these he guards people, -by his Knowledge, firmness and manliness"}, {"number": 633, "line1": "பிரித்தலும் பேணிக் கொளலும் பிரிந்தார்ப்", "line2": "பொருத்தலும் வல்ல தமைச்சு.", "translation": "A minister cherishes friends Divides foes and the parted blends"}, {"number": 634, "line1": "தெரிதலும் தேர்ந்து செயலும் ஒருதலையாச்", "line2": "சொல்லலும் வல்லது அமைச்சு.", "translation": "A minister must sift reflect Select and say surely one fact"}, {"number": 635, "line1": "அறனறிந்து ஆன்றமைந்த சொல்லான்எஞ் ஞான்றுந்", "line2": "திறனறிந்தான் தேர்ச்சித் துணை.", "translation": "Have him for help who virtue knows Right wisdom speaks, ever apt in acts"}, {"number": 636, "line1": "மதிநுட்பம் நூலோடு உடையார்க்கு அதிநுட்பம்", "line2": "யாவுள முன்நிற் பவை.", "translation": "Which subtler brain can stand before The keen in brain with learned love?"}, {"number": 637, "line1": "செயற்கை அறிந்தக் கடைத்தும் உலகத்து", "line2": "இயற்கை அறிந்து செயல்.", "translation": "Albeit you know to act from books Act after knowing world's outlooks"}, {"number": 638, "line1": "அறிகொன்று அறியான் எனினும் உறுதி", "line2": "உழையிருந்தான் கூறல் கடன்.", "translation": "The man in place must tell the facts Though the ignorant king refutes"}, {"number": 639, "line1": "பழுதெண்ணும் மந்திரியின் பக்கததுள் தெவ்வோர்", "line2": "எழுபது கோடி உறும்.", "translation": "Seventy crores of foes are better Than a minister with mind bitter"}, {"number": 640, "line1": "முறைப்படச் சூழ்ந்தும் முடிவிலவே செய்வர்", "line2": "திறப்பாடு இலாஅ தவர்.", "translation": "The unresolved, though well designed To fulfil an act they have no mind"}, {"number": 641, "line1": "நாநலம் என்னும் நலனுடைமை அந்நலம்", "line2": "யாநலத்து உள்ளதூஉம் அன்று.", "translation": "The goodness called goodness of speech Is goodness which nothing can reach"}, {"number": 642, "line1": "ஆக்கமுங் கேடும் அதனால் வருதலால்", "line2": "காத்தோம்பல் சொல்லின்கட் சோர்வு.", "translation": "Since gain or ruin speeches bring Guard against the slips of tongue"}, {"number": 643, "line1": "கேட்டார்ப் பிணிக்கும் தகையவாய்க் கேளாரும்", "line2": "வேட்ப மொழிவதாம் சொல்.", "translation": "A speech is speech that holds ears And attracts ev'n those that are averse"}, {"number": 644, "line1": "திறனறிந்து சொல்லுக சொல்லை அறனும்", "line2": "பொருளும் அதனினூஉங்கு இல்.", "translation": "Weigh thy words and speak; because  No wealth or virtue words surpass"}, {"number": 645, "line1": "சொல்லுக சொல்லைப் பிறிதோர்சொல் அச்சொல்லை", "line2": "வெல்லுஞ்சொல் இன்மை அறிந்து.", "translation": "Speak out thy world so that no word Can win it and say untoward"}, {"number": 646, "line1": "வேட்பத்தாஞ் சொல்லிப் பிறர்சொல் பயன்கோடல்", "line2": "மாட்சியின் மாசற்றார் கோள்.", "translation": "Spotless men speak what is sweet And grasp in others what is meet"}, {"number": 647, "line1": "சொலல்வல்லன் சோர்விலன் அஞ்சான் அவனை", "line2": "இகல்வெல்லல் யார்க்கும் அரிது.", "translation": "No foe defies the speaker clear Flawless, puissant, and free from fear"}, {"number": 648, "line1": "விரைந்து தொழில்கேட்கும் ஞாலம் நிரந்தினிது", "line2": "சொல்லுதல் வல்லார்ப் பெறின்.", "translation": "The world will quickly carry out The words of counsellors astute"}, {"number": 649, "line1": "பலசொல்லக் காமுறுவர் மன்றமா சற்ற", "line2": "சிலசொல்லல் தேற்றா தவர்.", "translation": "They overspeak who do not seek A few and flawless words to speak"}, {"number": 650, "line1": "இணருழ்த்தும் நாறா மலரனையர் கற்றது", "line2": "உணர விரித்துரையா தார்.", "translation": "Who can't express what they have learnt Are bunch of flowers not fragrant"}, {"number": 651, "line1": "துணைநலம் ஆக்கம் த்ருஉம் வினைநலம்", "line2": "வேண்டிய எல்லாந் தரும்.", "translation": "Friendship brings gain; but action pure Does every good thing we desire"}, {"number": 652, "line1": "என்றும் ஒருவுதல் வேண்டும் புகழொடு", "line2": "நன்றி பயவா வினை.", "translation": "Eschew always acts that do not  Bring good nor glory on their part"}, {"number": 653, "line1": "ஒஓதல் வேண்டும் ஒளிமாழ்கும் செய்வினை", "line2": "ஆஅதும் என்னு மவர்.", "translation": "Those in the world desire for fame Should shun the deed that dims their name"}, {"number": 654, "line1": "இடுக்கண் படினும் இளிவந்த செய்யார்", "line2": "நடுக்கற்ற காட்சி யவர்.", "translation": "Though perils press the faultless wise Shun deeds of mean, shameful device"}, {"number": 655, "line1": "எற்றென்று இரங்குவ செய்யற்க செய்வானேல்", "line2": "மற்றன்ன செய்யாமை நன்று.", "translation": "Do not wrong act and grieve, \\\"Alas\\\"  If done, do not repeat it twice"}, {"number": 656, "line1": "ஈன்றாள் பசிகாண்பான் ஆயினுஞ் செய்யற்க", "line2": "சான்றோர் பழிக்கும் வினை.", "translation": "Though she who begot thee hungers Shun acts denounced by ancient seers"}, {"number": 657, "line1": "பழிமலைந்து எய்திய ஆக்கத்தின் சான்றோர்", "line2": "கழிநல் குரவே தலை.", "translation": "Pinching poverty of the wise Is more than wealth hoarded by Vice"}, {"number": 658, "line1": "கடிந்த கடிந்தொரார் செய்தார்க்கு அவைதாம்", "line2": "முடிந்தாலும் பீழை தரும்.", "translation": "Those who dare a forbidden deed Suffer troubles though they succeed"}, {"number": 659, "line1": "அழக்கொண்ட எல்லாம் அழப்போம் இழப்பினும்", "line2": "பிற்பயக்கும் நற்பா லவை.", "translation": "Gains from weeping, weeping go Though lost, from good deeds blessings flow"}, {"number": 660, "line1": "சலத்தால் பொருள்செய்தே மார்த்தல் பசுமண்", "line2": "கலத்துள்நீர் பெய்திரீஇ யற்று.", "translation": "The wealth gathered in guilty ways Is water poured in wet clay vase"}, {"number": 661, "line1": "வினைத்திட்பம் என்பது ஒருவன் மனத்திட்பம்", "line2": "மற்றைய எல்லாம் பிற.", "translation": "A powerful mind does powerful act And all the rest are imperfect"}, {"number": 662, "line1": "ஊறொரால் உற்றபின் ஒல்காமை இவ்விரண்டின்", "line2": "ஆறென்பர் ஆய்ந்தவர் கோள்.", "translation": "Shun failing fuss; fail not purpose These two are maxims of the wise"}, {"number": 663, "line1": "கடைக்கொட்கச் செய்தக்க தாண்மை இடைக்கொட்கின்", "line2": "எற்றா விழுமந் தரும்.", "translation": "The strong achieve and then display Woe unto work displayed midway"}, {"number": 664, "line1": "சொல்லுதல் யார்க்கும் எளிய அரியவாம்", "line2": "சொல்லிய வண்ணம் செயல்.", "translation": "Easy it is to tell a fact But hard it is to know and act"}, {"number": 665, "line1": "வீறெய்தி மாண்டார் வினைத்திட்பம் வேந்தன்கண்", "line2": "ஊறெய்தி உள்ளப் படும்.", "translation": "Dynamic deeds of a doughty soul Shall win the praise of king and all"}, {"number": 666, "line1": "எண்ணிய எண்ணியாங்கு எய்துவர் எண்ணியார்", "line2": "திண்ணியர் ஆகப் பெறின்.", "translation": "The will-to-do achieves the deed When mind that wills is strong indeed"}, {"number": 667, "line1": "உருவுகண்டு எள்ளாமை வேண்டும் உருள்பெருந்தேர்க்கு", "line2": "அச்சாணி அன்னார் உடைத்து.", "translation": "Scorn not the form: for men there are Like linchpin of big rolling car"}, {"number": 668, "line1": "கலங்காது கண்ட வினைக்கண் துளங்காது", "line2": "தூக்கங் கடிந்து செயல்.", "translation": "Waver not; do wakefully  The deed resolved purposefully"}, {"number": 669, "line1": "துன்பம் உறவரினும் செய்க துணிவாற்றி", "line2": "இன்பம் பயக்கும் வினை.", "translation": "Do with firm will though pains beset  The deed that brings delight at last"}, {"number": 670, "line1": "எனைத்திட்பம் எய்தியக் கண்ணும் வினைத்திட்பம்", "line2": "வேண்டாரை வேண்டாது உலகு.", "translation": "The world merits no other strength But strength of will-to-do at length"}, {"number": 671, "line1": "சூழ்ச்சி முடிவு துணிவெய்தல் அத்துணிவு", "line2": "தாழ்ச்சியுள் தங்குதல் தீது.", "translation": "When counsel takes a resolve strong Weak delay of action is wrong"}, {"number": 672, "line1": "தூங்குக தூங்கிச் செயற்பால தூங்கற்க", "line2": "தூங்காது செய்யும் வினை.", "translation": "Delay such acts as need delay Delay not acts that need display"}, {"number": 673, "line1": "ஒல்லும்வா யெல்லாம் வினைநன்றே ஒல்லாக்கால்", "line2": "செல்லும்வாய் நோக்கிச் செயல்.", "translation": "It's best to act when feasible If not see what is possible"}, {"number": 674, "line1": "வினைபகை என்றிரண்டின் எச்சம் நினையுங்கால்", "line2": "தீயெச்சம் போலத் தெறும்.", "translation": "Work or foe left unfinished Flare up like fire unextinguished"}, {"number": 675, "line1": "பொருள்கருவி காலம் வினையிடனொடு ஐந்தும்", "line2": "இருள்தீர எண்ணிச் செயல்.", "translation": "Money and means, time, place and deed Decide these five and then proceed"}, {"number": 676, "line1": "முடிவும் இடையூறும் முற்றியாங்கு எய்தும்", "line2": "படுபயனும் பார்த்துச் செயல்.", "translation": "Weigh well the end, hindrance, profit  And then pursue a fitting act"}, {"number": 677, "line1": "செய்வினை செய்வான் செயன்முறை அவ்வினை", "line2": "உள்ளறிவான் உள்ளம் கொளல்.", "translation": "Know first the secret from experts That is the way of fruitful acts"}, {"number": 678, "line1": "வினையான் வினையாக்கிக் கோடல் நனைகவுள்", "line2": "யானையால் யானையாத் தற்று.", "translation": "Lure a tusker by a tusker Achieve a deed by deed better"}, {"number": 679, "line1": "நட்டார்க்கு நல்ல செயலின் விரைந்ததே", "line2": "ஒட்டாரை ஒட்டிக் கொளல்.", "translation": "Than doing good to friends it is More urgent to befriend the foes"}, {"number": 680, "line1": "உறைசிறியார் உள்நடுங்கல் அஞ்சிக் குறைபெறின்", "line2": "கொள்வர் பெரியார்ப் பணிந்து.", "translation": "Small statesmen fearing people's fear Submit to foes superior"}, {"number": 681, "line1": "அன்புடைமை ஆன்ற குடிப்பிறத்தல் வேந்தவாம்", "line2": "பண்புடைமை தூதுரைப்பான் பண்பு.", "translation": "Love, noble birth, good courtesy Pleasing kings mark true embassy"}, {"number": 682, "line1": "அன்பறிவு ஆராய்ந்த சொல்வன்மை தூதுரைப்பார்க்கு", "line2": "இன்றி யமையாத மூன்று.", "translation": "Envoys must bear love for their prince Knowledge and learned eloquence"}, {"number": 683, "line1": "நூலாருள் நூல்வல்லன் ஆகுதல் வேலாருள்", "line2": "வென்றி வினையுரைப்பான் பண்பு.", "translation": "Savant among savants, he pleads  Before lanced king, triumphant words"}, {"number": 684, "line1": "அறிவுரு வாராய்ந்த கல்விஇம் மூன்றன்", "line2": "செறிவுடையான் செல்க வினைக்கு.", "translation": "Who has these three: good form, sense, lore Can act as bold ambassador"}, {"number": 685, "line1": "தொகச்சொல்லித் தூவாத நீக்கி நகச்சொல்லி", "line2": "நன்றி பயப்பதாந் தூது.", "translation": "Not harsh, the envoy's winsome ways Does good by pleasant words concise"}, {"number": 686, "line1": "கற்றுக்கண் அஞ்சான் செலச்சொல்லிக் காலத்தால்", "line2": "தக்கது அறிவதாம் தூது.", "translation": "Learned; fearless, the envoy tends Convincing words which time demands"}, {"number": 687, "line1": "கடனறிந்து காலங் கருதி இடனறிந்து", "line2": "எண்ணி உரைப்பான் தலை.", "translation": "Knowing duty time and place The envoy employs mature phrase"}, {"number": 688, "line1": "தூய்மை துணைமை துணிவுடைமை இம்மூன்றின்", "line2": "வாய்மை வழியுரைப்பான் பண்பு.", "translation": "The true envoy of three virtues Is pure helpful and bold in views"}, {"number": 689, "line1": "விடுமாற்றம் வேந்தர்க்கு உரைப்பான் வடுமாற்றம்", "line2": "வாய்சேரா வன்கணவன்.", "translation": "The envoy who ports the king's message Has flawless words and heart's courage"}, {"number": 690, "line1": "இறுதி பயப்பினும் எஞ்சாது இறைவற்கு", "line2": "உறுதி பயப்பதாம் தூது.", "translation": "Braving death the bold envoy Assures his king's safety and joy"}, {"number": 691, "line1": "அகலாது அணுகாது தீக்காய்வார் போல்க", "line2": "இகல்வேந்தர்ச் சேர்ந்தொழுகு வார்.", "translation": "Move with hostile kings as with fire  Not coming close nor going far"}, {"number": 692, "line1": "மன்னர் விழைப விழையாமை மன்னரால்", "line2": "மன்னிய ஆக்கந் தரும்.", "translation": "Crave not for things which kings desire  This brings thee their fruitful favour"}, {"number": 693, "line1": "போற்றின் அரியவை போற்றல் கடுத்தபின்", "line2": "தேற்றுதல் யார்க்கும் அரிது.", "translation": "Guard thyself from petty excess Suspected least, there's no redress"}, {"number": 694, "line1": "செவிச்சொல்லும் சேர்ந்த நகையும் அவித்தொழுகல்", "line2": "ஆன்ற பெரியா ரகத்து.", "translation": "Whisper not; nor smile exchange Amidst august men's assemblage"}, {"number": 695, "line1": "எப்பொருளும் ஓரார் தொடரார்மற் றப்பொருளை", "line2": "விட்டக்கால் கேட்க மறை.", "translation": "Hear not, ask not the king's secret Hear only when he lets it out"}, {"number": 696, "line1": "குறிப்பறிந்து காலங் கருதி வெறுப்பில", "line2": "வேண்டுப வேட்பச் சொலல்.", "translation": "Discern his mood and time and tell No dislikes but what king likes well"}, {"number": 697, "line1": "வேட்பன சொல்லி வினையில எஞ்ஞான்றும்", "line2": "கேட்பினும் சொல்லா விடல்.", "translation": "Tell pleasing things; and never tell Even if pressed what is futile"}, {"number": 698, "line1": "இளையர் இனமுறையர் என்றிகழார் நின்ற", "line2": "ஒளியோடு ஒழுகப் படும்.", "translation": "As young and kinsman do not slight; Look with awe king's light and might"}, {"number": 699, "line1": "கொளப்பட்டேம் என்றெண்ணிக் கொள்ளாத செய்யார்", "line2": "துளக்கற்ற காட்சி யவர்.", "translation": "The clear-visioned do nothing base Deeming they have the monarch's grace"}, {"number": 700, "line1": "பழையம் எனக்கருதிப் பண்பல்ல செய்யும்", "line2": "கெழுதகைமை கேடு தரும்.", "translation": "Worthless acts based on friendship old  Shall spell ruin and woe untold"}, {"number": 701, "line1": "கூறாமை நோக்கக் குறிப்பறிவான் எஞ்ஞான்றும்", "line2": "மாறாநீர் வையக் கணி.", "translation": "Who reads the mind by look, untold Adorns the changeless sea-girt world"}, {"number": 702, "line1": "ஐயப் படாஅது அகத்தது உணர்வானைத்", "line2": "தெய்வத்தோ டொப்பக் கொளல்.", "translation": "Take him as God who reads the thought Of another man with without a doubt"}, {"number": 703, "line1": "குறிப்பிற் குறிப்புணர் வாரை உறுப்பினுள்", "line2": "யாது கொடுத்தும் கொளல்.", "translation": "By sign who scans the sign admit At any cost in cabinet"}, {"number": 704, "line1": "குறித்தது கூறாமைக் கொள்வாரோ டேனை", "line2": "உறுப்போ ரனையரால் வேறு.", "translation": "Untold, he who divines the thought Though same in form is quite apart"}, {"number": 705, "line1": "குறிப்பிற் குறிப்புணரா வாயின் உறுப்பினுள்", "line2": "என்ன பயத்தவோ கண்?", "translation": "Among senses what for is eye If thought by thought one can't descry?"}, {"number": 706, "line1": "அடுத்தது காட்டும் பளிங்குபோல் நெஞ்சம்", "line2": "கடுத்தது காட்டும் முகம்.", "translation": "What throbs in mind the face reflects Just as mirror nearby objects"}, {"number": 707, "line1": "முகத்தின் முதுக்குறைந்தது உண்டோ உவப்பினும்", "line2": "காயினும் தான்முந் துறும்.", "translation": "Than face what is subtler to tell First if the mind feels well or ill"}, {"number": 708, "line1": "முகம்நோக்கி நிற்க அமையும் அகம்நோக்கி", "line2": "உற்ற துணர்வார்ப் பெறின்.", "translation": "Just standing in front would suffice For those who read the mind on face"}, {"number": 709, "line1": "பகைமையும் கேண்மையும் கண்ணுரைக்கும் கண்ணின்", "line2": "வகைமை உணர்வார்ப் பெறின்.", "translation": "Friend or foe the eyes will show To those who changing outlooks know"}, {"number": 710, "line1": "நுண்ணியம் என்பார் அளக்குங்கோல் காணுங்கால்", "line2": "கண்ணல்லது இல்லை பிற.", "translation": "The scale of keen discerning minds  Is eye and eye that secrets finds"}, {"number": 711, "line1": "அவையறிநது ஆராய்ந்து சொல்லுக சொல்லின்", "line2": "தொகையறிந்த தூய்மை யவர்.", "translation": "The pure in thought and eloquence  Adapt their words to audience"}, {"number": 712, "line1": "இடைதெரிந்து நன்குணர்ந்து சொல்லுக சொல்லின்", "line2": "நடைதெரிந்த நன்மை யவர்.", "translation": "Who know the art of speech shall suit Their chosen words to time in fact"}, {"number": 713, "line1": "அவையறியார் சொல்லல்மேற் கொள்பவர் சொல்லின்", "line2": "வகையறியார் வல்லதூஉம் இல்.", "translation": "They speak in vain at length who talk Words unversed which ears don't take"}, {"number": 714, "line1": "ஒளியார்முன் ஒள்ளிய ராதல் வெளியார்முன்", "line2": "வான்சுதை வண்ணம் கொளல்.", "translation": "Before the bright be brilliant light Before the muff be mortar white"}, {"number": 715, "line1": "நன்றென்ற வற்றுள்ளும் நன்றே முதுவருள்", "line2": "முந்து கிளவாச் செறிவு.", "translation": "Modest restraint all good excels Which argues not before elders"}, {"number": 716, "line1": "ஆற்றின் நிலைதளர்ந் தற்றே வியன்புலம்", "line2": "ஏற்றுணர்வார் முன்னர் இழுக்கு.", "translation": "Tongue-slip before the talented wise is like slipping from righteous ways"}, {"number": 717, "line1": "கற்றறிந்தார் கல்வி விளங்கும் கசடறச்", "line2": "சொல்தெரிதல் வல்லார் அகத்து.", "translation": "The learning of the learned shines Valued by flawless scholar-minds"}, {"number": 718, "line1": "உணர்வ துடையார்முன் சொல்லல் வளர்வதன்", "line2": "பாத்தியுள் நீர்சொரிந் தற்று.", "translation": "To address understanding ones Is to water beds of growing grains"}, {"number": 719, "line1": "புல்லவையுள் பொச்சாந்தும் சொல்லற்க நல்லவையுள்", "line2": "நன்குசலச் சொல்லு வார்.", "translation": "O ye who speak before the keen Forgetful, address not the mean"}, {"number": 720, "line1": "அங்கணத்துள் உக்க அமிழ்தற்றால் தங்கணத்தார்", "line2": "அல்லார்முன் கோட்டி கொளல்.", "translation": "To hostiles who wise words utters Pours ambrosia into gutters"}, {"number": 721, "line1": "வகையறிந்து வல்லவை வாய்சோரார் சொல்லின்", "line2": "தொகையறிந்த தூய்மை யவர்.", "translation": "The pure fail not in power of words Knowing grand council's moods and modes"}, {"number": 722, "line1": "கற்றாருள் கற்றார் எனப்படுவர் கற்றார்முன்", "line2": "கற்ற செலச்சொல்லு வார்.", "translation": "Among scholars he is scholar Who holds scholars with learned lore"}, {"number": 723, "line1": "பகையகத்துச் சாவார் எளியர் அரியர்", "line2": "அவையகத்து அஞ்சா தவர்.", "translation": "Many brave foes and die in fields The fearless few face wise councils"}, {"number": 724, "line1": "கற்றார்முன் கற்ற செலச்சொல்லித் தாம்கற்ற", "line2": "மிக்காருள் மிக்க கொளல்.", "translation": "Impress the learned with your lore From greater savants learn still more"}, {"number": 725, "line1": "ஆற்றின் அளவறிந்து கற்க அவையஞ்சா", "line2": "மாற்றங் கொடுத்தற் பொருட்டு.", "translation": "Grammar and logic learn so that Foes you can boldly retort"}, {"number": 726, "line1": "வாளொடென் வன்கண்ணர் அல்லார்க்கு நூலொடென்", "line2": "நுண்ணவை அஞ்சு பவர்க்கு.", "translation": "To cowards what can sword avail And books to those who councils fail?"}, {"number": 727, "line1": "பகையகத்துப் பேடிகை ஒள்வாள் அவையகத்து", "line2": "அஞ்சு மவன்கற்ற நூல்.", "translation": "Like eunuch's sword in field, is vain His lore who fears men of brain"}, {"number": 728, "line1": "பல்லவை கற்றும் பயமிலரே நல்லவையுள்", "line2": "நன்கு செலச்சொல்லா தார்.", "translation": "Though learned much his lore is dead Who says no good before the good"}, {"number": 729, "line1": "கல்லா தவரின் கடையென்ப கற்றறிந்தும்", "line2": "நல்லா ரவையஞ்சு வார்.", "translation": "Who fear to face good assembly Are learned idiots, certainly"}, {"number": 730, "line1": "உளரெனினும் இல்லாரொடு ஒப்பர் களன்அஞ்சிக்", "line2": "கற்ற செலச்சொல்லா தார்.", "translation": "They are breathing dead who dare not Empress before the wise their art"}, {"number": 731, "line1": "தள்ளா விளையுளும் தக்காரும் தாழ்விலாச்", "line2": "செல்வரும் சேர்வது நாடு.", "translation": "It's country which has souls of worth Unfailing yields and ample wealth"}, {"number": 732, "line1": "பெரும்பொருளால் பெட்டக்க தாகி அருங்கேட்டால்", "line2": "ஆற்ற விளைவது நாடு.", "translation": "The Land has large luring treasure Where pests are nil and yields are sure"}, {"number": 733, "line1": "பொறையொருங்கு மேல்வருங்கால் தாங்கி இறைவற்கு", "line2": "இறையொருங்கு நேர்வது நாடு.", "translation": "It's land that bears pressing burdens And pays its tax which king demands"}, {"number": 734, "line1": "உறுபசியும் ஓவாப் பிணியும் செறுபகையும்", "line2": "சேரா தியல்வது நாடு.", "translation": "It is country which is free from Fierce famine, plague and foemen's harm"}, {"number": 735, "line1": "பல்குழுவும் பாழ்செய்யும் உட்பகையும் வேந்தலைக்கும்", "line2": "கொல்குறும்பும் இல்லது நாடு.", "translation": "Sects and ruinous foes are nil No traitors in a land tranquil"}, {"number": 736, "line1": "கேடறியாக் கெட்ட இடத்தும் வளங்குன்றா", "line2": "நாடென்ப நாட்டின் தலை.", "translation": "The land of lands no ruin knows Even in grief its wealth yet grows"}, {"number": 737, "line1": "இருபுனலும் வாய்ந்த மலையும் வருபுனலும்", "line2": "வல்லரணும் நாட்டிற்கு உறுப்பு.", "translation": "Waters up and down, hills and streams With strong forts as limbs country beams"}, {"number": 738, "line1": "பிணியின்மை செல்வம் விளைவின்பம் ஏமம்", "line2": "அணியென்ப நாட்டிவ் வைந்து.", "translation": "Rich yield, delight, defence and wealth Are jewels of lands with blooming health"}, {"number": 739, "line1": "நாடென்ப நாடா வளத்தன நாடல்ல", "line2": "நாட வளந்தரு நாடு.", "translation": "A land is land which yields unsought Needing hard work the land is nought"}, {"number": 740, "line1": "ஆங்கமை வெய்தியக் கண்ணும் பயமின்றே", "line2": "வேந்தமை வில்லாத நாடு.", "translation": "Though a land has thus every thing It is worthless without a king"}, {"number": 741, "line1": "ஆற்று பவர்க்கும் அரண்பொருள் அஞ்சித்தற்", "line2": "போற்று பவர்க்கும் பொருள்.", "translation": "The fort is vital for offence Who fear the foes has its defence"}, {"number": 742, "line1": "மணிநீரும் மண்ணும் மலையும் அணிநிழற்", "line2": "காடும் உடைய தரண்.", "translation": "A crystal fount, a space a mount Thick woods form a fort paramount"}, {"number": 743, "line1": "உயர்வகலம் திண்மை அருமைஇந் நான்கின்", "line2": "அமைவரண் என்றுரைக்கும் நூல்.", "translation": "An ideal fort's so says science: High, broad, strong and hard for access"}, {"number": 744, "line1": "சிறுகாப்பிற் பேரிடத்த தாகி உறுபகை", "line2": "ஊக்கம் அழிப்ப தரண்.", "translation": "Ample in space, easy to hold The fort foils enemies bold"}, {"number": 745, "line1": "கொளற்கரிதாய்க் கொண்டகூழ்த் தாகி அகத்தார்", "line2": "நிலைக்கெளிதாம் நீரது அரண்.", "translation": "Impregnable with stores of food Cosy to live-That fort is good"}, {"number": 746, "line1": "எல்லாப் பொருளும் உடைத்தாய் இடத்துதவும்", "line2": "நல்லாள் உடையது அரண்.", "translation": "A fort is full of stores and arms And brave heroes to meet alarms"}, {"number": 747, "line1": "முற்றியும் முற்றா தெறிந்தும் அறைப்படுத்தும்", "line2": "பற்றற் கரியது அரண்.", "translation": "Besieging foes a fort withstands Darts and mines of treacherous hands"}, {"number": 748, "line1": "முற்றாற்றி முற்றி யவரையும் பற்றாற்றிப்", "line2": "பற்றியார் வெல்வது அரண்.", "translation": "A fort holds itself and defies The attacks of encircling foes"}, {"number": 749, "line1": "முனைமுகத்து மாற்றலர் சாய வினைமுகத்து", "line2": "வீறெய்தி மாண்ட தரண்.", "translation": "A fort it is that fells the foes And gains by deeds a name glorious"}, {"number": 750, "line1": "எனைமாட்சித் தாகியக் கண்ணும் வினைமாட்சி", "line2": "இல்லார்கண் இல்லது அரண்.", "translation": "But a fort however grand Is nil if heroes do not stand"}, {"number": 751, "line1": "பொருளல் லவரைப் பொருளாகச் செய்யும்", "line2": "பொருளல்லது இல்லை பொருள்.", "translation": "Naught exists that can, save wealth Make the worthless as men of worth"}, {"number": 752, "line1": "இல்லாரை எல்லாரும் எள்ளுவர் செல்வரை", "line2": "எல்லாரும் செய்வர் சிறப்பு.", "translation": "The have-nothing poor all despise The men of wealth all raise and praise"}, {"number": 753, "line1": "பொருளென்னும் பொய்யா விளக்கம் இருளறுக்கும்", "line2": "எண்ணிய தேயத்துச் சென்று.", "translation": "Waneless wealth is light that goes To every land and gloom removes"}, {"number": 754, "line1": "அறன்ஈனும் இன்பமும் ஈனும் திறனறிந்து", "line2": "தீதின்றி வந்த பொருள்.", "translation": "The blameless wealth from fairest means Brings good virtue and also bliss"}, {"number": 755, "line1": "அருளொடும் அன்பொடும் வாராப் பொருளாக்கம்", "line2": "புல்லார் புரள விடல்.", "translation": "Riches devoid of love and grace Off with it; it is disgrace!"}, {"number": 756, "line1": "உறுபொருளும் உல்கு பொருளும்தன் ஒன்னார்த்", "line2": "தெறுபொருளும் வேந்தன் பொருள்.", "translation": "Escheats, derelicts; spoils of war Taxes duties are king's treasure"}, {"number": 757, "line1": "அருளென்னும் அன்பீன் குழவி பொருளென்னும்", "line2": "செல்வச் செவிலியால் உண்டு.", "translation": "Grace the child of love is nourished By the wet-nurse of wealth cherished"}, {"number": 758, "line1": "குன்றேறி யானைப்போர் கண்டற்றால் தன்கைத்தொன்று", "line2": "உண்டாகச் செய்வான் வினை.", "translation": "Treasures in hand fulfil all things Like hill-tuskers the wars of kings"}, {"number": 759, "line1": "செய்க பொருளைச் செறுநர் செருக்கறுக்கும்", "line2": "எஃகதனிற் கூரிய தில்.", "translation": "Make wealth; there is no sharper steel The insolence of foes to quell"}, {"number": 760, "line1": "ஒண்பொருள் காழ்ப்ப இயற்றியார்க்கு எண்பொருள்", "line2": "ஏனை இரண்டும் ஒருங்கு.", "translation": "They have joy and virtue at hand Who acquire treasures abundant"}, {"number": 761, "line1": "உறுப்பமைந்து ஊறஞ்சா வெல்படை வேந்தன்", "line2": "வெறுக்கையுள் எல்லாம் தலை.", "translation": "The daring well-armed winning force Is king's treasure and main resource"}, {"number": 762, "line1": "உலைவிடத்து ஊறஞ்சா வன்கண் தொலைவிடத்துத்", "line2": "தொல்படைக் கல்லால் அரிது.", "translation": "Through shots and wounds brave heroes hold Quailing not in fall, the field"}, {"number": 763, "line1": "ஒலித்தக்கால் என்னாம் உவரி எலிப்பகை", "line2": "நாகம் உயிர்ப்பக் கெடும்.", "translation": "Sea-like ratfoes roar What if? They perish at a cobra's whiff"}, {"number": 764, "line1": "அழிவின்றி அறைபோகா தாகி வழிவந்த", "line2": "வன்க ணதுவே படை.", "translation": "The army guards its genial flame Not crushed, routed nor marred in name"}, {"number": 765, "line1": "கூற்றுடன்று மேல்வரினும் கூடி எதிர்நிற்கும்", "line2": "ஆற்ற லதுவே படை.", "translation": "The real army with rallied force Resists even Death-God fierce"}, {"number": 766, "line1": "மறமானம் மாண்ட வழிச்செலவு தேற்றம்", "line2": "எனநான்கே ஏமம் படைக்கு.", "translation": "Manly army has merits four:- Stately-march, faith, honour, valour"}, {"number": 767, "line1": "தார்தாங்கிச் செல்வது தானை தலைவந்த", "line2": "போர்தாங்கும் தன்மை அறிந்து.", "translation": "Army sets on to face to foes Knowing how the trend of war goes"}, {"number": 768, "line1": "அடல்தகையும் ஆற்றலும் இல்லெனினும் தானை", "line2": "படைத்தகையால் பாடு பெறும்.", "translation": "Army gains force by grand array Lacking in stay or dash in fray"}, {"number": 769, "line1": "சிறுமையும் செல்லாத் துனியும் வறுமையும்", "line2": "இல்லாயின் வெல்லும் படை.", "translation": "Army shall win if it is free From weakness, aversion, poverty"}, {"number": 770, "line1": "நிலைமக்கள் சால உடைத்தெனினும் தானை", "line2": "தலைமக்கள் இல்வழி இல்.", "translation": "With troops in large numbers on rolls Army can't march missing gen'rals"}, {"number": 771, "line1": "என்னைமுன் நில்லன்மின் தெவ்விர் பலரென்னை", "line2": "முன்நின்று கல்நின் றவர்.", "translation": "Stand not before my chief, O foes! Many who stood, in stones repose"}, {"number": 772, "line1": "கான முயலெய்த அம்பினில் யானை", "line2": "பிழைத்தவேல் ஏந்தல் இனிது.", "translation": "To lift a lance that missed a tusker Is prouder than shaft that hit a hare"}, {"number": 773, "line1": "பேராண்மை என்ப தறுகண்ஒன் றுற்றக்கால்", "line2": "ஊராண்மை மற்றதன் எஃகு.", "translation": "Valour is fight with fierce courage Mercy to the fallen is its edge"}, {"number": 774, "line1": "கைவேல் களிற்றொடு போக்கி வருபவன்", "line2": "மெய்வேல் பறியா நகும்.", "translation": "At the tusker he flings his lance One in body smiles another chance"}, {"number": 775, "line1": "விழித்தகண் வேல்கொண டெறிய அழித்திமைப்பின்", "line2": "ஒட்டன்றோ வன்க ணவர்க்கு.", "translation": "When lances dart if heroes wink \\\"It is a rout\\\" the world will think"}, {"number": 776, "line1": "விழுப்புண் படாதநாள் எல்லாம் வழுக்கினுள்", "line2": "வைக்கும்தன் நாளை எடுத்து.", "translation": "The brave shall deem the days as vain Which did not battle-wounds sustain"}, {"number": 777, "line1": "சுழலும் இசைவேண்டி வேண்டா உயிரார்", "line2": "கழல்யாப்புக் காரிகை நீர்த்து.", "translation": "Their anklets aloud jingle their name Who sacrifice their life for fame"}, {"number": 778, "line1": "உறின்உயிர் அஞ்சா மறவர் இறைவன்", "line2": "செறினும் சீர்குன்றல் இலர்.", "translation": "The king may chide, they pursue strife; They fear loss of glory; not life"}, {"number": 779, "line1": "இழைத்தது இகவாமைச் சாவாரை யாரே", "line2": "பிழைத்தது ஒறுக்கிற் பவர்.", "translation": "Who will blame the heroes that lose Their lives in war to keep their vows?"}, {"number": 780, "line1": "புரந்தார்கண் நீர்மல்கச் சாகிற்பின் சாக்காடு", "line2": "இரந்துகோள் தக்கது உடைத்து.", "translation": "Such a death shall be prayed for Which draws the the tears of the ruler"}, {"number": 781, "line1": "செயற்கரிய யாவுள நட்பின் அதுபோல்", "line2": "வினைக்கரிய யாவுள காப்பு.", "translation": "Like friendship what's so hard to gain? That guards one against acts villain?"}, {"number": 782, "line1": "நிறைநீர நீரவர் கேண்மை பிறைமதிப்", "line2": "பின்னீர பேதையார் நட்பு.", "translation": "Good friendship shines like waxing moon, The bad withers like waning moon"}, {"number": 783, "line1": "நவில்தொறும் நூல்நயம் போலும் பயில்தொறும்", "line2": "பண்புடை யாளர் தொடர்பு.", "translation": "Like taste in books good friendship grows The more one moves the more he knows"}, {"number": 784, "line1": "நகுதற் பொருட்டன்று நட்டல் மிகுதிக்கண்", "line2": "மேற்செனறு இடித்தற் பொருட்டு.", "translation": "Not to laugh is friendship made But to hit when faults exceed"}, {"number": 785, "line1": "புணர்ச்சி பழகுதல் வேண்டா உணர்ச்சிதான்", "line2": "நட்பாங் கிழமை தரும்.", "translation": "No close living nor clasping grip Friendship's feeling heart's fellowship"}, {"number": 786, "line1": "முகநக நட்பது நட்பன்று நெஞ்சத்து", "line2": "அகநக நட்பது நட்பு.", "translation": "Friendship is not more smile on face It is the smiling heart's embrace"}, {"number": 787, "line1": "அழிவி னவைநீக்கி ஆறுய்த்து அழிவின்கண்", "line2": "அல்லல் உழப்பதாம் நட்பு.", "translation": "From ruin friendship saves and shares The load of pain and right path shows"}, {"number": 788, "line1": "உடுக்கை இழந்தவன் கைபோல ஆங்கே", "line2": "இடுக்கண் களைவதாம் நட்பு.", "translation": "Friendship hastens help in mishaps Like hands picking up dress that slips"}, {"number": 789, "line1": "நட்பிற்கு வீற்றிருக்கை யாதெனின் கொட்பின்றி", "line2": "ஒல்லும்வாய் ஊன்றும் நிலை.", "translation": "Friendship is enthroned on the strength That always helps with utmost warmth"}, {"number": 790, "line1": "இனையர் இவரெமக்கு இன்னம்யாம் என்று", "line2": "புனையினும் புல்லென்னும் நட்பு.", "translation": "\\\"Such we are and such they are!\\\" Ev'n this boast will friendship mar"}, {"number": 791, "line1": "நாடாது நட்டலிற் கேடில்லை நட்டபின்", "line2": "வீடில்லை நட்பாள் பவர்க்கு.", "translation": "Than testless friendship nought is worse For contacts formed will scarcely cease"}, {"number": 792, "line1": "ஆய்ந்தாய்ந்து கொள்ளாதான் கேண்மை கடைமுறை", "line2": "தான்சாம் துயரம் தரும்.", "translation": "Friendship made without frequent test Shall end in grief and death at last"}, {"number": 793, "line1": "குணமும் குடிமையும் குற்றமும் குன்றா", "line2": "இனனும் அறிந்தியாக்க நட்பு.", "translation": "Temper, descent, defects and kins Trace well and take companions"}, {"number": 794, "line1": "குடிப்பிறந்து தன்கண் பழிநாணு வானைக்", "line2": "கொடுத்தும் கொளல்வேண்டும் நட்பு.", "translation": "Take as good friend at any price The nobly born who shun disgrace"}, {"number": 795, "line1": "அழச்சொல்லி அல்லது இடித்து வழக்கறிய", "line2": "வல்லார்நடபு ஆய்ந்து கொளல்.", "translation": "Who make you weep and chide wrong trends And lead you right are worthy friends"}, {"number": 796, "line1": "கேட்டினும் உண்டோர் உறுதி கிளைஞரை", "line2": "நீட்டி அளப்பதோர் கோல்.", "translation": "Is there a test like misfortune A rod to measure out kinsmen?"}, {"number": 797, "line1": "ஊதியம் என்பது ஒருவற்குப் பேதையார்", "line2": "கேண்மை ஒரீஇ விடல்.", "translation": "Keep off contacts with fools; that is The greatest gain so say the wise"}, {"number": 798, "line1": "உள்ளற்க உள்ளம் சிறுகுவ கொள்ளற்க", "line2": "அல்லற்கண் ஆற்றறுப்பார் நட்பு.", "translation": "Off with thoughts that depress the heart Off with friends that in woe depart"}, {"number": 799, "line1": "கெடுங்காலைக் கைவிடுவார் கேண்மை அடுங்காலை", "line2": "உள்ளினும் உள்ளஞ் சுடும்.", "translation": "Friends who betray at ruin's brink Burn our mind ev'n at death to think"}, {"number": 800, "line1": "மருவுக மாசற்றார் கேண்மைஒன் றீத்தும்", "line2": "ஒருவுக ஒப்பிலார் நட்பு.", "translation": "The blameless ones as friends embarace; Give something and give up the base"}, {"number": 801, "line1": "பழைமை எனப்படுவது யாதெனின் யாதும்", "line2": "கிழமையைக் கீழ்ந்திடா நட்பு.", "translation": "That friendship is good amity Which restrains not one's liberty"}, {"number": 802, "line1": "நட்பிற் குறுப்புக் கெழுதகைமை மற்றதற்கு", "line2": "உப்பாதல் சான்றோர் கடன்.", "translation": "Friendship's heart is freedom close; Wise men's duty is such to please"}, {"number": 803, "line1": "பழகிய நட்பெவன் செய்யுங் கெழுதகைமை", "line2": "செய்தாங்கு அமையாக் கடை.", "translation": "Of long friendship what is the use Righteous freedom if men refuse?"}, {"number": 804, "line1": "விழைதகையான் வேண்டி இருப்பர் கெழுதகையாற்", "line2": "கேளாது நட்டார் செயின்.", "translation": "Things done unasked by loving friends Please the wise as familiar trends!"}, {"number": 805, "line1": "பேதைமை ஒன்றோ பெருங்கிழமை என்றுணர்க", "line2": "நோதக்க நட்டார் செயின்.", "translation": "Offence of friends feel it easy As folloy or close intimacy"}, {"number": 806, "line1": "எல்லைக்கண் நின்றார் துறவார் தொலைவிடத்தும்", "line2": "தொல்லைக்கண் நின்றார் தொடர்பு.", "translation": "They forsake not but continue In friendship's bounds though loss ensue"}, {"number": 807, "line1": "அழிவந்த செய்யினும் அன்பறார் அன்பின்", "line2": "வழிவந்த கேண்மை யவர்.", "translation": "Comrades established in firm love Though ruin comes waive not their vow"}, {"number": 808, "line1": "கேளிழுக்கம் கேளாக் கெழுதகைமை வல்லார்க்கு", "line2": "நாளிழுக்கம் நட்டார் செயின்.", "translation": "Fast friends who list not tales of ill Though wronged they say \\\"that day is well\\\""}, {"number": 809, "line1": "கெடாஅ வழிவந்த கேண்மையார் கேண்மை", "line2": "விடாஅர் விழையும் உலகு.", "translation": "To love such friends the world desires Whose friendship has unbroken ties"}, {"number": 810, "line1": "விழையார் விழையப் படுப பழையார்கண்", "line2": "பண்பின் தலைப்பிரியா தார்.", "translation": "Even foes love for better ends Those who leave not long-standing friends"}, {"number": 811, "line1": "பருகுவார் போலினும் பண்பிலார் கேண்மை", "line2": "பெருகலிற் குன்றல் இனிது.", "translation": "Swallowing love of soulless men Had better wane than wax anon"}, {"number": 812, "line1": "உறின்நட்டு அறினொருஉம் ஒப்பிலார் கேண்மை", "line2": "பெறினும் இழப்பினும் என்?", "translation": "Who fawn in wealth and fail in dearth Gain or lose; such friends have no worth"}, {"number": 813, "line1": "உறுவது சீர்தூக்கும் நட்பும் பெறுவது", "line2": "கொள்வாரும் கள்வரும் நேர்.", "translation": "Cunning friends who calculate  Are like thieves and whores wicked"}, {"number": 814, "line1": "அமரகத்து ஆற்றறுக்கும் கல்லாமா அன்னார்", "line2": "தமரின் தனிமை தலை.", "translation": "Better be alone than trust in those That throw in field like faithless horse"}, {"number": 815, "line1": "செய்தேமஞ் சாராச் சிறியவர் புன்கேண்மை", "line2": "எய்தலின் எய்தாமை நன்று.", "translation": "Friends low and mean that give no help- Leave them is better than to keep"}, {"number": 816, "line1": "பேதை பெருங்கெழீஇ நட்பின் அறிவுடையார்", "line2": "ஏதின்மை கோடி உறும்.", "translation": "Million times the wise man's hate Is better than a fool intimate"}, {"number": 817, "line1": "நகைவகைய ராகிய நட்பின் பகைவரால்", "line2": "பத்தடுத்த கோடி உறும்.", "translation": "Ten-fold crore you gain from foes Than from friends who are vain laughers"}, {"number": 818, "line1": "ஒல்லும் கருமம் உடற்று பவர்கேண்மை", "line2": "சொல்லாடார் சோர விடல்.", "translation": "Without a word those friends eschew Who spoil deeds which they can do"}, {"number": 819, "line1": "கனவினும் இன்னாது மன்னோ வினைவேறு", "line2": "சொல்வேறு பட்டார் தொடர்பு.", "translation": "Even in dreams the tie is bad With those whose deed is far from word"}, {"number": 820, "line1": "எனைத்தும் குறுகுதல் ஓம்பல் மனைக்கெழீஇ", "line2": "மன்றில் பழிப்பார் தொடர்பு.", "translation": "Keep aloof from those that smile At home and in public revile"}, {"number": 821, "line1": "சீரிடம் காணின் எறிதற்குப் பட்டடை", "line2": "நேரா நிரந்தவர் நட்பு.", "translation": "The friendship by an enemy shown Is anvil in time, to strike you down"}, {"number": 822, "line1": "இனம்போன்று இனமல்லார் கேண்மை மகளிர்", "line2": "மனம்போல வேறு படும்.", "translation": "Who pretend kinship but are not Their friendship's fickle like woman's heart"}, {"number": 823, "line1": "பலநல்ல கற்றக் கடைத்து மனநல்லர்", "line2": "ஆகுதல் மாணார்க் கரிது.", "translation": "They may be vast in good studies But heartfelt-love is hard for foes"}, {"number": 824, "line1": "முகத்தின் இனிய நகாஅ அகத்தின்னா", "line2": "வஞ்சரை அஞ்சப் படும்.", "translation": "Fear foes whose face has winning smiles Whose heart is full of cunning guiles"}, {"number": 825, "line1": "மனத்தின் அமையா தவரை எனைத்தொன்றும்", "line2": "சொல்லினால் தேறற்பாற்று அன்று.", "translation": "Do not trust in what they tell Whose mind with your mind goes ill"}, {"number": 826, "line1": "நட்டார்போல் நல்லவை சொல்லினும் ஒட்டார்சொல்", "line2": "ஒல்லை உணரப் படும்.", "translation": "The words of foes is quickly seen Though they speak like friends in fine"}, {"number": 827, "line1": "சொல்வணக்கம் ஒன்னார்கண் கொள்ளற்க வில்வணக்கம்", "line2": "தீங்கு குறித்தமை யான்.", "translation": "Trust not the humble words of foes Danger darts from bending bows"}, {"number": 828, "line1": "தொழுதகை யுள்ளும் படையொடுங்கும் ஒன்னார்", "line2": "அழுதகண் ணீரும் அனைத்து.", "translation": "Adoring hands of foes hide arms Their sobbing tears have lurking harms"}, {"number": 829, "line1": "மிகச்செய்து தம்மெள்ளு வாரை நகச்செய்து", "line2": "நட்பினுள் சாப்புல்லற் பாற்று.", "translation": "In open who praise, at heart despise Cajole and crush them in friendly guise"}, {"number": 830, "line1": "பகைநட்பாம் காலம் வருங்கால் முகநட்டு", "line2": "அகநட்பு ஒரீஇ விடல்.", "translation": "When foes, in time, play friendship's part Feign love on face but not in heart"}, {"number": 831, "line1": "பேதைமை என்பதொன்று யாதெனின் ஏதங்கொண்டு", "line2": "ஊதியம் போக விடல்.", "translation": "This is folly's prominent vein To favour loss and forego gain"}, {"number": 832, "line1": "பேதைமையுள் எல்லாம் பேதைமை காதன்மை", "line2": "கையல்ல தன்கட் செயல்.", "translation": "Folly of follies is to lead A lewd and lawless life so bad"}, {"number": 833, "line1": "நாணாமை நாடாமை நாரின்மை யாதொன்றும்", "line2": "பேணாமை பேதை தொழில்", "translation": "Shameless, aimless, callous, listless Such are the marks of foolishness"}, {"number": 834, "line1": "ஓதி உணர்ந்தும் பிறர்க்குரைத்தும் தானடங்காப்", "line2": "பேதையின் பேதையார் இல்.", "translation": "No fool equals the fool who learns Knows, teaches, but self-control spurns"}, {"number": 835, "line1": "ஒருமைச் செயலாற்றும் பேதை எழுமையும்", "line2": "தான்புக் கழுந்தும் அளறு.", "translation": "The fool suffers seven fold hells In single birth of hellish ills"}, {"number": 836, "line1": "பொய்படும் ஒன்றோ புனைபூணும் கையறியாப்", "line2": "பேதை வினைமேற் கொளின்.", "translation": "A know-nothing fool daring a deed Not only fails but feels fettered"}, {"number": 837, "line1": "ஏதிலார் ஆரத் தமர்பசிப்பர் பேதை", "line2": "பெருஞ்செல்வம் உற்றக் கடை.", "translation": "Strangers feast and kinsmen fast  When fools mishandle fortunes vast"}, {"number": 838, "line1": "மையல் ஒருவன் களித்தற்றால் பேதைதன்", "line2": "கையொன்று உடைமை பெறின்.", "translation": "Fools possessing something on hand Like dazed and drunken stupids stand"}, {"number": 839, "line1": "பெரிதினிது பேதையார் கேண்மை பிரிவின்கண்", "line2": "பீழை தருவதொன் றில்.", "translation": "Friendship with fools is highly sweet For without a groan we part"}, {"number": 840, "line1": "கழாஅக்கால் பள்ளியுள் வைத்தற்றால் சான்றோர்", "line2": "குழாஅத்துப் பேதை புகல்.", "translation": "Entrance of fools where Savants meet Looks like couch trod by unclean feet"}, {"number": 841, "line1": "அறிவின்மை இன்மையுள் இன்மை பிறிதின்மை", "line2": "இன்மையா வையா துலகு.", "translation": "Want of wisdom is want of wants Want of aught else the world nev'r counts"}, {"number": 842, "line1": "அறிவிலான் நெஞ்சுவந்து ஈதல் பிறிதியாதும்", "line2": "இல்லை பெறுவான் தவம்.", "translation": "When fool bestows with glee a gift It comes but by getter's merit"}, {"number": 843, "line1": "அறிவிலார் தாந்தம்மைப் பீழிக்கும் பீழை", "line2": "செறுவார்க்கும் செய்தல் அரிது.", "translation": "The self-torments of fools exceed Ev'n tortures of their foes indeed"}, {"number": 844, "line1": "வெண்மை எனப்படுவ தியாதெனின் ஒண்மை", "line2": "உடையம்யாம் என்னும் செருக்கு.", "translation": "Stupidity is vanity That cries \\\"We have sagacity\\\""}, {"number": 845, "line1": "கல்லாத மேற்கொண் டொழுகல் கசடற", "line2": "வல்லதூஉம் ஐயம் தரும்.", "translation": "Feigning knowledge that one has not Leads to doubt ev'n that he has got"}, {"number": 846, "line1": "அற்றம் மறைத்தலோ புல்லறிவு தம்வயின்", "line2": "குற்றம் மறையா வழி.", "translation": "Fools their nakedness conceal And yet their glaring faults reveal"}, {"number": 847, "line1": "அருமறை சோரும் அறிவிலான் செய்யும்", "line2": "பெருமிறை தானே தனக்கு.", "translation": "The fool that slights sacred counsels Upon himself great harm entails"}, {"number": 848, "line1": "ஏவவும் செய்கலான் தான்தேறான் அவ்வுயிர்", "line2": "போஒம் அளவுமோர் நோய்.", "translation": "He listens not nor himself knows Plague is his life until it goes"}, {"number": 849, "line1": "காணாதான் காட்டுவான் தான்காணான் காணாதான்", "line2": "கண்டானாம் தான்கண்ட வாறு.", "translation": "Sans Self-sight in vain one opens Sight To the blind who bet their sight as right"}, {"number": 850, "line1": "உலகத்தார் உண்டென்பது இல்லென்பான் வையத்து", "line2": "அலகையா வைக்கப் படும்.", "translation": "To people's \\\"Yes\\\" who proffer \\\"No\\\" Deemed as ghouls on earth they go"}, {"number": 851, "line1": "இகலென்ப எல்லா உயிர்க்கும் பகலென்னும்", "line2": "பண்பின்மை பார஧க்கும் நோய்.", "translation": "Hatred is a plague that divides And rouses illwill on all sides"}, {"number": 852, "line1": "பகல்கருதிப் பற்றா செயினும் இகல்கருதி", "line2": "இன்னாசெய் யாமை தலை.", "translation": "Rouse not hatred and confusion Though foes provoke disunion"}, {"number": 853, "line1": "இகலென்னும் எவ்வநோய் நீக்கின் தவலில்லாத்", "line2": "தாவில் விளக்கம் தரும்.", "translation": "Shun the plague of enmity And win everlasting glory"}, {"number": 854, "line1": "இன்பத்துள் இன்பம் பயக்கும் இகலென்னும்", "line2": "துன்பத்துள் துன்பங் கெடின்.", "translation": "Hate-the woe of woes destroy; Then joy of joys you can enjoy"}, {"number": 855, "line1": "இகலெதிர் சாய்ந்தொழுக வல்லாரை யாரே", "line2": "மிக்லூக்கும் தன்மை யவர்.", "translation": "Who can overcome them in glory That are free from enmity?"}, {"number": 856, "line1": "இகலின் மிகலினிது என்பவன் வாழ்க்கை", "line2": "தவலும் கெடலும் நணித்து.", "translation": "His fall and ruin are quite near Who holds enmity sweet and dear"}, {"number": 857, "line1": "மிகல்மேவல் மெய்ப்பொருள் காணார் இகல்மேவல்", "line2": "இன்னா அறிவி னவர்.", "translation": "They cannot see the supreme Truth Who hate and injure without ruth"}, {"number": 858, "line1": "இகலிற்கு எதிர்சாய்தல் ஆக்கம் அதனை", "line2": "மிக்லூக்கின் ஊக்குமாம் கேடு.", "translation": "To turn from enmity is gain Fomenting it brings fast ruin"}, {"number": 859, "line1": "இகல்காணான் ஆக்கம் வருங்கால் அதனை", "line2": "மிகல்காணும் கேடு தரற்கு.", "translation": "Fortune favours when hate recedes Hatred exceeding ruin breeds"}, {"number": 860, "line1": "இகலானாம் இன்னாத எல்லாம் நகலானாம்", "line2": "நன்னயம் என்னும் செருக்கு.", "translation": "All evils come from enmity All goodness flow from amity"}, {"number": 861, "line1": "வலியார்க்கு மாறேற்றல் ஓம்புக ஓம்பா", "line2": "மெலியார்மேல் மேக பகை.", "translation": "Turn from strife with foes too strong With the feeble for battle long"}, {"number": 862, "line1": "அன்பிலன் ஆன்ற துணையிலன் தான்துவ்வான்", "line2": "என்பரியும் ஏதிலான் துப்பு.", "translation": "Loveless, aidless, powerless king Can he withstand an enemy strong?"}, {"number": 863, "line1": "அஞ்சும் அறியான் அமைவிலன் ஈகலான்", "line2": "தஞ்சம் எளியன் பகைக்கு.", "translation": "Unskilled, timid, miser, misfit He is easy for foes to hit"}, {"number": 864, "line1": "நீங்கான் வெகுளி நிறையிலன் எஞ்ஞான்றும்", "line2": "யாங்கணும் யார்க்கும் எளிது.", "translation": "The wrathful restive man is prey To any, anywhere any day"}, {"number": 865, "line1": "வழிநோக்கான் வாய்ப்பன செய்யான் பழிநோக்கான்", "line2": "பண்பிலன் பற்றார்க்கு இனிது.", "translation": "Crooked, cruel, tactless and base Any foe can fell him with ease"}, {"number": 866, "line1": "காணாச் சினத்தான் கழிபெருங் காமத்தான்", "line2": "பேணாமை பேணப் படும்.", "translation": "Blind in rage and mad in lust To have his hatred is but just"}, {"number": 867, "line1": "கொடுத்தும் கொளல்வேண்டும் மன்ற அடுத்திருந்து", "line2": "மாணாத செய்வான் பகை.", "translation": "Pay and buy his enmity Who muddles chance with oddity"}, {"number": 868, "line1": "குணனிலனாய்க் குற்றம் பலவாயின் மாற்றார்க்கு", "line2": "இனனிலனாம் ஏமாப் புடைத்து.", "translation": "With no virtue but full of vice He loses friends and delights foes"}, {"number": 869, "line1": "செறுவார்க்குச் சேணிகவா இன்பம் அறிவிலா", "line2": "அஞ்சும் பகைவர்ப் பெறின்.", "translation": "The joy of heroes knows no bounds When timid fools are opponents"}, {"number": 870, "line1": "கல்லான் வெகுளும் சிறுபொருள் எஞ்ஞான்றும்", "line2": "ஒல்லானை ஒல்லா தொளி.", "translation": "Glory's light he will not gain Who fails to fight a fool and win"}, {"number": 871, "line1": "பகைஎன்னும் பண்பி லதனை ஒருவன்", "line2": "நகையேயும் வேண்டற்பாற்று அன்று.", "translation": "Let not one even as a sport The ill-natured enmity court"}, {"number": 872, "line1": "வில்லேர் உழவர் பகைகொளினும் கொள்ளற்க", "line2": "சொல்லேர் உழவர் பகை.", "translation": "Incur the hate of bow-ploughers But not the hate of word-ploughers"}, {"number": 873, "line1": "ஏமுற் றவரினும் ஏழை தமியனாய்ப்", "line2": "பல்லார் பகைகொள் பவன்.", "translation": "Forlorn, who rouses many foes The worst insanity betrays"}, {"number": 874, "line1": "பகைநட்பாக் கொண்டொழுகும் பண்புடை யாளன்", "line2": "தகைமைக்கண் தங்கிற்று உலகு.", "translation": "This world goes safely in his grace Whose heart makes friends even of foes"}, {"number": 875, "line1": "தன்துணை இன்றால் பகையிரண்டால் தான்ஒருவன்", "line2": "இன்துணையாக் கொள்கவற்றின் ஒன்று.", "translation": "Alone, if two foes you oppose Make one of them your ally close"}, {"number": 876, "line1": "தேறினும் தேறா விடினும் அழிவின்கண்", "line2": "தேறான் பகாஅன் விடல்.", "translation": "Trust or distrust; during distress Keep aloof; don't mix with foes"}, {"number": 877, "line1": "நோவற்க நொந்தது அறியார்க்கு மேவற்க", "line2": "மென்மை பகைவர் அகத்து.", "translation": "To those who know not, tell not your pain Nor your weakness to foes explain"}, {"number": 878, "line1": "வகையறிந்து தற்செய்து தற்காப்ப மாயும்", "line2": "பகைவர்கண் பட்ட செருக்கு.", "translation": "Know how and act and defend well The pride of enemies shall fall"}, {"number": 879, "line1": "இளைதாக முள்மரம் கொல்க களையுநர்", "line2": "கைகொல்லும் காழ்த்த இடத்து.", "translation": "Cut off thorn-trees when young they are; Grown hard, they cut your hands beware"}, {"number": 880, "line1": "உயிர்ப்ப உளரல்லர் மன்ற செயிர்ப்பவர்", "line2": "செம்மல் சிதைக்கலா தார்.", "translation": "To breathe on earth they are not fit Defying foes who don't defeat"}, {"number": 881, "line1": "நிழல்நீரும் இன்னாத இன்னா தமர்நீரும்", "line2": "இன்னாவாம் இன்னா செயின்.", "translation": "Traitorous kinsmen will make you sad As water and shade do harm when bad"}, {"number": 882, "line1": "வாள்போல பகைவரை அஞ்சற்க அஞ்சுக", "line2": "கேள்போல் பகைவர் தொடர்பு.", "translation": "You need not sword-like kinsmen fear Fear foes who feign as kinsmen dear"}, {"number": 883, "line1": "உட்பகை அஞ்சித்தற் காக்க உலைவிடத்து", "line2": "மட்பகையின் மாணத் தெறும்.", "translation": "The secret foe in days evil Will cut you, beware, like potters' steel"}, {"number": 884, "line1": "மனமாணா உட்பகை தோன்றின் இனமாணா", "line2": "ஏதம் பலவும் தரும்.", "translation": "The evil-minded foe within Foments trouble, spoils kinsmen!"}, {"number": 885, "line1": "உறல்முறையான் உட்பகை தோன்றின் இறல்முறையான்", "line2": "ஏதம் பலவும் தரும்.", "translation": "A traitor among kinsmen will Bring life-endangering evil"}, {"number": 886, "line1": "ஒன்றாமை ஒன்றியார் கட்படின் எஞ்ஞான்றும்", "line2": "பொன்றாமை ஒன்றல் அரிது.", "translation": "Discord in kings' circle entails Life-destroying deadly evils"}, {"number": 887, "line1": "செப்பின் புணர்ச்சிபோல் கூடினும் கூடாதே", "line2": "உட்பகை உற்ற குடி.", "translation": "A house hiding hostiles in core Just seems on like the lid in jar"}, {"number": 888, "line1": "அரம்பொருத பொன்போலத் தேயும் உரம்பொருது", "line2": "உட்பகை உற்ற குடி.", "translation": "By secret spite the house wears out Like gold crumbling by file's contact"}, {"number": 889, "line1": "எட்பக வன்ன சிறுமைத்தே ஆயினும்", "line2": "உட்பகை உள்ளதாங் கேடு.", "translation": "Ruin lurks in enmity As slit in sesame though it be"}, {"number": 890, "line1": "உடம்பாடு இலாதவர் வாழ்க்கை குடங்கருள்", "line2": "பாம்போடு உடனுறைந் தற்று.", "translation": "Dwell with traitors that hate in heart Is dwelling with snake in selfsame hut"}, {"number": 891, "line1": "ஆற்றுவார் ஆற்றல் இகழாமை போற்றுவார்", "line2": "போற்றலுள் எல்லாம் தலை.", "translation": "Not to spite the mighty ones Safest safeguard to living brings"}, {"number": 892, "line1": "பெரியாரைப் பேணாது ஒழுகிற் பெரியாரால்", "line2": "பேரா இடும்பை தரும்.", "translation": "To walk unmindful of the great Shall great troubles ceaseless create"}, {"number": 893, "line1": "கெடல்வேண்டின் கேளாது செய்க அடல்வேண்டின்", "line2": "ஆற்று பவர்கண் இழுக்கு.", "translation": "Heed not and do, if ruin you want Offence against the mighty great"}, {"number": 894, "line1": "கூற்றத்தைக் கையால் விளித்தற்றால் ஆற்றுவார்க்கு", "line2": "ஆற்றாதார் இன்னா செயல்.", "translation": "The weak who insult men of might Death with their own hands invite"}, {"number": 895, "line1": "யாண்டுச்சென்று யாண்டும் உளராகார் வெந்துப்பின்", "line2": "வேந்து செறப்பட் டவர்.", "translation": "Where can they go and thrive where Pursued by powerful monarch's ire?"}, {"number": 896, "line1": "எரியால் சுடப்படினும் உய்வுண்டாம் உய்யார்", "line2": "பெரியார்ப் பிழைத்தொழுகு வார்.", "translation": "One can escape in fire caught The great who offends escapes not"}, {"number": 897, "line1": "வகைமாண்ட வாழ்க்கையும் வான்பொருளும் என்னாம்", "line2": "தகைமாண்ட தக்கார் செறின்.", "translation": "If holy mighty sages frown Stately gifts and stores who can own?"}, {"number": 898, "line1": "குன்றன்னார் குன்ற மதிப்பின் குடியொடு", "line2": "நின்றன்னார் மாய்வர் நிலத்து.", "translation": "When hill-like sages are held small The firm on earth lose home and all"}, {"number": 899, "line1": "ஏந்திய கொள்கையார் சீறின் இடைமுரிந்து", "line2": "வேந்தனும் வேந்து கெடும்.", "translation": "Before the holy sage's rage Ev'n Indra's empire meets damage"}, {"number": 900, "line1": "இறந்தமைந்த சார்புடையர் ஆயினும் உய்யார்", "line2": "சிறந்தமைந்த சீரார் செறின்.", "translation": "Even mighty aided men shall quail If the enraged holy seers will"}, {"number": 901, "line1": "மனைவிழைவார் மாண்பயன் எய்தார் வினைவிழையார்", "line2": "வேண்டாப் பொருளும் அது.", "translation": "Who dote on wives lose mighty gain That lust, dynamic men disdain"}, {"number": 902, "line1": "பேணாது பெண்விழைவான் ஆக்கம் பெரியதோர்", "line2": "நாணாக நாணுத் தரும்.", "translation": "Who dotes, unmanly, on his dame His wealth to him and all is shame"}, {"number": 903, "line1": "இல்லாள்கண் தாழ்ந்த இயல்பின்மை எஞ்ஞான்றும்", "line2": "நல்லாருள் நாணுத் தரும்.", "translation": "Who's servile to his wife always Shy he feels before the wise"}, {"number": 904, "line1": "மனையாளை அஞ்சும் மறுமையி லாளன்", "line2": "வினையாண்மை வீறெய்த லின்று.", "translation": "Fearing his wife salvationless The weaklings' action has no grace"}, {"number": 905, "line1": "இல்லாளை அஞ்சுவான் அஞ்சுமற் றெஞ்ஞான்றும்", "line2": "நல்லார்க்கு நல்ல செயல்.", "translation": "Who fears his wife fears always Good to do to the good and wise"}, {"number": 906, "line1": "இமையாரின் வாழினும் பாடிலரே இல்லாள்", "line2": "அமையார்தோள் அஞ்சு பவர்.", "translation": "Who fear douce arms of their wives Look petty even with god-like lives"}, {"number": 907, "line1": "பெண்ணேவல் செய்தொழுகும் ஆண்மையின் நாணுடைப்", "line2": "பெண்ணே பெருமை உடைத்து.", "translation": "Esteemed more is women bashful Than man servile unto her will"}, {"number": 908, "line1": "நட்டார் குறைமுடியார் நன்றாற்றார் நன்னுதலாள்", "line2": "பெட் டாங்கு ஒழுகு பவர்.", "translation": "By fair-browed wives who are governed Help no friends nor goodness tend"}, {"number": 909, "line1": "அறவினையும் ஆன்ற பொருளும் பிறவினையும்", "line2": "பெண்ஏவல் செய்வார்கண் இல்.", "translation": "No virtue riches nor joy is seen In those who submit to women"}, {"number": 910, "line1": "எண்சேர்ந்த நெஞ்சத் திடனுடையார்க்கு எஞ்ஞான்றும்", "line2": "பெண்சேர்ந்தாம் பேதைமை இல்.", "translation": "Thinkers strong and broad of heart By folly on fair sex do not dote"}, {"number": 911, "line1": "அன்பின் விழையார் பொருள்விழையும் ஆய்தொடியார்", "line2": "இன்சொல் இழுக்குத் தரும்.", "translation": "For gold, not love their tongue cajoles Men are ruined by bangled belles"}, {"number": 912, "line1": "பயன்தூக்கிப் பண்புரைக்கும் பண்பின் மகளிர்", "line2": "நயன்தூக்கி நள்ளா விடல்.", "translation": "Avoid ill-natured whores who feign Love only for their selfish gain"}, {"number": 913, "line1": "பொருட்பெண்டிர் பொய்ம்மை முயக்கம் இருட்டறையில்", "line2": "ஏத஧ல் பிணந்தழீஇ அற்று.", "translation": "The false embrace of whores is like That of a damned corpse in the dark"}, {"number": 914, "line1": "பொருட்பொருளார் புன்னலந் தோயார் அருட்பொருள்", "line2": "ஆயும் அறிவி னவர்.", "translation": "The wise who seek the wealth of grace Look not for harlots' low embrace"}, {"number": 915, "line1": "பொதுநலத்தார் புன்னலம் தோயார் மதிநலத்தின்", "line2": "மாண்ட அறிவி னவர்.", "translation": "The lofty wise will never covet The open charms of a vile harlot"}, {"number": 916, "line1": "தந்நலம் பாரிப்பார் தோயார் தகைசெருக்கிப்", "line2": "புன்னலம் பாரிப்பார் தோள்.", "translation": "Those who guard their worthy fame Shun the wanton's vaunting charm"}, {"number": 917, "line1": "நிறைநெஞ்சம் இல்லவர் தோய்வார் பிறநெஞ்சிற்", "line2": "பேணிப் புணர்பவர் தோள்.", "translation": "Hollow hearts alone desire The arms of whores with hearts elsewere"}, {"number": 918, "line1": "ஆயும் அறிவினர் அல்லார்க்கு அணங்கென்ப", "line2": "மாய மகளிர் முயக்கு.", "translation": "Senseless fools are lured away By arms of sirens who lead astray"}, {"number": 919, "line1": "வரைவிலா மாணிழையார் மென்தோள் புரையிலாப்", "line2": "பூரியர்கள் ஆழும் அளறு.", "translation": "The soft jewelled arms of whores are hell Into which the degraded fall"}, {"number": 920, "line1": "இருமனப் பெண்டிரும் கள்ளும் கவறும்", "line2": "திருநீக்கப் பட்டார் தொடர்பு.", "translation": "Double-minded whores, wine and dice Are lures of those whom fortune flies"}, {"number": 921, "line1": "உட்கப் படாஅர் ஒளியிழப்பர் எஞ்ஞான்றும்", "line2": "கட்காதல் கொண்டொழுகு வார்.", "translation": "Foes fear not who for toddy craze The addicts daily their glory lose"}, {"number": 922, "line1": "உண்ணற்க கள்ளை உணில்உண்க சான்றோரான்", "line2": "எண்ணப் படவேண்டா தார்.", "translation": "Drink not liquor; but let them drink Whom with esteem the wise won't think"}, {"number": 923, "line1": "ஈன்றாள் முகத்தேயும் இன்னாதால் என்மற்றுச்", "line2": "சான்றோர் முகத்துக் களி.", "translation": "The drunkard's joy pains ev'n mother's face How vile must it look for the wise?"}, {"number": 924, "line1": "நாண்என்னும் நல்லாள் புறங்கொடுக்கும் கள்ளென்னும்", "line2": "பேணாப் பெருங்குற்றத் தார்க்கு.", "translation": "Good shame turns back from him ashamed Who is guilty of wine condemned"}, {"number": 925, "line1": "கையறி யாமை உடைத்தே பொருள்கொடுத்து", "line2": "மெய்யறி யாமை கொளல்.", "translation": "To pay and drink and lose the sense Is nothing but rank ignorance"}, {"number": 926, "line1": "துஞ்சினார் செத்தாரின் வேறல்லர் எஞ்ஞான்றும்", "line2": "நஞ்சுண்பார் கள்ளுண் பவர்.", "translation": "They take poison who take toddy And doze ev'n like a dead body"}, {"number": 927, "line1": "உள்ளொற்றி உள்ளூர் நகப்படுவர் எஞ்ஞான்றும்", "line2": "கள்ளொற்றிக் கண்சாய் பவர்", "translation": "The secret drunkards' senses off Make the prying public laugh"}, {"number": 928, "line1": "களித்தறியேன் என்பது கைவிடுக நெஞ்சத்து", "line2": "ஒளித்ததூஉம் ஆங்கே மிகும்.", "translation": "Don't say I'm not a drunkard hard The hidden fraud is known abroad"}, {"number": 929, "line1": "களித்தானைக் காரணம் காட்டுதல் கீழ்நீர்க்", "line2": "குளித்தானைத் தீத்துரீஇ அற்று.", "translation": "Can torch search one in water sunk?  Can reason reach the raving drunk?"}, {"number": 930, "line1": "கள்ளுண்ணாப் போழ்திற் களித்தானைக் காணுங்கால்", "line2": "உள்ளான்கொல் உண்டதன் சோர்வு.", "translation": "The sober seeing the drunkard's plight On selves can't they feel same effect?"}, {"number": 931, "line1": "வேண்டற்க வென்றிடினும் சூதினை வென்றதூஉம்", "line2": "தூண்டிற்பொன் மீன்விழுங்கி அற்று.", "translation": "Avoid gambling, albeit you win Gulping bait-hook what does fish gain?"}, {"number": 932, "line1": "ஒன்றெய்தி நூறிழக்கும் சூதர்க்கும் உண்டாங்கொல்", "line2": "நன்றெய்தி வாழ்வதோர் ஆறு.", "translation": "Can gamblers in life good obtain Who lose a hundred one to gain?"}, {"number": 933, "line1": "உருளாயம் ஓவாது கூறின் பொருளாயம்", "line2": "போஒய்ப் புறமே படும்.", "translation": "If kings indulge in casting dice All their fortune will flow to foes"}, {"number": 934, "line1": "சிறுமை பலசெய்து சீரழக்கும் சூதின்", "line2": "வறுமை தருவதொன்று இல்.", "translation": "Nothing will make you poor like game Which adds to woes and ruins fame"}, {"number": 935, "line1": "கவறும் கழகமும் கையும் தருக்கி", "line2": "இவறியார் இல்லாகி யார்.", "translation": "The game, game-hall and gambler's art Who sought with glee have come to nought"}, {"number": 936, "line1": "அகடாரார் அல்லல் உழப்பர்சூ தென்னும்", "line2": "முகடியான் மூடப்பட் டார்.", "translation": "Men swallowed by the ogress, dice Suffer grief and want by that vice"}, {"number": 937, "line1": "பழகிய செல்வமும் பண்பும் கெடுக்கும்", "line2": "கழகத்துக் காலை புகின்.", "translation": "If men their time in game-den spend Ancestral wealth and virtues end"}, {"number": 938, "line1": "பொருள்கெடுத்துப் பொய்மேற் கொளீஇ அருள்கெடுத்து", "line2": "அல்லல் உழப்பிக்கும் சூது.", "translation": "Game ruins wealth and spoils grace Leads to lies and wretched woes"}, {"number": 939, "line1": "உடைசெல்வம் ஊண்ஒளி கல்விஎன்று ஐந்தும்", "line2": "அடையாவாம் ஆயங் கொளின்.", "translation": "Dress, wealth, food, fame, learning-these five In gambler's hand will never thrive"}, {"number": 940, "line1": "இழத்தொறூஉம் காதலிக்கும் சூதேபோல் துன்பம்", "line2": "உழத்தொறூஉம் காதற்று உயிர்.", "translation": "Love for game grows with every loss As love for life with sorrows grows"}, {"number": 941, "line1": "மிகினும் குறையினும் நோய்செய்யும் நூலோர்", "line2": "வளிமுதலா எண்ணிய மூன்று.", "translation": "Wind, bile and phlegm three cause disease So doctors deem it more or less"}, {"number": 942, "line1": "மருந்தென வேண்டாவாம் யாக்கைக்கு அருந்தியது", "line2": "அற்றது போற்றி உணின்.", "translation": "After digestion one who feeds His body no medicine needs"}, {"number": 943, "line1": "அற்றால் அறவறிந்து உண்க அஃதுடம்பு", "line2": "பெற்றான் நெடிதுய்க்கும் ஆறு.", "translation": "Eat food to digestive measure Life in body lasts with pleasure"}, {"number": 944, "line1": "அற்றது அறிந்து கடைப்பிடித்து மாறல்ல", "line2": "துய்க்க துவரப் பசித்து.", "translation": "Know digestion; with keen appetite Eat what is suitable and right"}, {"number": 945, "line1": "மாறுபாடு இல்லாத உண்டி மறுத்துண்ணின்", "line2": "ஊறுபாடு இல்லை உயிர்க்கு.", "translation": "With fasting adjusted food right Cures ills of life and makes you bright"}, {"number": 946, "line1": "இழிவறிந்து உண்பான்கண் இன்பம்போல் நிற்கும்", "line2": "கழிபேர் இரையான்கண் நோய்.", "translation": "Who eats with clean stomach gets health With greedy glutton abides ill-health"}, {"number": 947, "line1": "தீயள வன்றித் தெரியான் பெரிதுண்ணின்", "line2": "நோயள வின்றிப் படும்.", "translation": "who glut beyond the hunger's fire Suffer from untold diseases here"}, {"number": 948, "line1": "நோய்நாடி நோய்முதல் நாடி அதுதணிக்கும்", "line2": "வாய்நாடி வாய்ப்பச் செயல்.", "translation": "Test disease, its cause and cure And apply remedy that is sure"}, {"number": 949, "line1": "உற்றான் அளவும் பிணியளவும் காலமும்", "line2": "கற்றான் கருதிச் செயல்.", "translation": "Let the skilful doctor note The sickmen, sickness, season and treat"}, {"number": 950, "line1": "உற்றவன் தீர்ப்பான் மருந்துழைச் செல்வானென்று", "line2": "அப்பால் நாற் கூற்றே மருந்து.", "translation": "Patient, doctor, medicine and nurse Are four-fold codes of treating course"}, {"number": 951, "line1": "இற்பிறந்தார் கண்அல்லது இல்லை இயல்பாகச்", "line2": "செப்பமும் நாணும் ஒருங்கு.", "translation": "Right-sense and bashfulness adorn By nature only the noble-born"}, {"number": 952, "line1": "ஒழுக்கமும் வாய்மையும் நாணும்இம் மூன்றும்", "line2": "இழுக்கார் குடிப்பிறந் தார்.", "translation": "The noble-born lack not these three: Good conduct, truth and modesty"}, {"number": 953, "line1": "நகைஈகை இன்சொல் இகழாமை நான்கும்", "line2": "வகையென்ப வாய்மைக் குடிக்கு.", "translation": "Smile, gift, sweet words and courtesy These four mark true nobility"}, {"number": 954, "line1": "அடுக்கிய கோடி பெறினும் குடிப்பிறந்தார்", "line2": "குன்றுவ செய்தல் இலர்.", "translation": "Even for crores, the noble mood Cannot bend to degrading deed"}, {"number": 955, "line1": "வழங்குவ துள்வீழ்ந்தக் கண்ணும் பழங்குடி", "line2": "பண்பில் தலைப்பிரிதல் இன்று.", "translation": "The means of gift may dwindle; yet Ancient homes guard their noble trait"}, {"number": 956, "line1": "சலம்பற்றிச் சால்பில செய்யார்மா சற்ற", "line2": "குலம்பற்றி வாழ்தும் என் பார்.", "translation": "Who guard their family prestige pure Stoop not to acts of cunning lure"}, {"number": 957, "line1": "குடிப்பிறந்தார் கண்விளங்கும் குற்றம் விசும்பின்", "line2": "மத஧க்கண் மறுப்போல் உயர்ந்து.", "translation": "The faults of nobly-born are seen Like on the sky the spots of moon"}, {"number": 958, "line1": "நலத்தின்கண் நாரின்மை தோன்றின் அவனைக்", "line2": "குலத்தின்கண் ஐயப் படும்.", "translation": "If manners of the good are rude People deem their pedigree crude"}, {"number": 959, "line1": "நிலத்தில் கிடந்தமை கால்காட்டும் காட்டும்", "line2": "குலத்தில் பிறந்தார்வாய்ச் சொல்.", "translation": "Soil's nature is seen in sprout The worth of birth from words flow out"}, {"number": 960, "line1": "நலம்வேண்டின் நாணுடைமை வேண்டும் குலம்வேண்டின்", "line2": "வேண்டுக யார்க்கும் பணிவு.", "translation": "All gain good name by modesty Nobility by humility"}, {"number": 961, "line1": "இன்றி அமையாச் சிறப்பின ஆயினும்", "line2": "குன்ற வருப விடல்.", "translation": "Though needed for your life in main, From mean degrading acts refrain"}, {"number": 962, "line1": "சீரினும் சீரல்ல செய்யாரே சீரொடு", "line2": "பேராண்மை வேண்டு பவர்.", "translation": "Who seek honour and manly fame Don't do mean deeds even for name"}, {"number": 963, "line1": "பெருக்கத்து வேண்டும் பணிதல் சிறிய", "line2": "சுருக்கத்து வேண்டும் உயர்வு.", "translation": "Be humble in prosperity In decline uphold dignity"}, {"number": 964, "line1": "தலையின் இழிந்த மயிரனையர் மாந்தர்", "line2": "நிலையின் இழிந்தக் கடை.", "translation": "Like hair fallen from head are those Who fall down from their high status"}, {"number": 965, "line1": "குன்றின் அனையாரும் குன்றுவர் குன்றுவ", "line2": "குன்றி அனைய செயின்.", "translation": "Even hill-like men will sink to nought With abrus-grain-like small default"}, {"number": 966, "line1": "புகழ்இன்றால் புத்தேள்நாட்டு உய்யாதால் என்மற்று", "line2": "இகழ்வார்பின் சென்று நிலை.", "translation": "Why fawn on men that scorn you here It yields no fame, heaven's bliss neither"}, {"number": 967, "line1": "ஒட்டார்பின் சென்றொருவன் வாழ்தலின் அந்நிலையே", "line2": "கெட்டான் எனப்படுதல் நன்று.", "translation": "Better it is to die forlorn Than live as slaves of those who scorn"}, {"number": 968, "line1": "மருந்தோமற்று ஊன்ஓம்பும் வாழ்க்கை பெருந்தகைமை", "line2": "பீடழிய வந்த இடத்து.", "translation": "Is nursing body nectar sweet Even when one's honour is lost?"}, {"number": 969, "line1": "மயிர்நீப்பின் வாழாக் கவரிமா அன்னார்", "line2": "உயிர்நீப்பர் மானம் வரின்.", "translation": "Honour lost, the noble expire Like a yak that loses its hair"}, {"number": 970, "line1": "இளிவரின் வாழாத மானம் உடையார்", "line2": "ஒளிதொழுது ஏத்தும் உலகு.", "translation": "Their light the world adores and hails  Who will not live when honour fails"}, {"number": 971, "line1": "ஒளிஒருவற்கு உள்ள வெறுக்கை இளிஒருவற்கு", "line2": "அஃதிறந்து வாழ்தும் எனல்.", "translation": "A heart of courage lives in light  Devoid of that one's life is night"}, {"number": 972, "line1": "பிறப்பொக்கும் எல்லா உயிர்க்கும் சிறப்பொவ்வா", "line2": "செய்தொழில் வேற்றுமை யான்.", "translation": "All beings are the same in birth But work decides their varied worth"}, {"number": 973, "line1": "மேலிருந்தும் மேலல்லார் மேலல்லர் கீழிருந்தும்", "line2": "கீழல்லார் கீழல் லவர்.", "translation": "Ignoble high not high they are The noble low not low they fare"}, {"number": 974, "line1": "ஒருமை மகளிரே போலப் பெருமையும்", "line2": "தன்னைத்தான் கொண்டொழுகின் உண்டு.", "translation": "Greatness like woman's chastity Is guarded by self-varacity"}, {"number": 975, "line1": "பெருமை யுடையவர் ஆற்றுவார் ஆற்றின்", "line2": "அருமை உடைய செயல்.", "translation": "Great souls when their will is active Do mighty deeds rare to achieve"}, {"number": 976, "line1": "சிறியார் உணர்ச்சியுள் இல்லை பெரியாரைப்", "line2": "பேணிக் கொள் வேம் என்னும் நோக்கு.", "translation": "The petty-natured ones have not The mind to seek and befriend the great"}, {"number": 977, "line1": "இறப்பே புரிந்த தொழிற்றாம் சிறப்புந்தான்", "line2": "சீரல் லவர்கண் படின்.", "translation": "The base with power and opulence Wax with deeds of insolence"}, {"number": 978, "line1": "பணியுமாம் என்றும் பெருமை சிறுமை", "line2": "அணியுமாம் தன்னை வியந்து.", "translation": "Greatness bends with modesty Meanness vaunts with vanity"}, {"number": 979, "line1": "பெருமை பெருமிதம் இன்மை சிறுமை", "line2": "பெருமிதம் ஊர்ந்து விடல்.", "translation": "Greatness is free from insolence Littleness swells with that offence"}, {"number": 980, "line1": "அற்றம் மறைக்கும் பெருமை சிறுமைதான்", "line2": "குற்றமே கூறி விடும்.", "translation": "Weakness of others greatness screens Smallness defects alone proclaims"}, {"number": 981, "line1": "கடன்என்ப நல்லவை எல்லாம் கடன்அறிந்து", "line2": "சான்றாண்மை மேற்கொள் பவர்க்கு.", "translation": "All goodness is duty to them  Who are dutiful and sublime"}, {"number": 982, "line1": "குணநலம் சான்றோர் நலனே பிறநலம்", "line2": "எந்நலத்து உள்ளதூஉம் அன்று.", "translation": "Good in the great is character Than that there is nothing better"}, {"number": 983, "line1": "அன்புநாண் ஒப்புரவு கண்ணோட்டம் வாய்மையொடு", "line2": "ஐந்துசால் ஊன்றிய தூண்.", "translation": "Love, truth, regard, modesty, grace These five are virtue's resting place"}, {"number": 984, "line1": "கொல்லா நலத்தது நோன்மை பிறர்தீமை", "line2": "சொல்லா நலத்தது சால்பு.", "translation": "Not to kill is penance pure Not to slander virtue sure"}, {"number": 985, "line1": "ஆற்றுவார் ஆற்றல் பணிதல் அதுசான்றோர்", "line2": "மாற்றாரை மாற்றும் படை.", "translation": "Humility is valour's strength A force that averts foes at length"}, {"number": 986, "line1": "சால்பிற்குக் கட்டளை யாதெனின் தோல்வி", "line2": "துலையல்லார் கண்ணும் கொளல்.", "translation": "To bear repulse e'en from the mean Is the touch-stone of worthy men"}, {"number": 987, "line1": "இன்னாசெய் தார்க்கும் இனியவே செய்யாக்கால்", "line2": "என்ன பயத்ததோ சால்பு.", "translation": "Of perfection what is the gain If it returns not joy for pain?"}, {"number": 988, "line1": "இன்மை ஒருவற்கு இளிவன்று சால்பென்னும்", "line2": "திண்மை உண் டாகப் பெறின்.", "translation": "No shame there is in poverty To one strong in good quality"}, {"number": 989, "line1": "ஊழி பெயரினும் தாம்பெயரார் சான்றாண்மைக்கு", "line2": "ஆழி எனப்படு வார்.", "translation": "Aeons may change but not the seer Who is a sea of virtue pure"}, {"number": 990, "line1": "சான்றவர் சான்றாண்மை குன்றின் இருநிலந்தான்", "line2": "தாங்காது மன்னோ பொறை.", "translation": "The world will not more bear its weight If from high virtue fall the great"}, {"number": 991, "line1": "எண்பதத்தால் எய்தல் எளிதென்ப யார்மாட்டும்", "line2": "பண்புடைமை என்னும் வழக்கு.", "translation": "To the polite free of access Easily comes courteousness"}, {"number": 992, "line1": "அன்புடைமை ஆன்ற குடிப்பிறத்தல் இவ்விரண்டும்", "line2": "பண்புடைமை என்னும் வழக்கு.", "translation": "Humanity and noble birth Develop courtesy and moral worth"}, {"number": 993, "line1": "உறுப்பொத்தல் மக்களொப்பு அன்றால் வெறுத்தக்க", "line2": "பண்பொத்தல் ஒப்பதாம் ஒப்பு.", "translation": "Likeness in limbs is not likeness It's likeness in kind courteousness"}, {"number": 994, "line1": "நயனொடு நன்றி புரிந்த பயனுடையார்", "line2": "பண்புபா ராட்டும் உலகு.", "translation": "The world applauds those helpful men Whose actions are just and benign"}, {"number": 995, "line1": "நகையுள்ளும் இன்னா திகழ்ச்சி பகையுள்ளும்", "line2": "பண்புள பாடறிவார் மாட்டு.", "translation": "The courteous don't even foes detest For contempt offends even in jest"}, {"number": 996, "line1": "பண்புடையார்ப் பட்டுண்டு உலகம் அதுஇன்றேல்", "line2": "மண்புக்கு மாய்வது மன்.", "translation": "The world rests with the mannered best Or it crumbles and falls to dust"}, {"number": 997, "line1": "அரம்போலும் கூர்மைய ரேனும் மரம்போல்வர்", "line2": "மக்கட்பண்பு இல்லா தவர்.", "translation": "The mannerless though sharp like file Are like wooden blocks indocile"}, {"number": 998, "line1": "நண்பாற்றார் ஆகி நயமில செய்வார்க்கும்", "line2": "பண்பாற்றார் ஆதல் கடை.", "translation": "Discourtesy is mean indeed E'en to a base unfriendly breed"}, {"number": 999, "line1": "நகல்வல்லர் அல்லார்க்கு மாயிரு ஞாலம்", "line2": "பகலும்பாற் பட்டன்று இருள்.", "translation": "To those bereft of smiling light Even in day the earth is night"}, {"number": 1000, "line1": "பண்பிலான் பெற்ற பெருஞ்செல்வம் நன்பால்", "line2": "கலந்தீமை யால்திரிந் தற்று.", "translation": "The wealth heaped by the churlish base Is pure milk soured by impure vase"}, {"number": 1001, "line1": "வைத்தான்வாய் சான்ற பெரும்பொருள் அஃதுண்ணான்", "line2": "செத்தான் செயக்கிடந்தது இல்.", "translation": "Dead is he with wealth in pile Unenjoyed, it is futile"}, {"number": 1002, "line1": "பொருளானாம் எல்லாமென்று ஈயாது இவறும்", "line2": "மருளானாம் மாணாப் பிறப்பு", "translation": "The niggard miser thinks wealth is all He hoards, gives not is born devil"}, {"number": 1003, "line1": "ஈட்டம் இவறி இசைவேண்டா ஆடவர்", "line2": "தோற்றம் நிலக்குப் பொறை.", "translation": "A burden he is to earth indeed Who hoards without a worthy deed"}, {"number": 1004, "line1": "எச்சமென்று என்எண்ணுங் கொல்லோ ஒருவரால்", "line2": "நச்சப் படாஅ தவன்.", "translation": "What legacy can he leave behind Who is for approach too unkind"}, {"number": 1005, "line1": "கொடுப்பதூஉம் துய்ப்பதூஉம் இல்லார்க்கு அடுக்கிய", "line2": "கோடியுண் டாயினும் இல்.", "translation": "What is the good of crores they hoard To give and enjoy whose heart is hard"}, {"number": 1006, "line1": "ஏதம் பெருஞ்செல்வம் தான்துவ்வான் தக்கார்க்கொன்று", "line2": "ஈதல் இயல்பிலா தான்.", "translation": "Great wealth unused for oneself nor To worthy men is but a slur"}, {"number": 1007, "line1": "அற்றார்க்கொன்று ஆற்றாதான் செல்வம் மிகநலம்", "line2": "பெற்றாள் தமியள்மூத் தற்று.", "translation": "Who loaths to help have-nots, his gold Is like a spinster-belle grown old"}, {"number": 1008, "line1": "நச்சப் படாதவன் செல்வம் நடுவூருள்", "line2": "நச்சு மரம்பழுத் தற்று.", "translation": "The idle wealth of unsought men Is poison-fruit-tree amidst a town"}, {"number": 1009, "line1": "அன்பொரீஇத் தற்செற்று அறநோக்காது ஈட்டிய", "line2": "ஒண்பொருள் கொள்வார் பிறர்.", "translation": "Others usurp the shining gold In loveless, stingy, vicious hold"}, {"number": 1010, "line1": "சீருடைச் செல்வர் சிறுதுனி மாரி", "line2": "வறங்கூர்ந் தனையது உடைத்து.", "translation": "The brief want of the rich benign Is like rainclouds growing thin"}, {"number": 1011, "line1": "கருமத்தால் நாணுதல் நாணுந் திருநுதல்", "line2": "நல்லவர் நாணுப் பிற.", "translation": "To shrink from evil deed is shame The rest is blush of fair-faced dame"}, {"number": 1012, "line1": "ஊணுடை எச்சம் உயிர்க்கெல்லாம் வேறல்ல", "line2": "நாணுடைமை மாந்தர் சிறப்பு.", "translation": "Food, dress and such are one for all Modesty marks the higher soul"}, {"number": 1013, "line1": "ஊனைக் குறித்த உயிரெல்லாம் நாண்என்னும்", "line2": "நன்மை குறித்தது சால்பு.", "translation": "All lives have their lodge in flesh Perfection has its home in blush"}, {"number": 1014, "line1": "அணிஅன்றோ நாணுடைமை சான்றோர்க்கு அஃதின்றேல்", "line2": "பிணிஅன்றோ பீடு நடை.", "translation": "Shame is the jewel of dignity Shameless swagger is vanity"}, {"number": 1015, "line1": "பிறர்பழியும் தம்பழியும் நாணுவார் நாணுக்கு", "line2": "உறைபதி என்னும் உலகு.", "translation": "In them resides the sense of shame Who blush for their and other's blame"}, {"number": 1016, "line1": "நாண்வேலி கொள்ளாது மன்னோ வியன்ஞாலம்", "line2": "பேணலர் மேலா யவர்.", "translation": "The great refuse the wonder-world Without modesty's hedge and shield"}, {"number": 1017, "line1": "நாணால் உயிரைத் துறப்பர் உயிர்ப்பொருட்டால்", "line2": "நாண்துறவார் நாணாள் பவர்.", "translation": "For shame their life the shame-sensed give Loss of shame they won't outlive"}, {"number": 1018, "line1": "பிறர்நாணத் தக்கது தான்நாணா னாயின்", "line2": "அறம்நாணத் தக்கது உடைத்து.", "translation": "Virtue is much ashamed of him Who shameless does what others shame"}, {"number": 1019, "line1": "குலஞ்சுடும் கொள்கை பிழைப்பின் நலஞ்சுடும்", "line2": "நாணின்மை நின்றக் கடை.", "translation": "Lapse in manners injures the race Want of shame harms every good grace"}, {"number": 1020, "line1": "நாண்அகத் தில்லார் இயக்கம் மரப்பாவை", "line2": "நாணால் உயிர்மருட்டி அற்று.", "translation": "Movements of the shameless in heart Are string-led puppet show in fact"}, {"number": 1021, "line1": "கருமம் செயஒருவன் கைதூவேன் என்னும்", "line2": "பெருமையின் பீடுடையது இல்.", "translation": "No greatness is grander like Saying \\\"I shall work without slack\\\""}, {"number": 1022, "line1": "ஆள்வினையும் ஆன்ற அறிவும் எனஇரண்டின்", "line2": "நீள்வினையால் நீளும் குடி.", "translation": "These two exalt a noble home Ardent effort and ripe wisdom"}, {"number": 1023, "line1": "குடிசெய்வல் என்னும் ஒருவற்குத் தெய்வம்", "line2": "மடிதற்றுத் தான்முந் துறும்.", "translation": "When one resolves to raise his race Loin girt up God leads his ways"}, {"number": 1024, "line1": "சூழாமல் தானே முடிவெய்தும் தம்குடியைத்", "line2": "தாழாது உஞற்று பவர்க்கு.", "translation": "Who raise their races with ceaseless pain No need for plan; their ends will gain"}, {"number": 1025, "line1": "குற்றம் இலனாய்க் குடிசெய்து வாழ்வானைச்", "line2": "சுற்றமாச் சுற்றும் உலகு.", "translation": "Who keeps his house without a blame People around, his kinship claim"}, {"number": 1026, "line1": "நல்லாண்மை என்பது ஒருவற்குத் தான்பிறந்த", "line2": "இல்லாண்மை ஆக்கிக் கொளல்.", "translation": "Who raise their race which gave them birth Are deemed as men of manly worth"}, {"number": 1027, "line1": "அமரகத்து வன்கண்ணர் போலத் தமரகத்தும்", "line2": "ஆற்றுவார் மேற்றே பொறை.", "translation": "Like dauntless heroes in battle field The home-burden rests on the bold"}, {"number": 1028, "line1": "குடிசெய்வார்க் கில்லை பருவம் மடிசெய்து", "line2": "மானங் கருதக் கெடும்.", "translation": "No season have they who raise their race Sloth and pride will honour efface"}, {"number": 1029, "line1": "இடும்பைக்கே கொள்கலம் கொல்லோ குடும்பத்தைக்", "line2": "குற்ற மறைப்பான் உடம்பு.", "translation": "Is not his frame a vase for woes Who from mishaps shields his house?"}, {"number": 1030, "line1": "இடுக்கண்கால் கொன்றிட வீழும் அடுத்தூன்றும்", "line2": "நல்லாள் இலாத குடி.", "translation": "A house will fall by a mishap With no good man to prop it up"}, {"number": 1031, "line1": "சுழன்றும்ஏர்ப் பின்னது உலகம் அதனால்", "line2": "உழந்தும் உழவே தலை.", "translation": "Farming though hard is foremost trade Men ply at will but ploughmen lead"}, {"number": 1032, "line1": "உழுவார் உலகத்தார்க்கு ஆணிஅஃ தாற்றாது", "line2": "எழுவாரை எல்லாம் பொறுத்து.", "translation": "Tillers are linch-pin of mankind Bearing the rest who cannot tend"}, {"number": 1033, "line1": "உழுதுண்டு வாழ்வாரே வாழ்வார்மற் றெல்லாம்", "line2": "தொழுதுண்டு பின்செல் பவர்.", "translation": "They live who live to plough and eat The rest behind them bow and eat"}, {"number": 1034, "line1": "பலகுடை நீழலும் தங்குடைக்கீழ்க் காண்பர்", "line2": "அலகுடை நீழ லவர்.", "translation": "Who have the shade of cornful crest Under their umbra umbrellas rest"}, {"number": 1035, "line1": "இரவார் இரப்பார்க்கொன்று ஈவர் கரவாது", "line2": "கைசெய்தூண் மாலை யவர்.", "translation": "Who till and eat, beg not; nought hide But give to those who are in need"}, {"number": 1036, "line1": "உழவினார் கைம்மடங்கின் இல்லை விழைவதூஉம்", "line2": "விட்டேம்என் பார்க்கும் நிலை.", "translation": "Should ploughmen sit folding their hands Desire-free monks too suffer wants"}, {"number": 1037, "line1": "தொடிப்புழுதி கஃசா உணக்கின் பிடித்தெருவும்", "line2": "வேண்டாது சாலப் படும்.", "translation": "Moulds dried to quarter-dust ensure Rich crops without handful manure"}, {"number": 1038, "line1": "ஏரினும் நன்றால் எருவிடுதல் கட்டபின்", "line2": "நீரினும் நன்றதன் காப்பு.", "translation": "Better manure than plough; then weed; Than irrigating, better guard"}, {"number": 1039, "line1": "செல்லான் கிழவன் இருப்பின் நிலம்புலந்து", "line2": "இல்லாளின் ஊடி விடும்.", "translation": "If landsmen sit sans moving about The field like wife will sulk and pout"}, {"number": 1040, "line1": "இலமென்று அசைஇ இருப்பாரைக் காணின்", "line2": "நிலமென்னும் நல்லாள் நகும்.", "translation": "Fair good earth will laugh to see Idlers pleading poverty"}, {"number": 1041, "line1": "இன்மையின் இன்னாதது யாதெனின் இன்மையின்", "line2": "இன்மையே இன்னா தது.", "translation": "What gives more pain than scarcity? No pain pinches like poverty"}, {"number": 1042, "line1": "இன்மை எனவொரு பாவி மறுமையும்", "line2": "இம்மையும் இன்றி வரும்.", "translation": "The sinner Want is enemy dire Of joys of earth and heaven there"}, {"number": 1043, "line1": "தொல்வரவும் தோலும் கெடுக்கும் தொகையாக", "line2": "நல்குரவு என்னும் நசை.", "translation": "The craving itch of poverty Kills graceful words and ancestry"}, {"number": 1044, "line1": "இற்பிறந்தார் கண்ணேயும் இன்மை இளிவந்த", "line2": "சொற்பிறக்கும் சோர்வு தரும்.", "translation": "Want makes even good familymen Utter words that are low and mean"}, {"number": 1045, "line1": "நல்குரவு என்னும் இடும்பையுள் பல்குரைத்", "line2": "துன்பங்கள் சென்று படும்.", "translation": "The pest of wanton poverty Brings a train of misery"}, {"number": 1046, "line1": "நற்பொருள் நன்குணர்ந்து சொல்லினும் நல்கூர்ந்தார்", "line2": "சொற்பொருள் சோர்வு படும்.", "translation": "The poor men's words are thrown away Though from heart good things they say"}, {"number": 1047, "line1": "அறஞ்சாரா நல்குரவு ஈன்றதா யானும்", "line2": "பிறன்போல நோக்கப் படும்.", "translation": "Even the mother looks as stranger The poor devoid of character"}, {"number": 1048, "line1": "இன்றும் வருவது கொல்லோ நெருநலும்", "line2": "கொன்றது போலும் நிரப்பு.", "translation": "The killing Want of yesterday Will it pester me even to-day?"}, {"number": 1049, "line1": "நெருப்பினுள் துஞ்சலும் ஆகும் நிரப்பினுள்", "line2": "யாதொன்றும் கண்பாடு அரிது.", "translation": "One may sleep in the midst of fire In want a wink of sleep is rare"}, {"number": 1050, "line1": "துப்புர வில்லார் துவரத் துறவாமை", "line2": "உப்பிற்கும் காடிக்கும் கூற்று.", "translation": "Renounce their lives the poor must Or salt and gruel go to waste"}, {"number": 1051, "line1": "இரக்க இரத்தக்கார்க் காணின் கரப்பின்", "line2": "அவர்பழி தம்பழி அன்று.", "translation": "Demand from those who can supply Default is theirs when they deny"}, {"number": 1052, "line1": "இன்பம் ஒருவற்கு இரத்தல் இரந்தவை", "line2": "துன்பம் உறாஅ வரின்.", "translation": "Even demand becomes a joy When the things comes without annoy"}, {"number": 1053, "line1": "கரப்பிலா நெஞ்சின் கடனறிவார் முன்நின்று", "line2": "இரப்புமோ ரேஎர் உடைத்து.", "translation": "Request has charm form open hearts Who know the duty on their part"}, {"number": 1054, "line1": "இரத்தலும் ஈதலே போலும் கரத்தல்", "line2": "கனவிலும் தேற்றாதார் மாட்டு.", "translation": "Like giving even asking seems From those who hide not even in dreams"}, {"number": 1055, "line1": "கரப்பிலார் வையகத்து உண்மையால் கண்ணின்று", "line2": "இரப்பவர் மேற்கொள் வது.", "translation": "The needy demand for help because The world has men who don't refuse"}, {"number": 1056, "line1": "கரப்பிடும்பை யில்லாரைக் காணின் நிரப்பிடும்பை", "line2": "எல்லாம் ஒருங்கு கெடும்.", "translation": "The pain of poverty shall die Before the free who don't deny"}, {"number": 1057, "line1": "இகழ்ந்தெள்ளாது ஈவாரைக் காணின் மகிழ்ந்துள்ளம்", "line2": "உள்ளுள் உவப்பது உடைத்து.", "translation": "When givers without scorn impart A thrill of delight fills the heart"}, {"number": 1058, "line1": "இரப்பாரை இல்லாயின் ஈர்ங்கண்மா ஞாலம்", "line2": "மரப்பாவை சென்றுவந் தற்று.", "translation": "This grand cool world shall move to and fro Sans Askers like a puppet show"}, {"number": 1059, "line1": "ஈவார்கண் என்னுண்டாம் தோற்றம் இரந்துகோள்", "line2": "மேவார் இலாஅக் கடை.", "translation": "Where stands the glory of givers Without obligation seekers?"}, {"number": 1060, "line1": "இரப்பான் வெகுளாமை வேண்டும் நிரப்பிடும்பை", "line2": "தானேயும் சாலும் கரி.", "translation": "The needy should not scowl at \\\"No\\\" His need another's need must show * Saint valluvar talks of two kinds of Asking:() Asking help for public causes or enterprises () Begging when one is able to work and this is condemned"}, {"number": 1061, "line1": "கரவாது உவந்தீயும் கண்ணன்னார் கண்ணும்", "line2": "இரவாமை கோடி உறும்.", "translation": "Not to beg is billions worth E'en from eye-like friends who give with mirth"}, {"number": 1062, "line1": "இரந்தும் உயிர்வாழ்தல் வேண்டின் பரந்து", "line2": "கெடுக உலகியற்றி யான்.", "translation": "Let World-Maker loiter and rot If \\\"beg and live\\\" be human fate"}, {"number": 1063, "line1": "இன்மை இடும்பை இரந்துதீர் வாமென்னும்", "line2": "வன்மையின் வன்பாட்ட தில்.", "translation": "Nothing is hard like hard saying \\\"We end poverty by begging\\\""}, {"number": 1064, "line1": "இடமெல்லாம் கொள்ளாத் தகைத்தே இடமில்லாக்", "line2": "காலும் இரவொல்லாச் சால்பு.", "translation": "All space is small before the great Who beg not e'en in want acute"}, {"number": 1065, "line1": "தெண்ணீர் அடுபுற்கை ஆயினும் தாள்தந்தது", "line2": "உண்ணலின் ஊங்கினிய தில்.", "translation": "Though gruel thin, nothing is sweet Like the food earned by labour's sweat"}, {"number": 1066, "line1": "ஆவிற்கு நீரென்று இரப்பினும் நாவிற்கு", "line2": "இரவின் இளிவந்த தில்.", "translation": "It may be water for the cow Begging tongue is mean anyhow"}, {"number": 1067, "line1": "இரப்பன் இரப்பாரை எல்லாம் இரப்பின்", "line2": "கரப்பார் இரவன்மின் என்று.", "translation": "If beg they must I beg beggers Not to beg from shrinking misers"}, {"number": 1068, "line1": "இரவென்னும் ஏமாப்பில் தோணி கரவென்னும்", "line2": "பார்தாக்கப் பக்கு விடும்.", "translation": "The hapless bark of beggary splits On the rock of refusing hits"}, {"number": 1069, "line1": "இரவுள்ள உள்ளம் உருகும் கரவுள்ள", "line2": "உள்ளதூஉம் இன்றிக் கெடும்.", "translation": "The heart at thought of beggars melts; It dies at repulsing insults"}, {"number": 1070, "line1": "கரப்பவர்க்கு யாங்கொளிக்கும் கொல்லோ இரப்பவர்", "line2": "சொல்லாடப் போஒம் உயிர்.", "translation": "The word \\\"No\\\" kills the begger's life Where can the niggard's life be safe?"}, {"number": 1071, "line1": "மக்களே போல்வர் கயவர் அவரன்ன", "line2": "ஒப்பாரி யாங்கண்ட தில்.", "translation": "The mean seem men only in form We have never seen such a sham"}, {"number": 1072, "line1": "நன்றறி வாரிற் கயவர் திருவுடையர்", "line2": "நெஞ்சத்து அவலம் இலர்.", "translation": "The base seem richer than the good For no care enters their heart or head"}, {"number": 1073, "line1": "தேவர் அனையர் கயவர் அவருந்தாம்", "line2": "மேவன செய்தொழுக லான்.", "translation": "The base are like gods; for they too As prompted by their desire do"}, {"number": 1074, "line1": "அகப்பட்டி ஆவாரைக் காணின் அவரின்", "line2": "மிகப்பட்டுச் செம்மாக்கும் கீழ்.", "translation": "When the base meets a rake so vile Him he will exceed, exult and smile"}, {"number": 1075, "line1": "அச்சமே கீழ்களது ஆசாரம் எச்சம்", "line2": "அவாவுண்டேல் உண்டாம் சிறிது.", "translation": "Fear forms the conduct of the low Craving avails a bit below"}, {"number": 1076, "line1": "அறைபறை அன்னர் கயவர்தாம் கேட்ட", "line2": "மறைபிறர்க்கு உய்த்துரைக்க லான்.", "translation": "The base are like the beaten drum Since other's secrets they proclaim"}, {"number": 1077, "line1": "ஈர்ங்கை விதிரார் கயவர் கொடிறுடைக்கும்", "line2": "கூன்கையர் அல்லா தவர்க்கு.", "translation": "The base their damp hand will not shake But for fists clenched their jaws to break"}, {"number": 1078, "line1": "சொல்லப் பயன்படுவர் சான்றோர் கரும்புபோல்", "line2": "கொல்லப் பயன்படும் கீழ்.", "translation": "The good by soft words profits yield The cane-like base when crushed and killed"}, {"number": 1079, "line1": "உடுப்பதூஉம் உண்பதூஉம் காணின் பிறர்மேல்", "line2": "வடுக்காண வற்றாகும் கீழ்.", "translation": "Faults in others the mean will guess On seeing how they eat and dress"}, {"number": 1080, "line1": "எற்றிற் குரியர் கயவரொன்று உற்றக்கால்", "line2": "விற்றற்கு உரியர் விரைந்து.", "translation": "The base hasten to sell themselves From doom to flit and nothing else"}];
